export const APP_MODES = {
  DASHBOARD: 'dashboard',
  CHAT: 'chat',
  NOTES: 'notes',
  SYLLABUS: 'syllabus',
  DOUBTS: 'doubts'
} as const;

import { GoogleGenAI, GenerateContentParameters } from "@google/genai";
import { Message } from "../types";

const API_KEY = process.env.API_KEY || '';

export const getGeminiResponse = async (messages: Message[], systemInstruction?: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const contents = messages.map(msg => ({
    role: msg.role,
    parts: msg.parts
  }));

  const params: GenerateContentParameters = {
    model: 'gemini-3-flash-preview',
    contents,
    config: {
      systemInstruction: systemInstruction || "You are EduPulse, a helpful and expert AI tutor. Help the student with their doubts, explain concepts clearly, and be encouraging. If notes are provided, refer to them in your explanations.",
      temperature: 0.7,
    }
  };

  try {
    const response = await ai.models.generateContent(params);
    return response.text || "I'm sorry, I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error: Unable to connect to AI tutor. Please check your connection.";
  }
};

