import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip } from 'recharts';
import { Subject, Note, Doubt } from '../types';

interface DashboardProps {
  subjects: Subject[];
  notes: Note[];
  doubts: Doubt[];
}

const Dashboard: React.FC<DashboardProps> = ({ subjects, notes, doubts }) => {
  const totalTopics = subjects.reduce((acc, s) => acc + s.topics.length, 0);
  const completedTopics = subjects.reduce((acc, s) => acc + s.topics.filter(t => t.completed).length, 0);
  const completionPercentage = Math.round((completedTopics / totalTopics) * 100) || 0;

  const chartData = subjects.map(s => ({
    name: s.name,
    completion: Math.round((s.topics.filter(t => t.completed).length / s.topics.length) * 100)
  }));

  const pieData = [
    { name: 'Completed', value: completedTopics },
    { name: 'Remaining', value: totalTopics - completedTopics }
  ];
  const COLORS = ['#10b981', '#e2e8f0'];

  return (
    <div className="space-y-8 animate-fadeIn">
      <header>
        <h2 className="text-3xl font-bold text-slate-800">Welcome back, Scholar!</h2>
        <p className="text-slate-500">Here is your learning summary for today.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex flex-col items-center">
          <h3 className="text-lg font-semibold text-slate-700 mb-4">Overall Progress</h3>
          <div className="h-48 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <p className="text-4xl font-bold text-indigo-600 mt-[-7rem]">{completionPercentage}%</p>
          <p className="mt-20 text-slate-500 text-sm">Target: 100% completion</p>
        </div>

        <div className="md:col-span-2 bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold text-slate-700 mb-4">Subject Mastery</h3>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="completion" fill="#6366f1" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-semibold text-slate-700">Recent Notes</h3>
            <button className="text-indigo-600 text-sm font-medium">View All</button>
          </div>
          <div className="space-y-3">
            {notes.slice(0, 3).map(note => (
              <div key={note.id} className="flex items-center p-3 hover:bg-slate-50 rounded-xl transition-colors cursor-pointer border border-transparent hover:border-slate-200">
                <div className="bg-amber-100 text-amber-600 p-3 rounded-lg mr-4">
                  <i className="fa-solid fa-file-lines"></i>
                </div>
                <div>
                  <h4 className="font-medium text-slate-800">{note.title}</h4>
                  <p className="text-xs text-slate-500">{new Date(note.timestamp).toLocaleDateString()}</p>
                </div>
              </div>
            ))}
            {notes.length === 0 && <p className="text-slate-400 text-center py-4 italic">No notes uploaded yet.</p>}
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-semibold text-slate-700">Saved Doubts</h3>
            <button className="text-indigo-600 text-sm font-medium">Review</button>
          </div>
          <div className="space-y-3">
            {doubts.slice(0, 3).map(doubt => (
              <div key={doubt.id} className="p-3 border border-slate-100 rounded-xl hover:bg-slate-50 transition-colors">
                <p className="text-sm font-medium text-slate-800 line-clamp-1">{doubt.question}</p>
                <div className="flex justify-between items-center mt-2">
                  <span className="text-[10px] px-2 py-0.5 bg-indigo-50 text-indigo-600 rounded-full">{doubt.subject}</span>
                  <span className="text-[10px] text-slate-400">{new Date(doubt.timestamp).toLocaleDateString()}</span>
                </div>
              </div>
            ))}
            {doubts.length === 0 && <p className="text-slate-400 text-center py-4 italic">No doubts saved yet.</p>}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef, useEffect } from 'react';
import { Message, Note, Doubt } from '../types';
import { getGeminiResponse } from '../services/geminiService';

interface AITutorProps {
  notes: Note[];
  onSaveDoubt: (doubt: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => void;
}

const AITutor: React.FC<AITutorProps> = ({ notes, onSaveDoubt }) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      parts: [{ text: "Hello! I'm EduPulse. How can I help with your studies today? You can ask me anything or provide context from your uploaded notes." }],
      timestamp: Date.now(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedNoteId, setSelectedNoteId] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if ((!input.trim() && !selectedNoteId) || isLoading) return;

    const currentInput = input;
    setInput('');

    let parts: any[] = [{ text: currentInput }];

    // Add note context if selected
    if (selectedNoteId) {
      const note = notes.find(n => n.id === selectedNoteId);
      if (note) {
        parts.push({ text: `\n\n[CONTEXT FROM NOTE: ${note.title}]\n${note.content}` });
      }
    }

    const newUserMsg: Message = {
      role: 'user',
      parts: [{ text: currentInput }], // Only show user's actual input in UI
      timestamp: Date.now()
    };

    const conversationHistory = [...messages, { role: 'user', parts, timestamp: Date.now() }];
    setMessages(prev => [...prev, newUserMsg]);
    setIsLoading(true);

    const responseText = await getGeminiResponse(conversationHistory);

    const aiMsg: Message = {
      role: 'model',
      parts: [{ text: responseText }],
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, aiMsg]);
    setIsLoading(false);
    setSelectedNoteId(null);
  };

  const bookmarkDoubt = (msgIndex: number) => {
    const userMsg = messages[msgIndex - 1];
    const aiMsg = messages[msgIndex];
    if (userMsg && aiMsg) {
      onSaveDoubt({
        question: userMsg.parts[0].text || "Unknown question",
        answer: aiMsg.parts[0].text || "No answer provided",
        subject: "General" // Ideally we could extract this with AI
      });
      alert("Doubt saved to your collection!");
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-8rem)] bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="bg-indigo-50 p-4 border-b border-indigo-100 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-full flex items-center justify-center text-white">
            <i className="fa-solid fa-robot"></i>
          </div>
          <div>
            <h3 className="font-semibold text-slate-800">EduPulse AI</h3>
            <span className="text-xs text-indigo-500 font-medium flex items-center gap-1">
              <span className="w-2 h-2 bg-green-500 rounded-full"></span> Online & Ready
            </span>
          </div>
        </div>
        <div className="flex items-center gap-2">
           <select 
             className="text-sm bg-white border border-slate-200 rounded-lg px-2 py-1 outline-none focus:ring-2 ring-indigo-500"
             value={selectedNoteId || ''}
             onChange={(e) => setSelectedNoteId(e.target.value || null)}
           >
             <option value="">No Note Selected</option>
             {notes.map(n => (
               <option key={n.id} value={n.id}>{n.title}</option>
             ))}
           </select>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] rounded-2xl px-4 py-3 relative group ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-slate-100 text-slate-800 rounded-tl-none'
            }`}>
              <p className="whitespace-pre-wrap text-sm leading-relaxed">{msg.parts[0].text}</p>
              {msg.role === 'model' && idx > 0 && (
                <button 
                  onClick={() => bookmarkDoubt(idx)}
                  className="absolute -right-10 top-2 opacity-0 group-hover:opacity-100 transition-opacity p-2 text-slate-400 hover:text-amber-500"
                  title="Save as Doubt"
                >
                  <i className="fa-solid fa-bookmark"></i>
                </button>
              )}
              <span className="text-[10px] opacity-50 block mt-2">
                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-100 text-slate-500 rounded-2xl rounded-tl-none px-4 py-3">
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-50 border-t border-slate-100">
        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask your doubt..."
            className="w-full bg-white border border-slate-200 rounded-2xl py-3 pl-4 pr-12 focus:ring-2 ring-indigo-500 outline-none transition-all shadow-sm"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || (!input.trim() && !selectedNoteId)}
            className="absolute right-2 p-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors disabled:opacity-50"
          >
            <i className="fa-solid fa-paper-plane"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default AITutor;

import React from 'react';
import { Subject } from '../types';

interface SyllabusTrackerProps {
  subjects: Subject[];
  onToggleTopic: (subjectId: string, topicId: string) => void;
}

const SyllabusTracker: React.FC<SyllabusTrackerProps> = ({ subjects, onToggleTopic }) => {
  return (
    <div className="space-y-6 animate-fadeIn">
      <header className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Syllabus Progress</h2>
          <p className="text-slate-500">Track and manage your learning milestones.</p>
        </div>
        <button className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-medium hover:bg-indigo-700 shadow-lg">
          <i className="fa-solid fa-plus mr-2"></i> Add Subject
        </button>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {subjects.map((subject) => {
          const completedCount = subject.topics.filter(t => t.completed).length;
          const progress = Math.round((completedCount / subject.topics.length) * 100);

          return (
            <div key={subject.id} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex flex-col">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h3 className="text-xl font-bold text-slate-800">{subject.name}</h3>
                  <p className="text-sm text-slate-400">{completedCount} of {subject.topics.length} topics completed</p>
                </div>
                <div className="text-right">
                  <span className="text-2xl font-bold text-indigo-600">{progress}%</span>
                </div>
              </div>

              <div className="w-full bg-slate-100 h-2 rounded-full mb-6">
                <div 
                  className="bg-indigo-600 h-full rounded-full transition-all duration-1000" 
                  style={{ width: `${progress}%` }}
                ></div>
              </div>

              <div className="space-y-2 flex-1">
                {subject.topics.map((topic) => (
                  <label 
                    key={topic.id} 
                    className={`flex items-center p-3 rounded-xl border transition-all cursor-pointer group ${
                      topic.completed ? 'bg-indigo-50 border-indigo-100' : 'bg-white border-slate-100 hover:border-indigo-200'
                    }`}
                  >
                    <input
                      type="checkbox"
                      checked={topic.completed}
                      onChange={() => onToggleTopic(subject.id, topic.id)}
                      className="w-5 h-5 rounded text-indigo-600 focus:ring-indigo-500 border-slate-300 mr-3"
                    />
                    <span className={`flex-1 text-sm font-medium ${topic.completed ? 'text-indigo-900 line-through opacity-70' : 'text-slate-700'}`}>
                      {topic.name}
                    </span>
                    <button className="text-slate-300 group-hover:text-indigo-400 transition-colors">
                      <i className="fa-solid fa-ellipsis"></i>
                    </button>
                  </label>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default SyllabusTracker;

import React, { useState } from 'react';
import { Note } from '../types';

interface NotesManagerProps {
  notes: Note[];
  onAddNote: (note: Omit<Note, 'id' | 'timestamp'>) => void;
  onDeleteNote: (id: string) => void;
}

const NotesManager: React.FC<NotesManagerProps> = ({ notes, onAddNote, onDeleteNote }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [newNoteTitle, setNewNoteTitle] = useState('');
  const [newNoteContent, setNewNoteContent] = useState('');

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const content = event.target?.result as string;
        onAddNote({
          title: file.name,
          content: content,
          type: 'text' // For simplicity treating as text/raw content
        });
      };
      reader.readAsText(file);
    }
  };

  const handleManualAdd = () => {
    if (newNoteTitle && newNoteContent) {
      onAddNote({
        title: newNoteTitle,
        content: newNoteContent,
        type: 'text'
      });
      setNewNoteTitle('');
      setNewNoteContent('');
      setIsUploading(false);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <header className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">My Study Notes</h2>
          <p className="text-slate-500">Organize and search through your course materials.</p>
        </div>
        <div className="flex gap-3">
           <label className="bg-white text-slate-700 px-4 py-2 rounded-xl text-sm font-medium border border-slate-200 cursor-pointer hover:bg-slate-50 shadow-sm transition-all flex items-center">
             <i className="fa-solid fa-upload mr-2"></i> Upload File
             <input type="file" className="hidden" onChange={handleFileUpload} accept=".txt,.md,.json" />
           </label>
           <button 
             onClick={() => setIsUploading(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-medium hover:bg-indigo-700 shadow-lg flex items-center"
           >
             <i className="fa-solid fa-plus mr-2"></i> New Note
           </button>
        </div>
      </header>

      {isUploading && (
        <div className="bg-white p-6 rounded-3xl shadow-lg border border-indigo-100 space-y-4 animate-slideDown">
          <h3 className="font-bold text-slate-800">Add New Note</h3>
          <input 
            className="w-full p-3 border border-slate-200 rounded-xl outline-none focus:ring-2 ring-indigo-500"
            placeholder="Note Title (e.g. Bio Lecture 1)"
            value={newNoteTitle}
            onChange={(e) => setNewNoteTitle(e.target.value)}
          />
          <textarea 
            className="w-full p-3 border border-slate-200 rounded-xl h-32 outline-none focus:ring-2 ring-indigo-500"
            placeholder="Paste your notes here..."
            value={newNoteContent}
            onChange={(e) => setNewNoteContent(e.target.value)}
          />
          <div className="flex justify-end gap-3">
            <button onClick={() => setIsUploading(false)} className="px-4 py-2 text-slate-500">Cancel</button>
            <button onClick={handleManualAdd} className="px-6 py-2 bg-indigo-600 text-white rounded-xl font-medium">Save Note</button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {notes.map((note) => (
          <div key={note.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow flex flex-col group">
            <div className="flex justify-between items-start mb-3">
              <div className="bg-indigo-50 text-indigo-600 p-3 rounded-2xl">
                <i className="fa-solid fa-file-lines text-xl"></i>
              </div>
              <button 
                onClick={() => onDeleteNote(note.id)}
                className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
              >
                <i className="fa-solid fa-trash-can"></i>
              </button>
            </div>
            <h4 className="font-bold text-slate-800 mb-2 truncate">{note.title}</h4>
            <p className="text-slate-500 text-sm line-clamp-3 mb-4 flex-1">
              {note.content}
            </p>
            <div className="flex justify-between items-center pt-4 border-t border-slate-50">
              <span className="text-[10px] text-slate-400 font-medium tracking-wider uppercase">
                {new Date(note.timestamp).toLocaleDateString()}
              </span>
              <button className="text-indigo-600 text-xs font-bold hover:underline">View Details</button>
            </div>
