import SyllabusTracker from './components/SyllabusTracker';
import NotesManager from './components/NotesManager';
import { Subject, Note, Doubt } from './types';
import { INITIAL_SYLLABUS, APP_MODES } from './constants';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<string>(APP_MODES.DASHBOARD);
  const [subjects, setSubjects] = useState<Subject[]>(() => {
    const saved = localStorage.getItem('edupulse_syllabus');
    return saved ? JSON.parse(saved) : INITIAL_SYLLABUS;
  });
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('edupulse_notes');
    return saved ? JSON.parse(saved) : [];
  });
  const [doubts, setDoubts] = useState<Doubt[]>(() => {
    const saved = localStorage.getItem('edupulse_doubts');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('edupulse_syllabus', JSON.stringify(subjects));
  }, [subjects]);

  useEffect(() => {
    localStorage.setItem('edupulse_notes', JSON.stringify(notes));
  }, [notes]);

  useEffect(() => {
    localStorage.setItem('edupulse_doubts', JSON.stringify(doubts));
  }, [doubts]);

  const handleToggleTopic = (subjectId: string, topicId: string) => {
    setSubjects(prev => prev.map(subject => {
      if (subject.id === subjectId) {
        return {
          ...subject,
          topics: subject.topics.map(topic => 
            topic.id === topicId ? { ...topic, completed: !topic.completed } : topic
          )
        };
      }
      return subject;
    }));
  };

  const handleAddNote = (newNoteData: Omit<Note, 'id' | 'timestamp'>) => {
    const newNote: Note = {
      ...newNoteData,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };
    setNotes(prev => [newNote, ...prev]);
  };

  const handleDeleteNote = (id: string) => {
    setNotes(prev => prev.filter(n => n.id !== id));
  };

  const handleSaveDoubt = (doubtData: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => {
    const newDoubt: Doubt = {
      ...doubtData,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      resolved: false
    };
    setDoubts(prev => [newDoubt, ...prev]);
  };

  const renderContent = () => {
    switch (activeMode) {
      case APP_MODES.DASHBOARD:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} />;
      case APP_MODES.CHAT:
        return <AITutor notes={notes} onSaveDoubt={handleSaveDoubt} />;
      case APP_MODES.SYLLABUS:
        return <SyllabusTracker subjects={subjects} onToggleTopic={handleToggleTopic} />;
      case APP_MODES.NOTES:
        return <NotesManager notes={notes} onAddNote={handleAddNote} onDeleteNote={handleDeleteNote} />;
      case APP_MODES.DOUBTS:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold text-slate-800">Saved Doubts</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {doubts.map(doubt => (
                <div key={doubt.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                  <span className="text-[10px] px-2 py-1 bg-amber-50 text-amber-600 rounded-full font-bold mb-2 inline-block">QUESTION</span>
                  <p className="text-sm font-bold text-slate-800 mb-4">{doubt.question}</p>
                  <span className="text-[10px] px-2 py-1 bg-green-50 text-green-600 rounded-full font-bold mb-2 inline-block">AI RESPONSE</span>
                  <p className="text-xs text-slate-600 leading-relaxed bg-slate-50 p-3 rounded-xl">{doubt.answer}</p>
                  <div className="mt-4 flex justify-between items-center text-[10px] text-slate-400">
                    <span>{doubt.subject}</span>
                    <span>{new Date(doubt.timestamp).toLocaleString()}</span>
                  </div>
                </div>
              ))}
              {doubts.length === 0 && <p className="col-span-full text-center py-20 text-slate-400 italic">You haven't saved any doubts yet.</p>}
            </div>
          </div>
        );
      default:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeMode={activeMode} setActiveMode={setActiveMode} />
      <main className="flex-1 ml-64 p-8 overflow-y-auto">
        <div className="max-w-6xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

