import React, { useState, useRef, useEffect } from 'react';
import { Message, Note, Doubt } from '../types';
import { getGeminiResponse } from '../services/geminiService';

interface AITutorProps {
  notes: Note[];
  onSaveDoubt: (doubt: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => void;
}

const AITutor: React.FC<AITutorProps> = ({ notes, onSaveDoubt }) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      parts: [{ text: "Hello! I'm MindOrbit. How can I help with your studies today? You can ask me anything or provide context from your uploaded notes." }],
      timestamp: Date.now(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedNoteId, setSelectedNoteId] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if ((!input.trim() && !selectedNoteId) || isLoading) return;

    const currentInput = input;
    setInput('');

    let parts: any[] = [{ text: currentInput }];

    if (selectedNoteId) {
      const note = notes.find(n => n.id === selectedNoteId);
      if (note) {
        parts.push({ text: `\n\n[CONTEXT FROM NOTE: ${note.title}]\n${note.content}` });
      }
    }

    const newUserMsg: Message = {
      role: 'user',
      parts: [{ text: currentInput }], 
      timestamp: Date.now()
    };

    const conversationHistory = [...messages, { role: 'user', parts, timestamp: Date.now() }];
    setMessages(prev => [...prev, newUserMsg]);
    setIsLoading(true);

    const responseText = await getGeminiResponse(conversationHistory);

    const aiMsg: Message = {
      role: 'model',
      parts: [{ text: responseText }],
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, aiMsg]);
    setIsLoading(false);
    setSelectedNoteId(null);
  };

  const bookmarkDoubt = (msgIndex: number) => {
    const userMsg = messages[msgIndex - 1];
    const aiMsg = messages[msgIndex];
    if (userMsg && aiMsg) {
      onSaveDoubt({
        question: userMsg.parts[0].text || "Unknown question",
        answer: aiMsg.parts[0].text || "No answer provided",
        subject: "General" 
      });
      alert("Doubt saved to your collection!");
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-8rem)] bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="bg-indigo-50 p-4 border-b border-indigo-100 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-full flex items-center justify-center text-white shadow-lg">
            <i className="fa-solid fa-robot"></i>
          </div>
          <div>
            <h3 className="font-bold text-slate-800">MindOrbit AI</h3>
            <span className="text-xs text-indigo-600 font-semibold flex items-center gap-1">
              <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span> Online
            </span>
          </div>
        </div>
        <div className="flex items-center gap-2">
           <select 
             className="text-sm bg-white border border-slate-200 rounded-xl px-3 py-1.5 outline-none focus:ring-2 ring-indigo-500 shadow-sm"
             value={selectedNoteId || ''}
             onChange={(e) => setSelectedNoteId(e.target.value || null)}
           >
             <option value="">Attach Note...</option>
             {notes.map(n => (
               <option key={n.id} value={n.id}>{n.title}</option>
             ))}
           </select>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/30">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] rounded-3xl px-5 py-3 relative group shadow-sm transition-all hover:shadow-md ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white text-slate-800 border border-slate-100 rounded-tl-none'
            }`}>
              <p className="whitespace-pre-wrap text-[0.95rem] leading-relaxed">{msg.parts[0].text}</p>
              {msg.role === 'model' && idx > 0 && (
                <button 
                  onClick={() => bookmarkDoubt(idx)}
                  className="absolute -right-12 top-2 opacity-0 group-hover:opacity-100 transition-opacity p-2 text-slate-400 hover:text-amber-500"
                  title="Save as Doubt"
                >
                  <i className="fa-solid fa-bookmark"></i>
                </button>
              )}
              <span className={`text-[10px] block mt-2 ${msg.role === 'user' ? 'text-indigo-200' : 'text-slate-400'}`}>
                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 text-slate-500 rounded-3xl rounded-tl-none px-5 py-4 shadow-sm">
              <div className="flex gap-1.5">
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-5 bg-white border-t border-slate-100">
        <div className="relative flex items-center max-w-4xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Type your question or concept here..."
            className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 pl-6 pr-14 focus:ring-2 ring-indigo-500 outline-none transition-all shadow-inner"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || (!input.trim() && !selectedNoteId)}
            className="absolute right-3 p-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-all disabled:opacity-50 shadow-lg shadow-indigo-600/30"
          >
            <i className="fa-solid fa-paper-plane"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

