import React, { useState, useRef, useEffect } from 'react';
import { Message, Note, Doubt, ThemeMode } from '../types';
import { getGeminiResponse } from '../services/geminiService';

interface AITutorProps {
  notes: Note[];
  onSaveDoubt: (doubt: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => void;
  theme: ThemeMode;
}

const AITutor: React.FC<AITutorProps> = ({ notes, onSaveDoubt, theme }) => {
  const isDark = theme === 'dark';
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      parts: [{ text: "Systems online. I'm MindOrbit AI. Ready to process your academic queries. Attach notes for deeper analysis." }],
      timestamp: Date.now(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedNoteId, setSelectedNoteId] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if ((!input.trim() && !selectedNoteId) || isLoading) return;

    const currentInput = input;
    setInput('');

    let parts: any[] = [{ text: currentInput }];

    if (selectedNoteId) {
      const note = notes.find(n => n.id === selectedNoteId);
      if (note) {
        parts.push({ text: `\n\n[CONTEXT FROM NOTE: ${note.title}]\n${note.content}` });
      }
    }

    const newUserMsg: Message = {
      role: 'user',
      parts: [{ text: currentInput }], 
      timestamp: Date.now()
    };

    const conversationHistory = [...messages, { role: 'user', parts, timestamp: Date.now() }];
    setMessages(prev => [...prev, newUserMsg]);
    setIsLoading(true);

    const responseText = await getGeminiResponse(conversationHistory);

    const aiMsg: Message = {
      role: 'model',
      parts: [{ text: responseText }],
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, aiMsg]);
    setIsLoading(false);
    setSelectedNoteId(null);
  };

  const bookmarkDoubt = (msgIndex: number) => {
    const userMsg = messages[msgIndex - 1];
    const aiMsg = messages[msgIndex];
    if (userMsg && aiMsg) {
      onSaveDoubt({
        question: userMsg.parts[0].text || "Unknown question",
        answer: aiMsg.parts[0].text || "No answer provided",
        subject: "General" 
      });
      alert("Breakthrough saved!");
    }
  };

  return (
    <div className={`flex flex-col h-[calc(100vh-8rem)] rounded-[2rem] shadow-2xl border overflow-hidden ${isDark ? 'bg-[#1B263B] border-[#415A77]' : 'bg-white border-slate-200'}`}>
      <div className={`p-5 flex justify-between items-center border-b ${isDark ? 'border-slate-800' : 'border-slate-100'}`}>
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-[#4CC9F0] rounded-xl flex items-center justify-center text-[#0D1B2A] shadow-lg shadow-[#4CC9F0]/20">
            <i className="fa-solid fa-microchip"></i>
          </div>
          <div>
            <h3 className={`font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>AI Processing Core</h3>
            <span className="text-[10px] font-black uppercase tracking-widest text-[#4CC9F0] flex items-center gap-2">
              <span className="w-1.5 h-1.5 bg-[#4CC9F0] rounded-full animate-pulse"></span> Stream Active
            </span>
          </div>
        </div>
        <select 
          className={`text-xs font-bold rounded-xl px-4 py-2 outline-none focus:ring-2 ring-[#4CC9F0] ${isDark ? 'bg-[#0D1B2A] border-slate-700 text-slate-300' : 'bg-slate-50 border-slate-200 text-slate-600'}`}
          value={selectedNoteId || ''}
          onChange={(e) => setSelectedNoteId(e.target.value || null)}
        >
          <option value="">Attach Data...</option>
          {notes.map(n => <option key={n.id} value={n.id}>{n.title}</option>)}
        </select>
      </div>

      <div ref={scrollRef} className={`flex-1 overflow-y-auto p-8 space-y-8 ${isDark ? 'bg-[#0D1B2A]/30' : 'bg-slate-50/20'}`}>
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[75%] rounded-3xl px-6 py-4 relative group shadow-sm ${
              msg.role === 'user' 
                ? 'bg-[#4CC9F0] text-[#0D1B2A] rounded-tr-none font-bold' 
                : `${isDark ? 'bg-[#1B263B] text-[#E0E1DD] border-slate-800' : 'bg-white text-slate-800 border-slate-100'} border rounded-tl-none`
            }`}>
              <p className="whitespace-pre-wrap text-[0.95rem] leading-relaxed">{msg.parts[0].text}</p>
              {msg.role === 'model' && idx > 0 && (
                <button 
                  onClick={() => bookmarkDoubt(idx)}
                  className="absolute -right-12 top-2 opacity-0 group-hover:opacity-100 transition-opacity p-2 text-slate-500 hover:text-[#4CC9F0]"
                >
                  <i className="fa-solid fa-bookmark"></i>
                </button>
              )}
              <span className={`text-[9px] font-black uppercase tracking-widest block mt-3 ${msg.role === 'user' ? 'text-[#0D1B2A]/60' : 'text-slate-500'}`}>
                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className={`rounded-3xl rounded-tl-none px-6 py-5 border ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100'}`}>
              <div className="flex gap-2">
                <div className="w-2 h-2 bg-[#4CC9F0] rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-[#4CC9F0] rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-2 h-2 bg-[#4CC9F0] rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className={`p-6 ${isDark ? 'bg-[#1B263B]' : 'bg-white'} border-t ${isDark ? 'border-slate-800' : 'border-slate-100'}`}>
        <div className="relative flex items-center max-w-5xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Input query for the AI processing core..."
            className={`w-full rounded-2xl py-5 pl-8 pr-16 focus:ring-2 ring-[#4CC9F0] outline-none transition-all font-medium ${isDark ? 'bg-[#0D1B2A] border-slate-700 text-white placeholder-slate-600' : 'bg-slate-50 border-slate-200 text-slate-900'}`}
          />
          <button
            onClick={handleSend}
            disabled={isLoading || (!input.trim() && !selectedNoteId)}
            className="absolute right-3 p-4 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl hover:scale-105 active:scale-95 transition-all disabled:opacity-50 shadow-xl shadow-[#4CC9F0]/20"
          >
            <i className="fa-solid fa-paper-plane-top"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default AITutor;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
