import { Subject, Note, Doubt, Reminder, ThemeMode } from './types';
import { INITIAL_SYLLABUS, APP_MODES } from './constants';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<string>(APP_MODES.LANDING);
  const [theme, setTheme] = useState<ThemeMode>(() => {
    const saved = localStorage.getItem('mindorbit_theme');
    return (saved as ThemeMode) || 'dark';
  });

  const [subjects, setSubjects] = useState<Subject[]>(() => {
    const saved = localStorage.getItem('mindorbit_syllabus');
    return saved ? JSON.parse(saved) : INITIAL_SYLLABUS;
  });
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('mindorbit_notes');
    return saved ? JSON.parse(saved) : [];
  });
  const [doubts, setDoubts] = useState<Doubt[]>(() => {
    const saved = localStorage.getItem('mindorbit_doubts');
    return saved ? JSON.parse(saved) : [];
  });
  const [reminders, setReminders] = useState<Reminder[]>(() => {
    const saved = localStorage.getItem('mindorbit_reminders');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('mindorbit_syllabus', JSON.stringify(subjects));
  }, [subjects]);

  useEffect(() => {
    localStorage.setItem('mindorbit_notes', JSON.stringify(notes));
  }, [notes]);

  useEffect(() => {
    localStorage.setItem('mindorbit_doubts', JSON.stringify(doubts));
  }, [doubts]);

  useEffect(() => {
    localStorage.setItem('mindorbit_reminders', JSON.stringify(reminders));
  }, [reminders]);

  useEffect(() => {
    localStorage.setItem('mindorbit_theme', theme);
    document.body.className = theme;
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const handleToggleTopic = (subjectId: string, topicId: string) => {
    setSubjects(prev => prev.map(subject => {
      if (subject.id === subjectId) {
        return {
          ...subject,
          topics: subject.topics.map(topic => 
            topic.id === topicId ? { ...topic, completed: !topic.completed } : topic
          )
        };
      }
      return subject;
    }));
  };

  const handleAddNote = (newNoteData: Omit<Note, 'id' | 'timestamp'>) => {
    const newNote: Note = {
      ...newNoteData,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };
    setNotes(prev => [newNote, ...prev]);
  };

  const handleDeleteNote = (id: string) => {
    setNotes(prev => prev.filter(n => n.id !== id));
  };

  const handleSaveDoubt = (doubtData: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => {
    const newDoubt: Doubt = {
      ...doubtData,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      resolved: false
    };
    setDoubts(prev => [newDoubt, ...prev]);
  };

  const handleAddReminder = (task: string, time: string) => {
    const newReminder: Reminder = {
      id: Math.random().toString(36).substr(2, 9),
      task,
      time,
      completed: false
    };
    setReminders(prev => [...prev, newReminder]);
  };

  const toggleReminder = (id: string) => {
    setReminders(prev => prev.map(r => r.id === id ? { ...r, completed: !r.completed } : r));
  };

  const deleteReminder = (id: string) => {
    setReminders(prev => prev.filter(r => r.id !== id));
  };

  const renderContent = () => {
    const isDark = theme === 'dark';

    switch (activeMode) {
      case APP_MODES.DASHBOARD:
        return (
          <div className="space-y-10 animate-fadeIn">
            <Dashboard subjects={subjects} notes={notes} doubts={doubts} />

            {/* Reminder Section integrated into Dashboard */}
            <div className={`p-8 rounded-[2rem] border ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-sm'}`}>
              <div className="flex justify-between items-center mb-6">
                <h3 className={`text-xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Mission Reminders</h3>
                <button 
                  onClick={() => {
                    const task = prompt("Enter mission task:");
                    const time = prompt("Enter time (e.g. 2:00 PM):");
                    if (task && time) handleAddReminder(task, time);
                  }}
                  className="px-4 py-2 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-xl text-xs font-black uppercase tracking-widest border border-[#4CC9F0]/20 hover:bg-[#4CC9F0] hover:text-[#0D1B2A] transition-all"
                >
                  <i className="fa-solid fa-plus mr-2"></i> New Target
                </button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {reminders.map(rem => (
                  <div key={rem.id} className={`p-5 rounded-2xl border flex items-center gap-4 transition-all ${isDark ? 'bg-[#0D1B2A] border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
                    <button 
                      onClick={() => toggleReminder(rem.id)}
                      className={`w-6 h-6 rounded-lg flex items-center justify-center border-2 transition-all ${rem.completed ? 'bg-[#4CAF50] border-[#4CAF50] text-[#0D1B2A]' : 'border-slate-700'}`}
                    >
                      {rem.completed && <i className="fa-solid fa-check text-xs"></i>}
                    </button>
                    <div className="flex-1">
                      <p className={`text-sm font-bold ${rem.completed ? 'line-through opacity-50' : isDark ? 'text-white' : 'text-slate-800'}`}>{rem.task}</p>
                      <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{rem.time}</p>
                    </div>
                    <button onClick={() => deleteReminder(rem.id)} className="text-slate-600 hover:text-red-500 transition-colors">
                      <i className="fa-solid fa-trash-can text-sm"></i>
                    </button>
                  </div>
                ))}
                {reminders.length === 0 && <p className="col-span-full text-center py-8 text-slate-500 font-bold italic opacity-60">No pending reminders.</p>}
              </div>
            </div>
          </div>
        );
      case APP_MODES.CHAT:
        return <AITutor notes={notes} onSaveDoubt={handleSaveDoubt} theme={theme} />;
      case APP_MODES.SYLLABUS:
        return <SyllabusTracker subjects={subjects} onToggleTopic={handleToggleTopic} />;
      case APP_MODES.NOTES:
        return <NotesManager notes={notes} onAddNote={handleAddNote} onDeleteNote={handleDeleteNote} />;
      case APP_MODES.DOUBTS:
        return (
          <div className="space-y-8 animate-fadeIn">
            <header>
              <h2 className={`text-3xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>The Vault</h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Archived intelligence and breakthrough moments.</p>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {doubts.map(doubt => (
                <div key={doubt.id} className={`p-8 rounded-[2rem] border transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-sm'}`}>
                  <div className="flex justify-between items-center mb-6">
                    <span className="text-[10px] px-3 py-1 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-full font-black uppercase tracking-widest border border-[#4CC9F0]/20">Question</span>
                    <span className="text-[10px] font-black text-slate-500 uppercase">{doubt.subject}</span>
                  </div>
                  <p className={`text-xl font-bold mb-6 leading-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>{doubt.question}</p>

                  <div className={`p-6 rounded-2xl italic text-sm leading-relaxed ${isDark ? 'bg-[#0D1B2A] text-slate-400' : 'bg-slate-50 text-slate-600'}`}>
                    {doubt.answer}
                  </div>
                  <div className="mt-6 pt-4 border-t border-slate-800/20 flex justify-between items-center text-[10px] text-slate-500 font-bold uppercase tracking-widest">
                    <span>{new Date(doubt.timestamp).toLocaleDateString()}</span>
                    <button className="text-[#4CC9F0] hover:underline">Re-examine</button>
                  </div>
                </div>
              ))}
              {doubts.length === 0 && (
                <div className={`col-span-full py-20 text-center rounded-[3rem] border-2 border-dashed ${isDark ? 'border-slate-800 bg-slate-900/20' : 'border-slate-200 bg-slate-50/50'}`}>
                  <p className="text-slate-500 font-black text-lg">Knowledge Vault is Locked</p>
                  <p className="text-slate-600 text-sm mt-2">Bookmark AI responses to store them here.</p>
                </div>
              )}
            </div>
          </div>
        );
      default:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} />;
    }
  };

  if (activeMode === APP_MODES.LANDING) {
    return <LandingPage onStart={() => setActiveMode(APP_MODES.DASHBOARD)} theme={theme} />;
  }

  return (
    <div className={`flex min-h-screen transition-colors duration-300 ${theme === 'dark' ? 'bg-[#0D1B2A]' : 'bg-slate-50'}`}>
      <Sidebar activeMode={activeMode} setActiveMode={setActiveMode} theme={theme} toggleTheme={toggleTheme} />
      <main className="flex-1 ml-64 p-12 overflow-y-auto">
        <div className="max-w-6xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

