import React, { useState, useEffect } from 'react';
import { Reminder, ThemeMode } from '../types';

interface StudyPlannerProps {
  reminders: Reminder[];
  onAddReminder: (task: string, time: string, type: Reminder['type']) => void;
  onToggleReminder: (id: string) => void;
  onDeleteReminder: (id: string) => void;
  theme: ThemeMode;
}

const StudyPlanner: React.FC<StudyPlannerProps> = ({ reminders, onAddReminder, onToggleReminder, onDeleteReminder, theme }) => {
  const isDark = theme === 'dark';
  const [timeLeft, setTimeLeft] = useState(25 * 60);
  const [isActive, setIsActive] = useState(false);
  const [mode, setMode] = useState<'Work' | 'Break'>('Work');

  useEffect(() => {
    let interval: any = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      const audio = new Audio('https://actions.google.com/sounds/v1/alarms/beep_short.ogg');
      audio.play();
      if (mode === 'Work') {
        setMode('Break');
        setTimeLeft(5 * 60);
      } else {
        setMode('Work');
        setTimeLeft(25 * 60);
      }
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode]);

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className="space-y-10 animate-fadeIn pb-12">
      <header>
        <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Study <span className="text-[#4CC9F0]">Navigator</span></h2>
        <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Manage your time and mission objectives.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Pomodoro Timer */}
        <div className={`lg:col-span-1 p-10 rounded-[3rem] border flex flex-col items-center justify-center transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
          <h3 className={`text-xl font-black mb-10 ${isDark ? 'text-white' : 'text-slate-800'}`}>{mode} Cycle</h3>
          <div className="relative w-56 h-56 flex items-center justify-center">
            <svg className="absolute w-full h-full -rotate-90">
              <circle cx="112" cy="112" r="100" stroke={isDark ? '#0D1B2A' : '#f1f5f9'} strokeWidth="12" fill="none" />
              <circle 
                cx="112" cy="112" r="100" 
                stroke="#4CC9F0" strokeWidth="12" fill="none"
                strokeDasharray="628"
                strokeDashoffset={628 - (628 * timeLeft) / (mode === 'Work' ? 25 * 60 : 5 * 60)}
                className="transition-all duration-1000 ease-linear"
                strokeLinecap="round"
              />
            </svg>
            <div className="text-center">
              <p className={`text-6xl font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>{formatTime(timeLeft)}</p>
              <p className="text-[10px] font-black text-[#4CC9F0] uppercase tracking-widest mt-2">Remaining</p>
            </div>
          </div>
          <div className="flex gap-4 mt-12">
            <button 
              onClick={() => setIsActive(!isActive)}
              className="w-16 h-16 rounded-2xl bg-[#4CC9F0] text-[#0D1B2A] flex items-center justify-center text-xl shadow-xl shadow-[#4CC9F0]/20 hover:scale-110 active:scale-95 transition-all"
            >
              <i className={`fa-solid ${isActive ? 'fa-pause' : 'fa-play'}`}></i>
            </button>
            <button 
              onClick={() => { setIsActive(false); setTimeLeft(mode === 'Work' ? 25 * 60 : 5 * 60); }}
              className={`w-16 h-16 rounded-2xl border flex items-center justify-center text-xl transition-all ${isDark ? 'border-slate-700 text-slate-400 hover:bg-slate-800' : 'border-slate-200 text-slate-400 hover:bg-slate-50'}`}
            >
              <i className="fa-solid fa-rotate-left"></i>
            </button>
          </div>
        </div>

        {/* Task List */}
        <div className={`lg:col-span-2 p-10 rounded-[3rem] border transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
          <div className="flex justify-between items-center mb-10">
            <h3 className={`text-xl font-black ${isDark ? 'text-white' : 'text-slate-800'}`}>Mission Objectives</h3>
            <button 
              onClick={() => {
                const task = prompt("Objective Name:");
                const time = prompt("Target Time (e.g. 5:00 PM):");
                if (task && time) onAddReminder(task, time, 'Study');
              }}
              className="px-6 py-2.5 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-xl text-[10px] font-black uppercase tracking-widest border border-[#4CC9F0]/20 hover:bg-[#4CC9F0] hover:text-[#0D1B2A] transition-all"
            >
              <i className="fa-solid fa-plus mr-2"></i> New Target
            </button>
          </div>
          <div className="space-y-4">
            {reminders.map(rem => (
              <div key={rem.id} className={`p-6 rounded-[2rem] border flex items-center gap-5 transition-all group ${isDark ? 'bg-[#0D1B2A] border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
                <button 
                  onClick={() => onToggleReminder(rem.id)}
                  className={`w-8 h-8 rounded-xl flex items-center justify-center border-2 transition-all ${rem.completed ? 'bg-[#4CAF50] border-[#4CAF50] text-[#0D1B2A]' : 'border-slate-700 hover:border-[#4CC9F0]'}`}
                >
                  {rem.completed && <i className="fa-solid fa-check text-sm"></i>}
                </button>
                <div className="flex-1">
                  <p className={`text-lg font-bold ${rem.completed ? 'line-through opacity-30' : isDark ? 'text-white' : 'text-slate-900'}`}>{rem.task}</p>
                  <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest mt-1 flex items-center gap-2">
                    <i className="fa-solid fa-clock text-[#4CC9F0]"></i> {rem.time}
                    <span className="px-2 py-0.5 bg-[#4CC9F0]/5 text-[#4CC9F0] rounded-md text-[8px]">{rem.type}</span>
                  </p>
                </div>
                <button onClick={() => onDeleteReminder(rem.id)} className="text-slate-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-3">
                  <i className="fa-solid fa-trash-can"></i>
                </button>
              </div>
            ))}
            {reminders.length === 0 && (
              <div className="py-20 text-center opacity-40">
                <i className="fa-solid fa-ghost text-4xl mb-4"></i>
                <p className="font-bold italic">Clear orbits. No objectives detected.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StudyPlanner;

import React, { useState, useRef, useEffect } from 'react';
import { Message, Note, Doubt, ThemeMode, StudyMode } from '../types';
import { getGeminiResponse } from '../services/geminiService';

interface AITutorProps {
  notes: Note[];
  onSaveDoubt: (doubt: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => void;
  theme: ThemeMode;
}

const AITutor: React.FC<AITutorProps> = ({ notes, onSaveDoubt, theme }) => {
  const isDark = theme === 'dark';
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      parts: [{ text: "Orbit active. Systems running at 100%. Main tumhara personal AI tutor hoon. Poocho, kya seekhna hai aaj? You can switch modes for different styles of explanations." }],
      timestamp: Date.now(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedNoteId, setSelectedNoteId] = useState<string | null>(null);
  const [studyMode, setStudyMode] = useState<StudyMode>('Normal');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isLoading]);

  const handleSend = async () => {
    if ((!input.trim() && !selectedNoteId) || isLoading) return;

    const currentInput = input;
    setInput('');

    let parts: any[] = [{ text: currentInput }];
    if (selectedNoteId) {
      const note = notes.find(n => n.id === selectedNoteId);
      if (note) parts.push({ text: `\n\n[CONTEXT FROM NOTE: ${note.title}]\n${note.content}` });
    }

    const newUserMsg: Message = { role: 'user', parts: [{ text: currentInput }], timestamp: Date.now(), mode: studyMode };
    setMessages(prev => [...prev, newUserMsg]);
    setIsLoading(true);

    const responseText = await getGeminiResponse([...messages, { role: 'user', parts, timestamp: Date.now() }], studyMode);

    setMessages(prev => [...prev, { role: 'model', parts: [{ text: responseText }], timestamp: Date.now() }]);
    setIsLoading(false);
    setSelectedNoteId(null);
  };

  return (
    <div className={`flex flex-col h-[calc(100vh-8rem)] rounded-[3.5rem] shadow-2xl border overflow-hidden transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-200'}`}>
      {/* AI Header */}
      <div className={`p-6 flex flex-wrap justify-between items-center border-b gap-4 ${isDark ? 'border-slate-800' : 'border-slate-100'}`}>
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-[#4CC9F0] rounded-2xl flex items-center justify-center text-[#0D1B2A] text-xl shadow-xl shadow-[#4CC9F0]/20">
            <i className="fa-solid fa-brain-circuit"></i>
          </div>
          <div>
            <h3 className={`font-black tracking-tight text-lg ${isDark ? 'text-white' : 'text-slate-900'}`}>Neural Orbit Assistant</h3>
            <div className="flex items-center gap-3 mt-0.5">
               <span className="text-[9px] font-black uppercase tracking-widest text-[#4CAF50] flex items-center gap-1.5">
                 <span className="w-1.5 h-1.5 bg-[#4CAF50] rounded-full animate-pulse"></span> Core Ready
               </span>
               <span className={`text-[9px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md ${isDark ? 'bg-slate-800 text-slate-400' : 'bg-slate-50 text-slate-500'}`}>
                 Hinglish Supported
               </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className={`flex p-1.5 rounded-2xl border ${isDark ? 'bg-[#0D1B2A] border-slate-700' : 'bg-slate-50 border-slate-200'}`}>
            {(['Normal', 'ELI5', 'Exam-Oriented'] as StudyMode[]).map(m => (
              <button
                key={m}
                onClick={() => setStudyMode(m)}
                className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${studyMode === m ? 'bg-[#4CC9F0] text-[#0D1B2A]' : 'text-slate-500 hover:text-slate-400'}`}
              >
                {m}
              </button>
            ))}
          </div>
          <select 
            className={`text-[10px] font-black uppercase tracking-widest rounded-2xl px-5 py-3.5 outline-none transition-all ${isDark ? 'bg-[#0D1B2A] border-slate-700 text-slate-300' : 'bg-white border-slate-200 text-slate-600 shadow-sm'}`}
            value={selectedNoteId || ''}
            onChange={(e) => setSelectedNoteId(e.target.value || null)}
          >
            <option value="">Neural Context (OFF)</option>
            {notes.map(n => <option key={n.id} value={n.id}>{n.title}</option>)}
          </select>
        </div>
      </div>

      {/* Chat Area */}
      <div ref={scrollRef} className={`flex-1 overflow-y-auto p-10 space-y-10 ${isDark ? 'bg-[#0D1B2A]/20' : 'bg-slate-50/20'}`}>
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[75%] group relative ${msg.role === 'user' ? 'flex flex-col items-end' : 'flex flex-col items-start'}`}>
              <div className={`rounded-[2.5rem] px-8 py-5 shadow-sm transition-all ${
                msg.role === 'user' 
                  ? 'bg-[#4CC9F0] text-[#0D1B2A] rounded-tr-none font-bold text-lg' 
                  : `${isDark ? 'bg-[#1B263B] text-[#E0E1DD] border-slate-800' : 'bg-white text-slate-800 border-slate-100 shadow-xl'} border rounded-tl-none`
              }`}>
                {msg.role === 'model' && (
                  <div className="flex gap-2 mb-3">
                    <span className="w-2 h-2 rounded-full bg-[#4CC9F0]"></span>
                    <span className="w-2 h-2 rounded-full bg-[#4CAF50]"></span>
                  </div>
                )}
                <p className="whitespace-pre-wrap leading-relaxed">{msg.parts[0].text}</p>
              </div>

              {msg.role === 'model' && idx > 0 && (
                <button 
                  onClick={() => onSaveDoubt(idx)}
                  className="mt-3 flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-[#4CC9F0] transition-colors"
                >
                  <i className="fa-solid fa-bookmark"></i> Save to Vault
                </button>
              )}

              <span className={`text-[9px] font-black uppercase tracking-widest mt-2 ${msg.role === 'user' ? 'text-[#4CC9F0]/60' : 'text-slate-600'}`}>
                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • {msg.mode || studyMode}
              </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className={`rounded-full px-8 py-4 border animate-pulse ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
              <div className="flex gap-3">
                <div className="w-2.5 h-2.5 bg-[#4CC9F0] rounded-full animate-bounce"></div>
                <div className="w-2.5 h-2.5 bg-[#4CC9F0] rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-2.5 h-2.5 bg-[#4CC9F0] rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Chat Input */}
      <div className={`p-8 ${isDark ? 'bg-[#1B263B]' : 'bg-white'} border-t ${isDark ? 'border-slate-800' : 'border-slate-100'}`}>
        <div className="relative flex items-center max-w-6xl mx-auto group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Poocho apne sawaal... (Hinglish Supported)"
            className={`w-full rounded-3xl py-6 pl-10 pr-20 focus:ring-4 ring-[#4CC9F0]/10 outline-none transition-all font-bold text-lg ${isDark ? 'bg-[#0D1B2A] border-slate-700 text-white placeholder-slate-700' : 'bg-slate-50 border-slate-200 text-slate-900'}`}
          />
          <div className="absolute right-4 flex items-center gap-2">
            <button className={`p-4 rounded-2xl transition-all ${isDark ? 'text-slate-500 hover:text-[#4CC9F0]' : 'text-slate-300 hover:text-[#4CC9F0]'}`}>
               <i className="fa-solid fa-microphone"></i>
            </button>
            <button
              onClick={handleSend}
              disabled={isLoading || (!input.trim() && !selectedNoteId)}
              className="p-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl hover:scale-105 active:scale-95 transition-all disabled:opacity-50 shadow-2xl shadow-[#4CC9F0]/30"
            >
              <i className="fa-solid fa-paper-plane-top text-xl"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AITutor;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import AITutor from './components/AITutor';
import SyllabusTracker from './components/SyllabusTracker';
import NotesManager from './components/NotesManager';
import LandingPage from './components/LandingPage';
import StudyPlanner from './components/StudyPlanner';
import { Subject, Note, Doubt, Reminder, ThemeMode } from './types';
import { INITIAL_SYLLABUS, APP_MODES } from './constants';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<string>(APP_MODES.LANDING);
  const [theme, setTheme] = useState<ThemeMode>(() => (localStorage.getItem('mindorbit_theme') as ThemeMode) || 'dark');
  const [subjects, setSubjects] = useState<Subject[]>(() => {
    const saved = localStorage.getItem('mindorbit_syllabus');
    return saved ? JSON.parse(saved) : INITIAL_SYLLABUS;
  });
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('mindorbit_notes');
    return saved ? JSON.parse(saved) : [];
  });
  const [doubts, setDoubts] = useState<Doubt[]>(() => {
    const saved = localStorage.getItem('mindorbit_doubts');
    return saved ? JSON.parse(saved) : [];
  });
  const [reminders, setReminders] = useState<Reminder[]>(() => {
    const saved = localStorage.getItem('mindorbit_reminders');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('mindorbit_syllabus', JSON.stringify(subjects));
    localStorage.setItem('mindorbit_notes', JSON.stringify(notes));
    localStorage.setItem('mindorbit_doubts', JSON.stringify(doubts));
    localStorage.setItem('mindorbit_reminders', JSON.stringify(reminders));
    localStorage.setItem('mindorbit_theme', theme);
    document.body.className = theme;
  }, [subjects, notes, doubts, reminders, theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const handleToggleTopic = (subjectId: string, topicId: string) => {
    setSubjects(prev => prev.map(s => s.id === subjectId ? { ...s, topics: s.topics.map(t => t.id === topicId ? { ...t, completed: !t.completed } : t) } : s));
  };

  const handleAddNote = (newNoteData: Omit<Note, 'id' | 'timestamp'>) => {
    setNotes(prev => [{ ...newNoteData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now() }, ...prev]);
  };

  const handleDeleteNote = (id: string) => setNotes(prev => prev.filter(n => n.id !== id));

  const handleSaveDoubt = (doubtData: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => {
    setDoubts(prev => [{ ...doubtData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now(), resolved: false }, ...prev]);
  };

  const handleAddReminder = (task: string, time: string, type: Reminder['type'] = 'Study') => {
    setReminders(prev => [...prev, { id: Math.random().toString(36).substr(2, 9), task, time, completed: false, type }]);
  };

  const toggleReminder = (id: string) => setReminders(prev => prev.map(r => r.id === id ? { ...r, completed: !r.completed } : r));
  const deleteReminder = (id: string) => setReminders(prev => prev.filter(r => r.id !== id));

  const renderContent = () => {
    const isDark = theme === 'dark';
    switch (activeMode) {
      case APP_MODES.DASHBOARD:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} />;
      case APP_MODES.CHAT:
        return <AITutor notes={notes} onSaveDoubt={handleSaveDoubt} theme={theme} />;
      case APP_MODES.PLANNER:
        return <StudyPlanner reminders={reminders} onAddReminder={handleAddReminder} onToggleReminder={toggleReminder} onDeleteReminder={deleteReminder} theme={theme} />;
      case APP_MODES.SYLLABUS:
        return <SyllabusTracker subjects={subjects} onToggleTopic={handleToggleTopic} />;
      case APP_MODES.NOTES:
        return <NotesManager notes={notes} onAddNote={handleAddNote} onDeleteNote={handleDeleteNote} />;
      case APP_MODES.DOUBTS:
        return (
          <div className="space-y-10 animate-fadeIn">
            <header>
              <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>The <span className="text-[#4CC9F0]">Vault</span></h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Permanently archived intelligence blocks.</p>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {doubts.map(doubt => (
                <div key={doubt.id} className={`p-10 rounded-[3rem] border transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
                  <div className="flex justify-between items-center mb-8">
                    <span className="text-[10px] px-4 py-1.5 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-full font-black uppercase tracking-widest border border-[#4CC9F0]/20">Doubt #0{doubt.id.substring(0,2)}</span>
                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{doubt.subject}</span>
                  </div>
                  <p className={`text-xl font-bold mb-8 leading-tight ${isDark ? 'text-white' : 'text-slate-950'}`}>{doubt.question}</p>
                  <div className={`p-8 rounded-[2rem] italic text-sm leading-relaxed border ${isDark ? 'bg-[#0D1B2A] border-slate-800 text-slate-400' : 'bg-slate-50 border-slate-100 text-slate-600'}`}>
                    {doubt.answer}
                  </div>
                  <div className="mt-10 pt-6 border-t border-slate-800/20 flex justify-between items-center text-[10px] text-slate-500 font-black uppercase tracking-widest">
                    <span>Date: {new Date(doubt.timestamp).toLocaleDateString()}</span>
                    <button className="text-[#4CC9F0] hover:underline flex items-center gap-2">
                      <i className="fa-solid fa-up-right-from-square"></i> Full Thread
                    </button>
                  </div>
                </div>
              ))}
              {doubts.length === 0 && <div className="col-span-full py-32 text-center opacity-30 italic font-black text-2xl tracking-tighter">VAULT_EMPTY.SYS</div>}
            </div>
          </div>
        );
      default:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} />;
    }
  };

  if (activeMode === APP_MODES.LANDING) {
    return <LandingPage onStart={() => setActiveMode(APP_MODES.DASHBOARD)} theme={theme} />;
  }

  return (
    <div className={`flex min-h-screen transition-colors duration-500 ${theme === 'dark' ? 'bg-[#0D1B2A]' : 'bg-slate-50'}`}>
      <Sidebar activeMode={activeMode} setActiveMode={setActiveMode} theme={theme} toggleTheme={toggleTheme} />
      <main className="flex-1 ml-72 p-16 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

