interface SyllabusTrackerProps {
  subjects: Subject[];
  onToggleTopic: (subjectId: string, topicId: string) => void;
  theme: ThemeMode;
}

const SyllabusTracker: React.FC<SyllabusTrackerProps> = ({ subjects, onToggleTopic, theme }) => {
  const isDark = theme === 'dark';
  const [selectedClass, setSelectedClass] = useState<string>('All');

  const classes = ['All', ...Array.from(new Set(subjects.map(s => s.classLevel)))];
  const filteredSubjects = selectedClass === 'All' ? subjects : subjects.filter(s => s.classLevel === selectedClass);

  const getSubjectIcon = (name: string) => {
    const n = name.toLowerCase();
    if (n.includes('math')) return 'fa-function';
    if (n.includes('phys')) return 'fa-atom';
    if (n.includes('comp')) return 'fa-code';
    if (n.includes('bio')) return 'fa-dna';
    if (n.includes('hist')) return 'fa-landmark';
    if (n.includes('chem')) return 'fa-flask';
    return 'fa-book-sparkles';
  };

  return (
    <div className="space-y-10 animate-fadeIn pb-12">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Syllabus <span className="text-[#4CC9F0]">Orbit</span></h2>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Class-wise roadmap to academic excellence.</p>
        </div>
        <div className="flex gap-4">
          <select 
            className={`px-6 py-3 rounded-2xl border font-bold text-xs uppercase tracking-widest outline-none focus:ring-2 ring-[#4CC9F0] ${isDark ? 'bg-[#1B263B] border-slate-700 text-slate-300' : 'bg-white border-slate-200 text-slate-600 shadow-sm'}`}
            value={selectedClass}
            onChange={(e) => setSelectedClass(e.target.value)}
          >
            {classes.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <button className="px-6 py-3 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-[#4CC9F0]/20 hover:scale-105 active:scale-95 transition-all">
            <i className="fa-solid fa-plus mr-2"></i> Add Subject
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
        {filteredSubjects.map((subject) => {
          const completedCount = subject.topics.filter(t => t.completed).length;
          const progress = Math.round((completedCount / subject.topics.length) * 100);

          return (
            <div key={subject.id} className={`rounded-[3rem] p-8 border transition-all hover:scale-[1.01] ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-4">
                  <div className="w-14 h-14 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-2xl flex items-center justify-center text-2xl shadow-inner border border-[#4CC9F0]/10">
                    <i className={`fa-solid ${getSubjectIcon(subject.name)}`}></i>
                  </div>
                  <div>
                    <h3 className={`text-xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>{subject.name}</h3>
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{subject.classLevel}</p>
                  </div>
                </div>
                <div className="text-right">
                  <span className="text-3xl font-black text-[#4CC9F0]">{progress}%</span>
                </div>
              </div>

              <div className={`w-full h-3 rounded-full mb-8 overflow-hidden ${isDark ? 'bg-slate-800' : 'bg-slate-100'}`}>
                <div 
                  className="bg-[#4CC9F0] h-full rounded-full transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(76,201,240,0.5)]" 
                  style={{ width: `${progress}%` }}
                ></div>
              </div>

              <div className="space-y-3">
                {subject.topics.map((topic) => (
                  <label 
                    key={topic.id} 
                    className={`flex items-center p-4 rounded-2xl border transition-all cursor-pointer group select-none ${
                      topic.completed 
                        ? (isDark ? 'bg-[#0D1B2A]/50 border-[#4CC9F0]/20' : 'bg-blue-50/50 border-blue-100/50') 
                        : (isDark ? 'bg-slate-800/20 border-slate-800 hover:border-[#4CC9F0]/50' : 'bg-white border-slate-100 hover:border-blue-200')
                    }`}
                  >
                    <div className="relative flex items-center justify-center mr-4">
                       <input
                        type="checkbox"
                        checked={topic.completed}
                        onChange={() => onToggleTopic(subject.id, topic.id)}
                        className="peer w-6 h-6 rounded-lg text-[#4CC9F0] focus:ring-[#4CC9F0] border-slate-300 cursor-pointer transition-all"
                      />
                    </div>
                    <div className="flex-1">
                      <span className={`text-sm font-bold tracking-tight ${topic.completed ? (isDark ? 'text-slate-500 line-through' : 'text-slate-400 line-through') : (isDark ? 'text-slate-200' : 'text-slate-700')}`}>
                        {topic.name}
                      </span>
                      <div className="flex gap-2 mt-1">
                        <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded ${topic.revisionStatus === 'Mastered' ? 'bg-[#4CAF50]/10 text-[#4CAF50]' : topic.revisionStatus === 'Partial' ? 'bg-amber-500/10 text-amber-500' : 'bg-slate-500/10 text-slate-500'}`}>
                          {topic.revisionStatus}
                        </span>
                      </div>
                    </div>
                    <button className="text-slate-500 group-hover:text-[#4CC9F0] transition-colors p-2">
                      <i className="fa-solid fa-circle-info"></i>
                    </button>
                  </label>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default SyllabusTracker;

import React, { useState } from 'react';
import { ThemeMode, TopicStudy } from '../types';
import { getGeminiResponse } from '../services/geminiService';

interface DeepDiveProps {
  theme: ThemeMode;
}

const DeepDive: React.FC<DeepDiveProps> = ({ theme }) => {
  const isDark = theme === 'dark';
  const [query, setQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<TopicStudy | null>(null);

  const handleDeepDive = async () => {
    if (!query.trim() || isLoading) return;
    setIsLoading(true);

    const messages = [{
      role: 'user' as const,
      parts: [{ text: `Provide a comprehensive, high-quality, step-by-step master guide for the topic: "${query}". Include definition, core concepts, key formulas (if any), 3 real-world examples, and a summary. Structure it perfectly for a student.` }],
      timestamp: Date.now()
    }];

    const content = await getGeminiResponse(messages, 'Normal');
    setResult({
      topicName: query,
      content,
      timestamp: Date.now()
    });
    setIsLoading(false);
  };

  return (
    <div className="space-y-10 animate-fadeIn pb-12">
      <header>
        <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Deep <span className="text-[#4CC9F0]">Dive</span></h2>
        <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Universal knowledge retrieval for any subject.</p>
      </header>

      <div className={`p-10 rounded-[3rem] border transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
        <div className="max-w-3xl mx-auto space-y-6">
          <p className={`text-center font-bold ${isDark ? 'text-slate-400' : 'text-slate-600'}`}>Enter any topic to get a full contextual master guide generated by MindOrbit AI.</p>
          <div className="relative flex items-center">
            <input 
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleDeepDive()}
              placeholder="e.g., Quantum Entanglement, Cellular Respiration, Calculus Integrals..."
              className={`w-full rounded-3xl py-6 pl-8 pr-20 font-bold text-lg outline-none focus:ring-4 ring-[#4CC9F0]/20 transition-all ${isDark ? 'bg-[#0D1B2A] border-slate-700 text-white placeholder-slate-700' : 'bg-slate-50 border-slate-200 text-slate-900'}`}
            />
            <button 
              onClick={handleDeepDive}
              disabled={isLoading || !query.trim()}
              className="absolute right-3 p-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl hover:scale-105 active:scale-95 transition-all disabled:opacity-50 shadow-xl shadow-[#4CC9F0]/20"
            >
              {isLoading ? <i className="fa-solid fa-spinner-third animate-spin"></i> : <i className="fa-solid fa-radar text-xl"></i>}
            </button>
          </div>
        </div>
      </div>

      {result && (
        <div className={`p-12 rounded-[3.5rem] border animate-slideUp transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-2xl'}`}>
          <div className="flex justify-between items-center mb-10 pb-6 border-b border-slate-800/20">
            <h3 className={`text-3xl font-black tracking-tighter ${isDark ? 'text-white' : 'text-slate-900'}`}>{result.topicName}</h3>
            <button className="flex items-center gap-2 px-6 py-2 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-xl text-xs font-black uppercase tracking-widest border border-[#4CC9F0]/20">
              <i className="fa-solid fa-download"></i> Save Guide
            </button>
          </div>
          <div className={`prose prose-invert max-w-none whitespace-pre-wrap leading-relaxed font-medium ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>
            {result.content}
          </div>
        </div>
      )}

      {!result && !isLoading && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {['Periodic Table Trends', 'World War I Causes', 'Python Decorators'].map(suggestion => (
            <button 
              key={suggestion}
              onClick={() => { setQuery(suggestion); }}
              className={`p-6 rounded-[2rem] border text-left group transition-all ${isDark ? 'bg-[#1B263B]/40 border-slate-800 hover:border-[#4CC9F0]' : 'bg-white border-slate-100 hover:border-blue-400'}`}
            >
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Try Suggestion</p>
              <p className={`font-bold transition-all ${isDark ? 'text-slate-300 group-hover:text-[#4CC9F0]' : 'text-slate-700 group-hover:text-blue-600'}`}>{suggestion}</p>
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

export default DeepDive;

