import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import AITutor from './components/AITutor';
import SyllabusTracker from './components/SyllabusTracker';
import NotesManager from './components/NotesManager';
import LandingPage from './components/LandingPage';
import StudyPlanner from './components/StudyPlanner';
import DeepDive from './components/DeepDive';
import { Subject, Note, Doubt, Reminder, ThemeMode } from './types';
import { INITIAL_SYLLABUS, APP_MODES } from './constants';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<string>(APP_MODES.LANDING);
  const [theme, setTheme] = useState<ThemeMode>(() => (localStorage.getItem('mindorbit_theme') as ThemeMode) || 'dark');
  const [subjects, setSubjects] = useState<Subject[]>(() => {
    const saved = localStorage.getItem('mindorbit_syllabus_v2');
    return saved ? JSON.parse(saved) : INITIAL_SYLLABUS;
  });
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('mindorbit_notes');
    return saved ? JSON.parse(saved) : [];
  });
  const [doubts, setDoubts] = useState<Doubt[]>(() => {
    const saved = localStorage.getItem('mindorbit_doubts');
    return saved ? JSON.parse(saved) : [];
  });
  const [reminders, setReminders] = useState<Reminder[]>(() => {
    const saved = localStorage.getItem('mindorbit_reminders');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('mindorbit_syllabus_v2', JSON.stringify(subjects));
    localStorage.setItem('mindorbit_notes', JSON.stringify(notes));
    localStorage.setItem('mindorbit_doubts', JSON.stringify(doubts));
    localStorage.setItem('mindorbit_reminders', JSON.stringify(reminders));
    localStorage.setItem('mindorbit_theme', theme);
    document.body.className = theme;
  }, [subjects, notes, doubts, reminders, theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const handleToggleTopic = (subjectId: string, topicId: string) => {
    setSubjects(prev => prev.map(s => s.id === subjectId ? { ...s, topics: s.topics.map(t => t.id === topicId ? { ...t, completed: !t.completed } : t) } : s));
  };

  const handleAddNote = (newNoteData: Omit<Note, 'id' | 'timestamp'>) => {
    setNotes(prev => [{ ...newNoteData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now() }, ...prev]);
  };

  const handleDeleteNote = (id: string) => setNotes(prev => prev.filter(n => n.id !== id));

  const handleSaveDoubt = (doubtData: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => {
    setDoubts(prev => [{ ...doubtData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now(), resolved: false }, ...prev]);
  };

  const handleAddReminder = (task: string, time: string, type: Reminder['type'] = 'Study') => {
    setReminders(prev => [...prev, { id: Math.random().toString(36).substr(2, 9), task, time, completed: false, type }]);
  };

  const toggleReminder = (id: string) => setReminders(prev => prev.map(r => r.id === id ? { ...r, completed: !r.completed } : r));
  const deleteReminder = (id: string) => setReminders(prev => prev.filter(r => r.id !== id));

  const renderContent = () => {
    const isDark = theme === 'dark';
    switch (activeMode) {
      case APP_MODES.DASHBOARD:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} />;
      case APP_MODES.CHAT:
        return <AITutor notes={notes} onSaveDoubt={handleSaveDoubt} theme={theme} />;
      case APP_MODES.PLANNER:
        return <StudyPlanner reminders={reminders} onAddReminder={handleAddReminder} onToggleReminder={toggleReminder} onDeleteReminder={deleteReminder} theme={theme} />;
      case APP_MODES.SYLLABUS:
        return <SyllabusTracker subjects={subjects} onToggleTopic={handleToggleTopic} theme={theme} />;
      case APP_MODES.NOTES:
        return <NotesManager notes={notes} onAddNote={handleAddNote} onDeleteNote={handleDeleteNote} />;
      case APP_MODES.DEEP_DIVE:
        return <DeepDive theme={theme} />;
      case APP_MODES.DOUBTS:
        return (
          <div className="space-y-10 animate-fadeIn">
            <header>
              <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>The <span className="text-[#4CC9F0]">Vault</span></h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Permanently archived intelligence blocks.</p>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {doubts.map(doubt => (
                <div key={doubt.id} className={`p-10 rounded-[3rem] border transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
                  <div className="flex justify-between items-center mb-8">
                    <span className="text-[10px] px-4 py-1.5 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-full font-black uppercase tracking-widest border border-[#4CC9F0]/20">Doubt #{doubt.id.substring(0,3)}</span>
                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{doubt.subject}</span>
                  </div>
                  <p className={`text-xl font-bold mb-8 leading-tight ${isDark ? 'text-white' : 'text-slate-950'}`}>{doubt.question}</p>
                  <div className={`p-8 rounded-[2rem] italic text-sm leading-relaxed border ${isDark ? 'bg-[#0D1B2A] border-slate-800 text-slate-400' : 'bg-slate-50 border-slate-100 text-slate-600'}`}>
                    {doubt.answer}
                  </div>
                </div>
              ))}
              {doubts.length === 0 && <div className="col-span-full py-32 text-center opacity-30 italic font-black text-2xl tracking-tighter">VAULT_EMPTY.SYS</div>}
            </div>
          </div>
        );
      default:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} />;
    }
  };

  if (activeMode === APP_MODES.LANDING) {
    return <LandingPage onStart={() => setActiveMode(APP_MODES.DASHBOARD)} theme={theme} />;
  }

  return (
    <div className={`flex min-h-screen transition-colors duration-500 ${theme === 'dark' ? 'bg-[#0D1B2A]' : 'bg-slate-50'}`}>
      <Sidebar activeMode={activeMode} setActiveMode={setActiveMode} theme={theme} toggleTheme={toggleTheme} />
      <main className="flex-1 ml-72 p-16 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Message, Note, Doubt, ThemeMode, StudyMode } from '../types';
import { getGeminiResponse } from '../services/geminiService';

interface AITutorProps {
  notes: Note[];
  onSaveDoubt: (doubt: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => void;
  theme: ThemeMode;
}

const AITutor: React.FC<AITutorProps> = ({ notes, onSaveDoubt, theme }) => {
  const isDark = theme === 'dark';
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      parts: [{ text: "Orbit active. Systems running at 100%. Main tumhara personal AI tutor hoon. Poocho, kya seekhna hai aaj? You can switch modes for different styles of explanations." }],
      timestamp: Date.now(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedNoteId, setSelectedNoteId] = useState<string | null>(null);
  const [studyMode, setStudyMode] = useState<StudyMode>('Normal');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isLoading]);

  const handleSend = async () => {
    if ((!input.trim() && !selectedNoteId) || isLoading) return;

    const currentInput = input;
    setInput('');

    let parts: any[] = [{ text: currentInput }];
    if (selectedNoteId) {
      const note = notes.find(n => n.id === selectedNoteId);
      if (note) parts.push({ text: `\n\n[CONTEXT FROM NOTE: ${note.title}]\n${note.content}` });
    }

    const newUserMsg: Message = { role: 'user', parts: [{ text: currentInput }], timestamp: Date.now(), mode: studyMode };
    setMessages(prev => [...prev, newUserMsg]);
    setIsLoading(true);

    const responseText = await getGeminiResponse([...messages, { role: 'user', parts, timestamp: Date.now() }], studyMode);

    setMessages(prev => [...prev, { role: 'model', parts: [{ text: responseText }], timestamp: Date.now() }]);
    setIsLoading(false);
    setSelectedNoteId(null);
  };

  return (
    <div className={`flex flex-col h-[calc(100vh-8rem)] rounded-[3.5rem] shadow-2xl border overflow-hidden transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-200'}`}>
      {/* AI Header */}
      <div className={`p-6 flex flex-wrap justify-between items-center border-b gap-4 ${isDark ? 'border-slate-800' : 'border-slate-100'}`}>
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-[#4CC9F0] rounded-2xl flex items-center justify-center text-[#0D1B2A] text-xl shadow-xl shadow-[#4CC9F0]/20">
            <i className="fa-solid fa-brain-circuit"></i>
          </div>
          <div>
            <h3 className={`font-black tracking-tight text-lg ${isDark ? 'text-white' : 'text-slate-900'}`}>Neural Orbit Assistant</h3>
            <div className="flex items-center gap-3 mt-0.5">
               <span className="text-[9px] font-black uppercase tracking-widest text-[#4CAF50] flex items-center gap-1.5">
                 <span className="w-1.5 h-1.5 bg-[#4CAF50] rounded-full animate-pulse"></span> Core Ready
               </span>
               <span className={`text-[9px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md ${isDark ? 'bg-slate-800 text-slate-400' : 'bg-slate-50 text-slate-500'}`}>
                 Hinglish Supported
               </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className={`flex p-1.5 rounded-2xl border ${isDark ? 'bg-[#0D1B2A] border-slate-700' : 'bg-slate-50 border-slate-200'}`}>
            {(['Normal', 'ELI5', 'Exam-Oriented'] as StudyMode[]).map(m => (
              <button
                key={m}
                onClick={() => setStudyMode(m)}
                className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${studyMode === m ? 'bg-[#4CC9F0] text-[#0D1B2A]' : 'text-slate-500 hover:text-slate-400'}`}
              >
                {m}
              </button>
            ))}
          </div>
          <select 
            className={`text-[10px] font-black uppercase tracking-widest rounded-2xl px-5 py-3.5 outline-none transition-all ${isDark ? 'bg-[#0D1B2A] border-slate-700 text-slate-300' : 'bg-white border-slate-200 text-slate-600 shadow-sm'}`}
            value={selectedNoteId || ''}
            onChange={(e) => setSelectedNoteId(e.target.value || null)}
          >
            <option value="">Neural Context (OFF)</option>
            {notes.map(n => <option key={n.id} value={n.id}>{n.title}</option>)}
          </select>
        </div>
      </div>

      {/* Chat Area */}
      <div ref={scrollRef} className={`flex-1 overflow-y-auto p-10 space-y-10 ${isDark ? 'bg-[#0D1B2A]/20' : 'bg-slate-50/20'}`}>
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[75%] group relative ${msg.role === 'user' ? 'flex flex-col items-end' : 'flex flex-col items-start'}`}>
              <div className={`rounded-[2.5rem] px-8 py-5 shadow-sm transition-all ${
                msg.role === 'user' 
                  ? 'bg-[#4CC9F0] text-[#0D1B2A] rounded-tr-none font-bold text-lg' 
                  : `${isDark ? 'bg-[#1B263B] text-[#E0E1DD] border-slate-800' : 'bg-white text-slate-800 border-slate-100 shadow-xl'} border rounded-tl-none`
              }`}>
                {msg.role === 'model' && (
                  <div className="flex gap-2 mb-3">
                    <span className="w-2 h-2 rounded-full bg-[#4CC9F0]"></span>
                    <span className="w-2 h-2 rounded-full bg-[#4CAF50]"></span>
                  </div>
                )}
                <p className="whitespace-pre-wrap leading-relaxed">{msg.parts[0].text}</p>
              </div>

              {msg.role === 'model' && idx > 0 && (
                <button 
                  // Fix: Construct the required Omit<Doubt, 'id' | 'timestamp' | 'resolved'> object from message history
                  onClick={() => onSaveDoubt({
                    question: messages[idx - 1]?.parts[0]?.text || 'General Question',
                    answer: msg.parts[0]?.text || '',
                    subject: 'General'
                  })}
                  className="mt-3 flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-[#4CC9F0] transition-colors"
                >
                  <i className="fa-solid fa-bookmark"></i> Save to Vault
                </button>
              )}

              <span className={`text-[9px] font-black uppercase tracking-widest mt-2 ${msg.role === 'user' ? 'text-[#4CC9F0]/60' : 'text-slate-600'}`}>
                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • {msg.mode || studyMode}
              </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className={`rounded-full px-8 py-4 border animate-pulse ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
              <div className="flex gap-3">
                <div className="w-2.5 h-2.5 bg-[#4CC9F0] rounded-full animate-bounce"></div>
                <div className="w-2.5 h-2.5 bg-[#4CC9F0] rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-2.5 h-2.5 bg-[#4CC9F0] rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Chat Input */}
      <div className={`p-8 ${isDark ? 'bg-[#1B263B]' : 'bg-white'} border-t ${isDark ? 'border-slate-800' : 'border-slate-100'}`}>
        <div className="relative flex items-center max-w-6xl mx-auto group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Poocho apne sawaal... (Hinglish Supported)"
            className={`w-full rounded-3xl py-6 pl-10 pr-20 focus:ring-4 ring-[#4CC9F0]/10 outline-none transition-all font-bold text-lg ${isDark ? 'bg-[#0D1B2A] border-slate-700 text-white placeholder-slate-700' : 'bg-slate-50 border-slate-200 text-slate-900'}`}
          />
          <div className="absolute right-4 flex items-center gap-2">
            <button className={`p-4 rounded-2xl transition-all ${isDark ? 'text-slate-500 hover:text-[#4CC9F0]' : 'text-slate-300 hover:text-[#4CC9F0]'}`}>
               <i className="fa-solid fa-microphone"></i>
            </button>
            <button
              onClick={handleSend}
              disabled={isLoading || (!input.trim() && !selectedNoteId)}
              className="p-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl hover:scale-105 active:scale-95 transition-all disabled:opacity-50 shadow-2xl shadow-[#4CC9F0]/30"
            >
              <i className="fa-solid fa-paper-plane-top text-xl"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AITutor;

import React, { useState } from 'react';
import { Note } from '../types';

interface NotesManagerProps {
  notes: Note[];
  onAddNote: (note: Omit<Note, 'id' | 'timestamp'>) => void;
  onDeleteNote: (id: string) => void;
}

const NotesManager: React.FC<NotesManagerProps> = ({ notes, onAddNote, onDeleteNote }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [newNoteTitle, setNewNoteTitle] = useState('');
  const [newNoteContent, setNewNoteContent] = useState('');

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const content = event.target?.result as string;
        // Fix: Added missing required 'tags' property to match Note interface
        onAddNote({
          title: file.name,
          content: content,
          type: 'text', // For simplicity treating as text/raw content
          tags: []
        });
      };
      reader.readAsText(file);
    }
  };

  const handleManualAdd = () => {
    if (newNoteTitle && newNoteContent) {
      // Fix: Added missing required 'tags' property to match Note interface
      onAddNote({
        title: newNoteTitle,
        content: newNoteContent,
        type: 'text',
        tags: []
      });
      setNewNoteTitle('');
      setNewNoteContent('');
      setIsUploading(false);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <header className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">My Study Notes</h2>
          <p className="text-slate-500">Organize and search through your course materials.</p>
        </div>
        <div className="flex gap-3">
           <label className="bg-white text-slate-700 px-4 py-2 rounded-xl text-sm font-medium border border-slate-200 cursor-pointer hover:bg-slate-50 shadow-sm transition-all flex items-center">
             <i className="fa-solid fa-upload mr-2"></i> Upload File
             <input type="file" className="hidden" onChange={handleFileUpload} accept=".txt,.md,.json" />
           </label>
           <button 
             onClick={() => setIsUploading(true)}
             className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-medium hover:bg-indigo-700 shadow-lg flex items-center"
           >
             <i className="fa-solid fa-plus mr-2"></i> New Note
           </button>
        </div>
      </header>

      {isUploading && (
        <div className="bg-white p-6 rounded-3xl shadow-lg border border-indigo-100 space-y-4 animate-slideDown">
          <h3 className="font-bold text-slate-800">Add New Note</h3>
          <input 
            className="w-full p-3 border border-slate-200 rounded-xl outline-none focus:ring-2 ring-indigo-500"
            placeholder="Note Title (e.g. Bio Lecture 1)"
            value={newNoteTitle}
            onChange={(e) => setNewNoteTitle(e.target.value)}
          />
          <textarea 
            className="w-full p-3 border border-slate-200 rounded-xl h-32 outline-none focus:ring-2 ring-indigo-500"
            placeholder="Paste your notes here..."
            value={newNoteContent}
            onChange={(e) => setNewNoteContent(e.target.value)}
          />
          <div className="flex justify-end gap-3">
            <button onClick={() => setIsUploading(false)} className="px-4 py-2 text-slate-500">Cancel</button>
            <button onClick={handleManualAdd} className="px-6 py-2 bg-indigo-600 text-white rounded-xl font-medium">Save Note</button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {notes.map((note) => (
          <div key={note.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow flex flex-col group">
            <div className="flex justify-between items-start mb-3">
              <div className="bg-indigo-50 text-indigo-600 p-3 rounded-2xl">
                <i className="fa-solid fa-file-lines text-xl"></i>
              </div>
              <button 
                onClick={() => onDeleteNote(note.id)}
                className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
              >
                <i className="fa-solid fa-trash-can"></i>
              </button>
            </div>
            <h4 className="font-bold text-slate-800 mb-2 truncate">{note.title}</h4>
            <p className="text-slate-500 text-sm line-clamp-3 mb-4 flex-1">
              {note.content}
            </p>
            <div className="flex justify-between items-center pt-4 border-t border-slate-50">
              <span className="text-[10px] text-slate-400 font-medium tracking-wider uppercase">
                {new Date(note.timestamp).toLocaleDateString()}
              </span>
              <button className="text-indigo-600 text-xs font-bold hover:underline">View Details</button>
            </div>
          </div>
        ))}
        {notes.length === 0 && !isUploading && (
          <div className="col-span-full py-20 text-center">
            <div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
              <i className="fa-solid fa-note-sticky text-3xl"></i>
            </div>
            <p className="text-slate-400">Your note collection is empty.</p>
            <button onClick={() => setIsUploading(true)} className="text-indigo-600 font-medium mt-2">Create your first note</button>
          </div>
        )}
      </div>
    </div>
  );
};

export default NotesManager;

import { GoogleGenAI, GenerateContentParameters } from "@google/genai";
import { Message, StudyMode } from "../types";

export const getGeminiResponse = async (messages: Message[], mode: StudyMode = 'Normal', systemInstruction?: string) => {
  // Fix: Initialize GoogleGenAI using process.env.API_KEY directly inside the call context
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents = messages.map(msg => ({
    role: msg.role,
    parts: msg.parts
  }));

  let modeInstruction = "";
  if (mode === 'ELI5') {
    modeInstruction = "IMPORTANT: Use the 'Explain Like I'm 5' methodology. Use simple analogies, avoid complex jargon, and use basic Hinglish where helpful.";
  } else if (mode === 'Exam-Oriented') {
    modeInstruction = "IMPORTANT: Be exam-oriented. Focus on marks-weightage, keywords that examiners look for, and provide structured, point-wise answers with common exam questions.";
  }

  const baseInstruction = systemInstruction || `You are MindOrbit, an elite AI student assistant.
    - Support both English and Hinglish (mix of Hindi/English) as per student's comfort.
    - Be encouraging but professional.
    - If notes context is provided, prioritize answering from the notes.
    - Break down complex topics into small, digestible chunks.
    ${modeInstruction}`;

  const params: GenerateContentParameters = {
    model: 'gemini-3-flash-preview',
    contents,
    config: {
      systemInstruction: baseInstruction,
      temperature: 0.8,
    }
  };

  try {
    const response = await ai.models.generateContent(params);
    return response.text || "Main orbit se connect nahi ho pa raha hoon. Please try again.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error: Orbit connection lost. Please check your satellite (internet).";
  }
};

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import AITutor from './components/AITutor';
import SyllabusTracker from './components/SyllabusTracker';
import NotesManager from './components/NotesManager';
import LandingPage from './components/LandingPage';
import StudyPlanner from './components/StudyPlanner';
import DeepDive from './components/DeepDive';
import { Subject, Note, Doubt, Reminder, ThemeMode } from './types';
import { INITIAL_SYLLABUS, APP_MODES } from './constants';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<string>(APP_MODES.LANDING);
  const [theme, setTheme] = useState<ThemeMode>(() => (localStorage.getItem('mindorbit_theme') as ThemeMode) || 'dark');
  const [subjects, setSubjects] = useState<Subject[]>(() => {
    const saved = localStorage.getItem('mindorbit_syllabus_v3');
    return saved ? JSON.parse(saved) : INITIAL_SYLLABUS;
  });
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('mindorbit_notes');
    return saved ? JSON.parse(saved) : [];
  });
  const [doubts, setDoubts] = useState<Doubt[]>(() => {
    const saved = localStorage.getItem('mindorbit_doubts');
    return saved ? JSON.parse(saved) : [];
  });
  const [reminders, setReminders] = useState<Reminder[]>(() => {
    const saved = localStorage.getItem('mindorbit_reminders');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('mindorbit_syllabus_v3', JSON.stringify(subjects));
    localStorage.setItem('mindorbit_notes', JSON.stringify(notes));
    localStorage.setItem('mindorbit_doubts', JSON.stringify(doubts));
    localStorage.setItem('mindorbit_reminders', JSON.stringify(reminders));
    localStorage.setItem('mindorbit_theme', theme);
    document.body.className = theme;
  }, [subjects, notes, doubts, reminders, theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const handleToggleTopic = (subjectId: string, topicId: string) => {
    setSubjects(prev => prev.map(s => s.id === subjectId ? { ...s, topics: s.topics.map(t => t.id === topicId ? { ...t, completed: !t.completed } : t) } : s));
  };

  const handleAddSubject = (name: string, classLevel: string) => {
    const newSubject: Subject = {
      id: `subj-${Math.random().toString(36).substr(2, 5)}`,
      name,
      classLevel,
      topics: [
        { id: `topic-${Math.random()}`, name: 'Introductory Chapter', completed: false, revisionStatus: 'Not Started' }
      ]
    };
    setSubjects(prev => [...prev, newSubject]);
  };

  const handleAddNote = (newNoteData: Omit<Note, 'id' | 'timestamp'>) => {
    setNotes(prev => [{ ...newNoteData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now() }, ...prev]);
  };

  const handleDeleteNote = (id: string) => setNotes(prev => prev.filter(n => n.id !== id));

  const handleSaveDoubt = (doubtData: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => {
    setDoubts(prev => [{ ...doubtData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now(), resolved: false }, ...prev]);
  };

  const handleAddReminder = (task: string, time: string, type: Reminder['type'] = 'Study') => {
    setReminders(prev => [...prev, { id: Math.random().toString(36).substr(2, 9), task, time, completed: false, type }]);
  };

  const toggleReminder = (id: string) => setReminders(prev => prev.map(r => r.id === id ? { ...r, completed: !r.completed } : r));
  const deleteReminder = (id: string) => setReminders(prev => prev.filter(r => r.id !== id));

  const renderContent = () => {
    const isDark = theme === 'dark';
    switch (activeMode) {
      case APP_MODES.DASHBOARD:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} />;
      case APP_MODES.CHAT:
        return <AITutor notes={notes} onSaveDoubt={handleSaveDoubt} theme={theme} />;
      case APP_MODES.PLANNER:
        return <StudyPlanner reminders={reminders} onAddReminder={handleAddReminder} onToggleReminder={toggleReminder} onDeleteReminder={deleteReminder} theme={theme} />;
      case APP_MODES.SYLLABUS:
        return <SyllabusTracker subjects={subjects} onToggleTopic={handleToggleTopic} onAddSubject={handleAddSubject} theme={theme} />;
      case APP_MODES.NOTES:
        return <NotesManager notes={notes} onAddNote={handleAddNote} onDeleteNote={handleDeleteNote} />;
      case APP_MODES.DEEP_DIVE:
        return <DeepDive theme={theme} />;
      case APP_MODES.DOUBTS:
        return (
          <div className="space-y-10 animate-fadeIn">
            <header>
              <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>The <span className="text-[#4CC9F0]">Vault</span></h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Permanently archived intelligence blocks.</p>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {doubts.map(doubt => (
                <div key={doubt.id} className={`p-10 rounded-[3rem] border transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
                  <div className="flex justify-between items-center mb-8">
                    <span className="text-[10px] px-4 py-1.5 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-full font-black uppercase tracking-widest border border-[#4CC9F0]/20">Doubt #{doubt.id.substring(0,3)}</span>
                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{doubt.subject}</span>
                  </div>
                  <p className={`text-xl font-bold mb-8 leading-tight ${isDark ? 'text-white' : 'text-slate-950'}`}>{doubt.question}</p>
                  <div className={`p-8 rounded-[2rem] italic text-sm leading-relaxed border ${isDark ? 'bg-[#0D1B2A] border-slate-800 text-slate-400' : 'bg-slate-50 border-slate-100 text-slate-600'}`}>
                    {doubt.answer}
                  </div>
                </div>
              ))}
              {doubts.length === 0 && <div className="col-span-full py-32 text-center opacity-30 italic font-black text-2xl tracking-tighter">VAULT_EMPTY.SYS</div>}
            </div>
          </div>
        );
      default:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} />;
    }
  };

  if (activeMode === APP_MODES.LANDING) {
    return <LandingPage onStart={() => setActiveMode(APP_MODES.DASHBOARD)} theme={theme} />;
  }

  return (
    <div className={`flex min-h-screen transition-colors duration-500 ${theme === 'dark' ? 'bg-[#0D1B2A]' : 'bg-slate-50'}`}>
      <Sidebar activeMode={activeMode} setActiveMode={setActiveMode} theme={theme} toggleTheme={toggleTheme} />
      <main className="flex-1 ml-72 p-16 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Subject, ThemeMode } from '../types';

interface SyllabusTrackerProps {
  subjects: Subject[];
  onToggleTopic: (subjectId: string, topicId: string) => void;
  onAddSubject: (name: string, classLevel: string) => void;
  theme: ThemeMode;
}

const SyllabusTracker: React.FC<SyllabusTrackerProps> = ({ subjects, onToggleTopic, onAddSubject, theme }) => {
  const isDark = theme === 'dark';
  const [selectedClass, setSelectedClass] = useState<string>('All');

  const classes = ['All', ...Array.from(new Set(subjects.map(s => s.classLevel)))];
  const filteredSubjects = selectedClass === 'All' ? subjects : subjects.filter(s => s.classLevel === selectedClass);

  const handleAddSubjectClick = () => {
    const name = prompt("Enter Subject Name:");
    const classLevel = prompt("Enter Class Level (e.g., Class 10, Class 12):");
    if (name && classLevel) {
      onAddSubject(name, classLevel);
    }
  };

  const getSubjectIcon = (name: string) => {
    const n = name.toLowerCase();
    if (n.includes('math')) return 'fa-function';
    if (n.includes('phys')) return 'fa-atom';
    if (n.includes('comp')) return 'fa-code';
    if (n.includes('bio')) return 'fa-dna';
    if (n.includes('hist')) return 'fa-landmark';
    if (n.includes('chem')) return 'fa-flask';
    return 'fa-book-sparkles';
  };

  return (
    <div className="space-y-10 animate-fadeIn pb-12">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Syllabus <span className="text-[#4CC9F0]">Orbit</span></h2>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Class-wise roadmap to academic excellence.</p>
        </div>
        <div className="flex gap-4">
          <select 
            className={`px-6 py-3 rounded-2xl border font-bold text-xs uppercase tracking-widest outline-none focus:ring-2 ring-[#4CC9F0] ${isDark ? 'bg-[#1B263B] border-slate-700 text-slate-300' : 'bg-white border-slate-200 text-slate-600 shadow-sm'}`}
            value={selectedClass}
            onChange={(e) => setSelectedClass(e.target.value)}
          >
            {classes.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <button 
            onClick={handleAddSubjectClick}
            className="px-6 py-3 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-[#4CC9F0]/20 hover:scale-105 active:scale-95 transition-all"
          >
            <i className="fa-solid fa-plus mr-2"></i> Add Subject
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
        {filteredSubjects.map((subject) => {
          const completedCount = subject.topics.filter(t => t.completed).length;
          const progress = Math.round((completedCount / subject.topics.length) * 100);

          return (
            <div key={subject.id} className={`rounded-[3rem] p-8 border transition-all hover:scale-[1.01] ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-4">
                  <div className="w-14 h-14 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-2xl flex items-center justify-center text-2xl shadow-inner border border-[#4CC9F0]/10">
                    <i className={`fa-solid ${getSubjectIcon(subject.name)}`}></i>
                  </div>
                  <div>
                    <h3 className={`text-xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>{subject.name}</h3>
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{subject.classLevel}</p>
                  </div>
                </div>
                <div className="text-right">
                  <span className="text-3xl font-black text-[#4CC9F0]">{progress}%</span>
                </div>
              </div>

              <div className={`w-full h-3 rounded-full mb-8 overflow-hidden ${isDark ? 'bg-slate-800' : 'bg-slate-100'}`}>
                <div 
                  className="bg-[#4CC9F0] h-full rounded-full transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(76,201,240,0.5)]" 
                  style={{ width: `${progress}%` }}
                ></div>
              </div>

              <div className="space-y-3">
                {subject.topics.map((topic) => (
                  <label 
                    key={topic.id} 
                    className={`flex items-center p-4 rounded-2xl border transition-all cursor-pointer group select-none ${
                      topic.completed 
                        ? (isDark ? 'bg-[#0D1B2A]/50 border-[#4CC9F0]/20' : 'bg-blue-50/50 border-blue-100/50') 
                        : (isDark ? 'bg-slate-800/20 border-slate-800 hover:border-[#4CC9F0]/50' : 'bg-white border-slate-100 hover:border-blue-200')
                    }`}
                  >
                    <div className="relative flex items-center justify-center mr-4">
                       <input
                        type="checkbox"
                        checked={topic.completed}
                        onChange={() => onToggleTopic(subject.id, topic.id)}
                        className="peer w-6 h-6 rounded-lg text-[#4CC9F0] focus:ring-[#4CC9F0] border-slate-300 cursor-pointer transition-all"
                      />
                    </div>
                    <div className="flex-1">
