             <div className="absolute inset-4 rounded-full border border-[#4CC9F0]/5 border-dashed"></div>

             <svg className="absolute w-full h-full -rotate-90">
              <circle cx="128" cy="128" r="100" stroke={isDark ? '#0D1B2A' : '#f8fafc'} strokeWidth="16" fill="none" />
