import React, { useState, useRef, useEffect } from 'react';
import { Message, Note, Doubt, ThemeMode, StudyMode } from '../types';
import { getGeminiResponse, cleanAIResponse } from '../services/geminiService';

interface AITutorProps {
  notes: Note[];
  onSaveDoubt: (doubt: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => void;
  theme: ThemeMode;
}

const AITutor: React.FC<AITutorProps> = ({ notes, onSaveDoubt, theme }) => {
  const isDark = theme === 'dark';
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      parts: [{ text: "Orbiting... Main tumhara personal AI tutor hoon. Poocho, kya seekhna hai aaj? You can switch modes for different styles of explanations." }],
      timestamp: Date.now(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedNoteId, setSelectedNoteId] = useState<string | null>(null);
  const [studyMode, setStudyMode] = useState<StudyMode>('Normal');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isLoading]);

  const handleSend = async () => {
    if ((!input.trim() && !selectedNoteId) || isLoading) return;

    const currentInput = input;
    setInput('');

    let parts: any[] = [{ text: currentInput }];
    if (selectedNoteId) {
      const note = notes.find(n => n.id === selectedNoteId);
      if (note) parts.push({ text: `\n\n[CONTEXT FROM NOTE: ${note.title}]\n${note.content}` });
    }

    const newUserMsg: Message = { role: 'user', parts: [{ text: currentInput }], timestamp: Date.now(), mode: studyMode };
    setMessages(prev => [...prev, newUserMsg]);
    setIsLoading(true);

    const responseText = await getGeminiResponse([...messages, { role: 'user', parts, timestamp: Date.now() }], studyMode);

    setMessages(prev => [...prev, { role: 'model', parts: [{ text: responseText }], timestamp: Date.now() }]);
    setIsLoading(false);
    setSelectedNoteId(null);
  };

  return (
    <div className={`flex flex-col h-[calc(100vh-8rem)] rounded-[3.5rem] overflow-hidden transition-all shadow-2xl border ${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white border-slate-100 shadow-slate-200/50'}`}>
      {/* AI Header */}
      <div className={`p-8 flex flex-wrap justify-between items-center border-b gap-4 ${isDark ? 'border-slate-800' : 'border-slate-50'}`}>
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 bg-[#4CC9F0] rounded-3xl flex items-center justify-center text-[#0D1B2A] text-2xl shadow-xl shadow-[#4CC9F0]/30 animate-pulse-slow">
            <i className="fa-solid fa-sparkles"></i>
          </div>
          <div>
            <h3 className={`font-black tracking-tight text-xl ${isDark ? 'text-white' : 'text-slate-900'}`}>Orbit AI</h3>
            <p className="text-[10px] font-extrabold uppercase tracking-[0.2em] text-[#4CAF50]">Neural Core Active</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className={`flex p-1.5 rounded-3xl border ${isDark ? 'bg-slate-900 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
            {(['Normal', 'ELI5', 'Exam-Oriented'] as StudyMode[]).map(m => (
              <button
                key={m}
                onClick={() => setStudyMode(m)}
                className={`px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${studyMode === m ? 'bg-[#4CC9F0] text-[#0D1B2A] shadow-lg shadow-[#4CC9F0]/20' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {m}
              </button>
            ))}
          </div>
          <select 
            className={`text-[10px] font-black uppercase tracking-widest rounded-3xl px-6 py-4 outline-none transition-all ${isDark ? 'bg-slate-900 border-slate-700 text-slate-300' : 'bg-white border-slate-100 text-slate-600 shadow-sm'}`}
            value={selectedNoteId || ''}
            onChange={(e) => setSelectedNoteId(e.target.value || null)}
          >
            <option value="">Neural Context (Off)</option>
            {notes.map(n => <option key={n.id} value={n.id}>{n.title}</option>)}
          </select>
        </div>
      </div>

      {/* Chat Area */}
      <div ref={scrollRef} className={`flex-1 overflow-y-auto p-12 space-y-12 custom-scrollbar ${isDark ? 'bg-slate-900/20' : 'bg-slate-50/20'}`}>
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`message-bubble rounded-[2.5rem] px-8 py-6 shadow-sm transition-all ${
                msg.role === 'user' 
                  ? 'bg-[#4CC9F0] text-[#0D1B2A] rounded-tr-none font-bold text-lg' 
                  : `${isDark ? 'bg-[#1B263B] text-[#E0E1DD] border-slate-800' : 'bg-white text-slate-700 border-slate-100 shadow-xl shadow-slate-200/40'} border rounded-tl-none`
              }`}>
                {msg.role === 'model' && (
                  <div className="flex gap-2 mb-4">
                    <div className="w-2.5 h-2.5 rounded-full bg-[#4CC9F0]"></div>
                    <div className="w-2.5 h-2.5 rounded-full bg-[#4CAF50]"></div>
                  </div>
                )}
                <p className="whitespace-pre-wrap leading-[1.8] font-medium tracking-tight">
                  {msg.role === 'model' ? cleanAIResponse(msg.parts[0].text || "") : msg.parts[0].text}
                </p>
              </div>

              <div className="flex items-center gap-4 mt-3 px-2">
                <span className={`text-[10px] font-black uppercase tracking-widest ${msg.role === 'user' ? 'text-[#4CC9F0]' : 'text-slate-500'}`}>
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
                {msg.role === 'model' && idx > 0 && (
                  <button 
                    onClick={() => onSaveDoubt({
                      question: messages[idx - 1]?.parts[0]?.text || 'General Question',
                      answer: cleanAIResponse(msg.parts[0]?.text || ""),
                      subject: 'General'
                    })}
                    className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-[#4CC9F0] transition-colors"
                  >
                    <i className="fa-solid fa-bookmark"></i> Save to Doubt Vault
                  </button>
                )}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
             <div className="bg-[#4CC9F0]/10 border border-[#4CC9F0]/20 rounded-full px-8 py-4 flex items-center gap-3">
               <div className="w-2 h-2 bg-[#4CC9F0] rounded-full animate-bounce"></div>
               <div className="w-2 h-2 bg-[#4CC9F0] rounded-full animate-bounce [animation-delay:-0.15s]"></div>
               <div className="w-2 h-2 bg-[#4CC9F0] rounded-full animate-bounce [animation-delay:-0.3s]"></div>
               <span className="text-[10px] font-black uppercase tracking-widest text-[#4CC9F0] ml-2">Orbiting Data...</span>
             </div>
          </div>
        )}
      </div>

      {/* Chat Input */}
      <div className={`p-8 border-t ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-50'}`}>
        <div className="max-w-4xl mx-auto relative flex items-center group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask anything in English or Hinglish..."
            className={`w-full rounded-[2.5rem] py-6 pl-10 pr-20 outline-none focus:ring-4 ring-[#4CC9F0]/10 transition-all font-bold text-lg ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-slate-50 border-slate-100 text-slate-900 placeholder-slate-400'}`}
          />
          <div className="absolute right-4 flex items-center gap-2">
            <button className={`p-4 rounded-3xl transition-all ${isDark ? 'text-slate-600 hover:text-[#4CC9F0]' : 'text-slate-300 hover:text-[#4CC9F0]'}`}>
               <i className="fa-solid fa-microphone-lines text-xl"></i>
            </button>
            <button
              onClick={handleSend}
              disabled={isLoading || (!input.trim() && !selectedNoteId)}
              className="p-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl hover:scale-110 active:scale-90 transition-all disabled:opacity-30 shadow-2xl shadow-[#4CC9F0]/30"
            >
              <i className="fa-solid fa-paper-plane text-xl"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

