import React, { useState, useEffect } from 'react';
import { Reminder, ThemeMode } from '../types';

interface StudyPlannerProps {
  reminders: Reminder[];
  onAddReminder: (task: string, time: string, type: Reminder['type']) => void;
  onToggleReminder: (id: string) => void;
  onDeleteReminder: (id: string) => void;
  theme: ThemeMode;
}

const StudyPlanner: React.FC<StudyPlannerProps> = ({ reminders, onAddReminder, onToggleReminder, onDeleteReminder, theme }) => {
  const isDark = theme === 'dark';
  const [timeLeft, setTimeLeft] = useState(25 * 60);
  const [isActive, setIsActive] = useState(false);
  const [mode, setMode] = useState<'Work' | 'Break'>('Work');
  const [showAddForm, setShowAddForm] = useState(false);
  const [newTaskName, setNewTaskName] = useState('');
  const [newTaskTime, setNewTaskTime] = useState('');

  useEffect(() => {
    let interval: any = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      try {
        const audio = new Audio('https://actions.google.com/sounds/v1/alarms/beep_short.ogg');
        audio.play();
      } catch (e) { console.warn("Audio blocked"); }
      if (mode === 'Work') {
        setMode('Break');
        setTimeLeft(5 * 60);
      } else {
        setMode('Work');
        setTimeLeft(25 * 60);
      }
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode]);

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const handleCreateTarget = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTaskName && newTaskTime) {
      onAddReminder(newTaskName, newTaskTime, 'Study');
      setNewTaskName('');
      setNewTaskTime('');
      setShowAddForm(false);
    }
  };

  return (
    <div className="space-y-12 animate-fadeIn pb-20">
      <header>
        <h2 className={`text-3xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Tactical <span className="text-[#4CC9F0]">Planner</span></h2>
        <p className="text-slate-500 font-bold text-sm mt-1">Strategic time mapping for your study session.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        {/* Advanced Tactical Radar Timer */}
        <div className="lg:col-span-4 card-premium p-10 rounded-[3.5rem] flex flex-col items-center justify-between group">
          <div className="w-full flex justify-between items-center mb-10">
            <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border ${mode === 'Work' ? 'bg-[#4CC9F0]/10 text-[#4CC9F0] border-[#4CC9F0]/20' : 'bg-[#4CAF50]/10 text-[#4CAF50] border-[#4CAF50]/20'}`}>
               {mode} Cycle
            </div>
            <div className="flex gap-1.5">
               <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-[#4CAF50] animate-pulse' : 'bg-slate-700'}`}></div>
               <div className="w-1.5 h-1.5 rounded-full bg-slate-700"></div>
            </div>
          </div>

          <div className="relative w-64 h-64 flex items-center justify-center">
             <div className="absolute inset-0 rounded-full border border-slate-800/20 border-dashed animate-orbit opacity-20"></div>
             <svg className="absolute w-full h-full -rotate-90">
              <circle cx="128" cy="128" r="105" stroke={isDark ? '#1B263B' : '#f1f5f9'} strokeWidth="18" fill="none" />
              <circle 
                cx="128" cy="128" r="105" 
                stroke={mode === 'Work' ? '#4CC9F0' : '#4CAF50'} strokeWidth="18" fill="none"
                strokeDasharray="660"
                strokeDashoffset={660 - (660 * timeLeft) / (mode === 'Work' ? 25 * 60 : 5 * 60)}
                className="transition-all duration-1000 ease-linear"
                strokeLinecap="round"
              />
            </svg>
            <div className="text-center z-10">
              <p className={`text-6xl font-black ${isDark ? 'text-white' : 'text-slate-900'} tracking-tighter`}>{formatTime(timeLeft)}</p>
              <p className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] mt-2">Remaining</p>
            </div>
          </div>

          <div className="flex gap-4 mt-12 w-full">
            <button 
              onClick={() => setIsActive(!isActive)}
              className="flex-1 py-5 rounded-3xl bg-[#4CC9F0] text-[#0D1B2A] font-black uppercase tracking-widest text-[10px] shadow-2xl shadow-[#4CC9F0]/30 hover:scale-[1.03] transition-all"
            >
              {isActive ? <><i className="fa-solid fa-pause mr-2"></i> Pause</> : <><i className="fa-solid fa-play mr-2"></i> Initiate</>}
            </button>
            <button 
              onClick={() => { setIsActive(false); setTimeLeft(mode === 'Work' ? 25 * 60 : 5 * 60); }}
              className={`px-6 rounded-3xl border transition-all ${isDark ? 'border-slate-800 text-slate-500 hover:bg-slate-800' : 'border-slate-100 text-slate-300 hover:bg-slate-50'}`}
            >
              <i className="fa-solid fa-rotate-left"></i>
            </button>
          </div>
        </div>

        {/* Mission Objectives Board */}
        <div className="lg:col-span-8 card-premium p-12 rounded-[3.5rem]">
          <div className="flex justify-between items-center mb-10">
            <div className="flex items-center gap-4">
               <div className="w-12 h-12 bg-[#4CC9F0]/10 rounded-2xl flex items-center justify-center text-[#4CC9F0] text-xl">
                 <i className="fa-solid fa-crosshairs"></i>
               </div>
               <h3 className={`text-xl font-black ${isDark ? 'text-white' : 'text-slate-800'}`}>Target Matrix</h3>
            </div>
            <button 
              onClick={() => setShowAddForm(!showAddForm)}
              className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${showAddForm ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-[#4CC9F0]/10 text-[#4CC9F0] border-[#4CC9F0]/20 hover:bg-[#4CC9F0] hover:text-[#0D1B2A]'}`}
            >
              {showAddForm ? 'Cancel' : <><i className="fa-solid fa-plus mr-2"></i> New Target</>}
            </button>
          </div>

          {showAddForm && (
            <form onSubmit={handleCreateTarget} className={`p-8 rounded-[2.5rem] border mb-10 animate-slideDown ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <input 
                  autoFocus
                  className={`px-6 py-4 rounded-2xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-white border-slate-100 text-slate-900 placeholder-slate-400'}`}
                  placeholder="Target Objective..."
                  value={newTaskName}
                  onChange={(e) => setNewTaskName(e.target.value)}
                />
                <input 
                  className={`px-6 py-4 rounded-2xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-white border-slate-100 text-slate-900 placeholder-slate-400'}`}
                  placeholder="Time (e.g., 5:00 PM)"
                  value={newTaskTime}
                  onChange={(e) => setNewTaskTime(e.target.value)}
                />
              </div>
              <button type="submit" className="w-full py-4 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl shadow-[#4CC9F0]/10">
                Confirm Deployment
              </button>
            </form>
          )}

          <div className="space-y-4">
            {reminders.map(rem => (
              <div key={rem.id} className={`p-6 rounded-[2rem] border flex items-center gap-8 transition-all group ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 hover:shadow-lg hover:shadow-slate-100'}`}>
                <button 
                  onClick={() => onToggleReminder(rem.id)}
                  className={`w-12 h-12 rounded-2xl flex items-center justify-center border-2 transition-all ${rem.completed ? 'bg-[#4CAF50] border-[#4CAF50] text-[#0D1B2A]' : 'border-slate-700 hover:border-[#4CC9F0] text-transparent'}`}
                >
                  <i className="fa-solid fa-check text-sm"></i>
                </button>
                <div className="flex-1">
                  <p className={`text-xl font-bold tracking-tight ${rem.completed ? 'line-through opacity-20' : isDark ? 'text-white' : 'text-slate-900'}`}>{rem.task}</p>
                  <div className="flex items-center gap-4 mt-2">
                    <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest flex items-center gap-2">
                      <i className="fa-solid fa-clock-three text-[#4CC9F0]"></i> {rem.time}
                    </span>
                    <span className={`text-[8px] px-3 py-1 rounded-full font-black uppercase tracking-widest ${rem.completed ? 'bg-green-500/10 text-green-500' : 'bg-[#4CC9F0]/10 text-[#4CC9F0]'}`}>
                      {rem.completed ? 'Mission Complete' : 'In Flight'}
                    </span>
                  </div>
                </div>
                <button onClick={() => onDeleteReminder(rem.id)} className="w-12 h-12 rounded-2xl bg-red-500/5 text-red-500 opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center hover:bg-red-500 hover:text-white">
                  <i className="fa-solid fa-trash text-sm"></i>
                </button>
              </div>
            ))}
            {reminders.length === 0 && !showAddForm && (
              <div className="py-24 text-center border-2 border-dashed border-slate-800/20 rounded-[3rem]">
                <div className="w-20 h-20 bg-slate-800/10 text-slate-500 rounded-3xl flex items-center justify-center mx-auto mb-8 text-3xl">
                  <i className="fa-solid fa-map-marked-alt"></i>
                </div>
                <h4 className={`text-2xl font-black ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>Clear Orbit.</h4>
                <p className="text-slate-600 font-bold text-sm mt-2">Add your first target objective to start tracking.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

