import React, { useState } from 'react';
import { Subject, ThemeMode } from '../types';

interface SyllabusTrackerProps {
  subjects: Subject[];
  onToggleTopic: (subjectId: string, topicId: string) => void;
  onAddSubject: (name: string, classLevel: string) => void;
  theme: ThemeMode;
}

const SyllabusTracker: React.FC<SyllabusTrackerProps> = ({ subjects, onToggleTopic, onAddSubject, theme }) => {
  const isDark = theme === 'dark';
  const [selectedClass, setSelectedClass] = useState<string>('All');

  const classes = ['All', ...Array.from(new Set(subjects.map(s => s.classLevel)))];
  const filteredSubjects = selectedClass === 'All' ? subjects : subjects.filter(s => s.classLevel === selectedClass);

  const handleAddSubjectClick = () => {
    const name = prompt("Enter Subject Name:");
    const classLevel = prompt("Enter Class Level (e.g., Class 10, Class 12):");
    if (name && classLevel) {
      onAddSubject(name, classLevel);
    }
  };

  const getSubjectIcon = (name: string) => {
    const n = name.toLowerCase();
    if (n.includes('math')) return 'fa-function';
    if (n.includes('phys')) return 'fa-atom';
    if (n.includes('comp')) return 'fa-code';
    if (n.includes('bio')) return 'fa-dna';
    if (n.includes('hist')) return 'fa-landmark';
    if (n.includes('chem')) return 'fa-flask';
    return 'fa-book-sparkles';
  };

  return (
    <div className="space-y-12 animate-fadeIn pb-24">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className={`text-3xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Syllabus <span className="text-[#4CC9F0]">Orbit</span></h2>
          <p className="text-slate-500 font-bold text-sm mt-1">Strategic roadmap for academic mastery.</p>
        </div>
        <div className="flex gap-4">
          <select 
            className={`px-6 py-3.5 rounded-3xl border font-bold text-xs uppercase tracking-widest outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-900 border-slate-800 text-slate-400' : 'bg-white border-slate-100 text-slate-600 shadow-sm shadow-slate-200/50'}`}
            value={selectedClass}
            onChange={(e) => setSelectedClass(e.target.value)}
          >
            {classes.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <button 
            onClick={handleAddSubjectClick}
            className="px-8 py-3.5 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl font-black text-[10px] uppercase tracking-widest shadow-2xl shadow-[#4CC9F0]/30 hover:scale-105 transition-all"
          >
            <i className="fa-solid fa-plus mr-2"></i> New Subject
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-10">
        {filteredSubjects.map((subject) => {
          const completedCount = subject.topics.filter(t => t.completed).length;
          const progress = Math.round((completedCount / subject.topics.length) * 100);

          return (
            <div key={subject.id} className="card-premium rounded-[3.5rem] p-10 group">
              <div className="flex justify-between items-start mb-8">
                <div className="flex items-center gap-6">
                  <div className="w-16 h-16 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-3xl flex items-center justify-center text-3xl shadow-inner border border-[#4CC9F0]/10 transition-transform group-hover:rotate-6">
                    <i className={`fa-solid ${getSubjectIcon(subject.name)}`}></i>
                  </div>
                  <div>
                    <h3 className={`text-2xl font-black tracking-tighter ${isDark ? 'text-white' : 'text-slate-900'}`}>{subject.name}</h3>
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mt-1">{subject.classLevel}</p>
                  </div>
                </div>
                <div className="text-right">
                  <span className="text-4xl font-black text-[#4CC9F0]">{progress}%</span>
                </div>
              </div>

              <div className={`w-full h-2.5 rounded-full mb-10 overflow-hidden ${isDark ? 'bg-slate-800' : 'bg-slate-50'}`}>
                <div 
                  className="bg-[#4CC9F0] h-full rounded-full transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(76,201,240,0.4)]" 
                  style={{ width: `${progress}%` }}
                ></div>
              </div>

              <div className="space-y-4">
                {subject.topics.map((topic) => (
                  <label 
                    key={topic.id} 
                    className={`flex items-center p-5 rounded-[2rem] border transition-all cursor-pointer group/item select-none ${
                      topic.completed 
                        ? (isDark ? 'bg-slate-900/50 border-[#4CC9F0]/20' : 'bg-blue-50/30 border-blue-100/30') 
                        : (isDark ? 'bg-slate-900/10 border-slate-800 hover:border-[#4CC9F0]/40' : 'bg-white border-slate-50 hover:border-blue-200/50')
                    }`}
                  >
                    <div className="relative flex items-center justify-center mr-5">
                       <input
                        type="checkbox"
                        checked={topic.completed}
                        onChange={() => onToggleTopic(subject.id, topic.id)}
                        className="peer w-6 h-6 rounded-xl text-[#4CC9F0] focus:ring-[#4CC9F0] border-slate-300 cursor-pointer transition-all"
                      />
                    </div>
                    <div className="flex-1">
                      <span className={`text-lg font-bold tracking-tight ${topic.completed ? (isDark ? 'text-slate-600 line-through' : 'text-slate-400 line-through') : (isDark ? 'text-slate-300' : 'text-slate-700')}`}>
                        {topic.name}
                      </span>
                      <div className="flex gap-2 mt-2">
                        <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-lg ${topic.revisionStatus === 'Mastered' ? 'bg-[#4CAF50]/10 text-[#4CAF50]' : topic.revisionStatus === 'Partial' ? 'bg-amber-500/10 text-amber-500' : 'bg-slate-500/10 text-slate-500'}`}>
                          {topic.revisionStatus}
                        </span>
                      </div>
                    </div>
                  </label>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default SyllabusTracker;

import React, { useState } from 'react';
import { ThemeMode, TopicStudy } from '../types';
import { getGeminiResponse, cleanAIResponse } from '../services/geminiService';

interface DeepDiveProps {
  theme: ThemeMode;
}

const DeepDive: React.FC<DeepDiveProps> = ({ theme }) => {
  const isDark = theme === 'dark';
  const [query, setQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<TopicStudy | null>(null);

  const handleDeepDive = async () => {
    if (!query.trim() || isLoading) return;
    setIsLoading(true);

    const messages = [{
      role: 'user' as const,
      parts: [{ text: `Provide a comprehensive, high-quality, step-by-step master guide for the topic: "${query}". Include definition, core concepts, key formulas (if any), 3 real-world examples, and a summary. Structure it perfectly for a student.` }],
      timestamp: Date.now()
    }];

    const content = await getGeminiResponse(messages, 'Normal');
    setResult({
      topicName: query,
      content: cleanAIResponse(content),
      timestamp: Date.now()
    });
    setIsLoading(false);
  };

  return (
    <div className="space-y-12 animate-fadeIn pb-24 max-w-5xl mx-auto">
      <header className="text-center mb-16">
        <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Deep <span className="text-[#4CC9F0]">Dive</span></h2>
        <p className="text-slate-500 font-bold text-sm mt-2">Instant context generation for any academic topic.</p>
      </header>

      <div className={`p-12 rounded-[4rem] card-premium transition-all`}>
        <div className="max-w-3xl mx-auto space-y-8">
          <p className={`text-center font-bold text-lg ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>What topic would you like to master today?</p>
          <div className="relative flex items-center">
            <input 
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleDeepDive()}
              placeholder="e.g., Photosynthesis, Laws of Motion, Python Lists..."
              className={`w-full rounded-[2.5rem] py-8 pl-10 pr-24 font-bold text-xl outline-none focus:ring-8 ring-[#4CC9F0]/5 transition-all ${isDark ? 'bg-slate-900 border-slate-800 text-white placeholder-slate-700' : 'bg-slate-50 border-slate-100 text-slate-900 placeholder-slate-400'}`}
            />
            <button 
              onClick={handleDeepDive}
              disabled={isLoading || !query.trim()}
              className="absolute right-4 p-6 bg-[#4CC9F0] text-[#0D1B2A] rounded-[2rem] hover:scale-105 active:scale-90 transition-all disabled:opacity-30 shadow-2xl shadow-[#4CC9F0]/30"
            >
              {isLoading ? <i className="fa-solid fa-circle-notch animate-spin text-2xl"></i> : <i className="fa-solid fa-radar text-2xl"></i>}
            </button>
          </div>
        </div>
      </div>

      {result && (
        <div className={`p-12 md:p-16 rounded-[4rem] card-premium animate-slideUp transition-all`}>
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-12 pb-10 border-b border-slate-800/20">
            <div>
              <p className="text-[10px] font-black uppercase tracking-[0.3em] text-[#4CC9F0] mb-3">Topic Master Guide</p>
              <h3 className={`text-4xl font-black tracking-tighter ${isDark ? 'text-white' : 'text-slate-900'}`}>{result.topicName}</h3>
            </div>
            <button className="flex items-center gap-3 px-8 py-4 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-3xl text-xs font-black uppercase tracking-widest border border-[#4CC9F0]/20 hover:bg-[#4CC9F0] hover:text-[#0D1B2A] transition-all">
              <i className="fa-solid fa-cloud-arrow-down text-lg"></i> Archive to Library
            </button>
          </div>
          <div className={`prose prose-lg max-w-none whitespace-pre-wrap leading-[2] font-medium tracking-tight ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>
            {result.content}
          </div>
        </div>
      )}

      {!result && !isLoading && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 pt-8">
          {['Quantum Entanglement', 'World War I', 'Calculus Integrals'].map(suggestion => (
            <button 
              key={suggestion}
              onClick={() => { setQuery(suggestion); }}
              className={`p-10 rounded-[3rem] card-premium text-left group transition-all`}
            >
              <p className="text-[10px] font-black uppercase tracking-widest text-[#4CAF50] mb-4">Mastery Target</p>
              <p className={`text-xl font-bold tracking-tight transition-all ${isDark ? 'text-slate-300 group-hover:text-[#4CC9F0]' : 'text-slate-700 group-hover:text-blue-600'}`}>{suggestion}</p>
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

