import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import AITutor from './components/AITutor';
import SyllabusTracker from './components/SyllabusTracker';
import NotesManager from './components/NotesManager';
import LandingPage from './components/LandingPage';
import StudyPlanner from './components/StudyPlanner';
import DeepDive from './components/DeepDive';
import { Subject, Note, Doubt, Reminder, ThemeMode, Badge, Message } from './types';
import { INITIAL_SYLLABUS, INITIAL_BADGES, INITIAL_CHAT_MESSAGES, APP_MODES } from './constants';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<string>(APP_MODES.LANDING);
  const [theme, setTheme] = useState<ThemeMode>(() => (localStorage.getItem('mindorbit_theme') as ThemeMode) || 'dark');

  const [subjects, setSubjects] = useState<Subject[]>(() => {
    const saved = localStorage.getItem('mindorbit_syllabus_v3');
    return saved ? JSON.parse(saved) : INITIAL_SYLLABUS;
  });
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('mindorbit_notes');
    return saved ? JSON.parse(saved) : [];
  });
  const [doubts, setDoubts] = useState<Doubt[]>(() => {
    const saved = localStorage.getItem('mindorbit_doubts');
    return saved ? JSON.parse(saved) : [];
  });
  const [reminders, setReminders] = useState<Reminder[]>(() => {
    const saved = localStorage.getItem('mindorbit_reminders');
    return saved ? JSON.parse(saved) : [];
  });
  const [badges, setBadges] = useState<Badge[]>(() => {
    const saved = localStorage.getItem('mindorbit_badges');
    return saved ? JSON.parse(saved) : INITIAL_BADGES;
  });
  const [chatHistory, setChatHistory] = useState<Message[]>(() => {
    const saved = localStorage.getItem('mindorbit_chat_v1');
    return saved ? JSON.parse(saved) : INITIAL_CHAT_MESSAGES;
  });

  useEffect(() => {
    if (activeMode !== APP_MODES.LANDING) {
      localStorage.setItem('mindorbit_syllabus_v3', JSON.stringify(subjects));
      localStorage.setItem('mindorbit_notes', JSON.stringify(notes));
      localStorage.setItem('mindorbit_doubts', JSON.stringify(doubts));
      localStorage.setItem('mindorbit_reminders', JSON.stringify(reminders));
      localStorage.setItem('mindorbit_badges', JSON.stringify(badges));
      localStorage.setItem('mindorbit_chat_v1', JSON.stringify(chatHistory));
      localStorage.setItem('mindorbit_theme', theme);
    }
    document.body.className = theme;
  }, [subjects, notes, doubts, reminders, badges, chatHistory, theme, activeMode]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const handleAuthSuccess = useCallback(() => {
    // FACTORY RESET: Clear everything to start fresh as requested
    console.log("Resetting application state to defaults...");

    // 1. Clear Storage
    localStorage.removeItem('mindorbit_syllabus_v3');
    localStorage.removeItem('mindorbit_notes');
    localStorage.removeItem('mindorbit_doubts');
    localStorage.removeItem('mindorbit_reminders');
    localStorage.removeItem('mindorbit_badges');
    localStorage.removeItem('mindorbit_chat_v1');

    // 2. Reset States to Constants
    setSubjects(JSON.parse(JSON.stringify(INITIAL_SYLLABUS)));
    setNotes([]);
    setDoubts([]);
    setReminders([]);
    setBadges(JSON.parse(JSON.stringify(INITIAL_BADGES)));
    setChatHistory(JSON.parse(JSON.stringify(INITIAL_CHAT_MESSAGES)));

    // 3. Navigate to Dashboard
    setActiveMode(APP_MODES.DASHBOARD);
  }, []);

  const handleToggleTopic = (subjectId: string, topicId: string) => {
    setSubjects(prev => prev.map(s => s.id === subjectId ? { ...s, topics: s.topics.map(t => t.id === topicId ? { ...t, completed: !t.completed } : t) } : s));
  };

  const handleAddSubject = (name: string, classLevel: string) => {
    const newSubject: Subject = {
      id: `subj-${Math.random().toString(36).substr(2, 5)}`,
      name,
      classLevel,
      topics: [
        { id: `topic-${Math.random()}`, name: 'Introductory Chapter', completed: false, revisionStatus: 'Not Started' }
      ]
    };
    setSubjects(prev => [...prev, newSubject]);
  };

  const handleAddNote = (newNoteData: Omit<Note, 'id' | 'timestamp'>) => {
    setNotes(prev => [{ ...newNoteData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now() }, ...prev]);
  };

  const handleDeleteNote = (id: string) => setNotes(prev => prev.filter(n => n.id !== id));

  const handleSaveDoubt = (doubtData: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => {
    setDoubts(prev => [{ ...doubtData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now(), resolved: false }, ...prev]);
  };

  const handleAddReminder = (task: string, time: string, type: Reminder['type'] = 'Study') => {
    setReminders(prev => [...prev, { id: Math.random().toString(36).substr(2, 9), task, time, completed: false, type }]);
  };

  const toggleReminder = (id: string) => setReminders(prev => prev.map(r => r.id === id ? { ...r, completed: !r.completed } : r));
  const deleteReminder = (id: string) => setReminders(prev => prev.filter(r => r.id !== id));

  const renderContent = () => {
    const isDark = theme === 'dark';
    switch (activeMode) {
      case APP_MODES.DASHBOARD:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} badges={badges} />;
      case APP_MODES.CHAT:
        return <AITutor messages={chatHistory} setMessages={setChatHistory} notes={notes} onSaveDoubt={handleSaveDoubt} theme={theme} />;
      case APP_MODES.PLANNER:
        return <StudyPlanner reminders={reminders} onAddReminder={handleAddReminder} onToggleReminder={toggleReminder} onDeleteReminder={deleteReminder} theme={theme} />;
      case APP_MODES.SYLLABUS:
        return <SyllabusTracker subjects={subjects} onToggleTopic={handleToggleTopic} onAddSubject={handleAddSubject} theme={theme} />;
      case APP_MODES.NOTES:
        return <NotesManager notes={notes} onAddNote={handleAddNote} onDeleteNote={handleDeleteNote} />;
      case APP_MODES.DEEP_DIVE:
        return <DeepDive theme={theme} />;
      case APP_MODES.DOUBTS:
        return (
          <div className="space-y-10 animate-fadeIn">
            <header>
              <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>The <span className="text-[#4CC9F0]">Vault</span></h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Permanently archived intelligence blocks.</p>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {doubts.map(doubt => (
                <div key={doubt.id} className={`p-10 rounded-[3rem] border transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
                  <div className="flex justify-between items-center mb-8">
                    <span className="text-[10px] px-4 py-1.5 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-full font-black uppercase tracking-widest border border-[#4CC9F0]/20">Doubt #{doubt.id.substring(0,3)}</span>
                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{doubt.subject}</span>
                  </div>
                  <p className={`text-xl font-bold mb-8 leading-tight ${isDark ? 'text-white' : 'text-slate-950'}`}>{doubt.question}</p>
                  <div className={`p-8 rounded-[2rem] italic text-sm leading-relaxed border ${isDark ? 'bg-[#0D1B2A] border-slate-800 text-slate-400' : 'bg-slate-50 border-slate-100 text-slate-600'}`}>
                    {doubt.answer}
                  </div>
                </div>
              ))}
              {doubts.length === 0 && <div className="col-span-full py-32 text-center opacity-30 italic font-black text-2xl tracking-tighter">VAULT_EMPTY.SYS</div>}
            </div>
          </div>
        );
      default:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} badges={badges} />;
    }
  };

  if (activeMode === APP_MODES.LANDING) {
    return <LandingPage onStart={handleAuthSuccess} theme={theme} />;
  }

  return (
    <div className={`flex min-h-screen transition-colors duration-500 ${theme === 'dark' ? 'bg-[#0D1B2A]' : 'bg-slate-50'}`}>
      <Sidebar 
        activeMode={activeMode} 
        setActiveMode={setActiveMode} 
        theme={theme} 
        toggleTheme={toggleTheme} 
        onLogout={() => setActiveMode(APP_MODES.LANDING)}
      />
      <main className="flex-1 ml-24 lg:ml-72 p-8 lg:p-16 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Message, Note, Doubt, ThemeMode, StudyMode } from '../types';
import { getGeminiResponse, cleanAIResponse } from '../services/geminiService';

interface AITutorProps {
  messages: Message[];
  setMessages: React.Dispatch<React.SetStateAction<Message[]>>;
  notes: Note[];
  onSaveDoubt: (doubt: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => void;
  theme: ThemeMode;
}

const AITutor: React.FC<AITutorProps> = ({ messages, setMessages, notes, onSaveDoubt, theme }) => {
  const isDark = theme === 'dark';
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [selectedNoteId, setSelectedNoteId] = useState<string | null>(null);
  const [studyMode, setStudyMode] = useState<StudyMode>('Normal');
  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'en-IN';

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInput(prev => prev + (prev ? ' ' : '') + transcript);
        setIsListening(false);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error('Speech recognition error', event.error);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isLoading]);

  const toggleListening = () => {
    if (!recognitionRef.current) {
      alert("Speech recognition is not supported in this browser.");
      return;
    }

    if (isListening) {
      recognitionRef.current.stop();
    } else {
      try {
        recognitionRef.current.start();
        setIsListening(true);
      } catch (err) {
        console.error("Failed to start recognition", err);
      }
    }
  };

  const handleSend = async () => {
    if ((!input.trim() && !selectedNoteId) || isLoading) return;

    const currentInput = input;
    setInput('');

    let parts: any[] = [{ text: currentInput }];
    if (selectedNoteId) {
      const note = notes.find(n => n.id === selectedNoteId);
      if (note) parts.push({ text: `\n\n[CONTEXT FROM NOTE: ${note.title}]\n${note.content}` });
    }

    const newUserMsg: Message = { role: 'user', parts: [{ text: currentInput }], timestamp: Date.now(), mode: studyMode };
    setMessages(prev => [...prev, newUserMsg]);
    setIsLoading(true);

    const responseText = await getGeminiResponse([...messages, { role: 'user', parts, timestamp: Date.now() }], studyMode);

    setMessages(prev => [...prev, { role: 'model', parts: [{ text: responseText }], timestamp: Date.now() }]);
    setIsLoading(false);
    setSelectedNoteId(null);
  };

  return (
    <div className={`flex flex-col h-[calc(100vh-8rem)] rounded-[3.5rem] overflow-hidden transition-all shadow-2xl border ${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white border-slate-100 shadow-slate-200/50'}`}>
      {/* AI Header */}
      <div className={`p-8 flex flex-wrap justify-between items-center border-b gap-4 ${isDark ? 'border-slate-800' : 'border-slate-50'}`}>
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 bg-[#4CC9F0] rounded-3xl flex items-center justify-center text-[#0D1B2A] text-2xl shadow-xl shadow-[#4CC9F0]/30 animate-pulse-slow">
            <i className="fa-solid fa-sparkles"></i>
          </div>
          <div>
            <h3 className={`font-black tracking-tight text-xl ${isDark ? 'text-white' : 'text-slate-900'}`}>Orbit AI</h3>
            <p className="text-[10px] font-extrabold uppercase tracking-[0.2em] text-[#4CAF50]">Neural Core Active</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className={`flex p-1.5 rounded-3xl border ${isDark ? 'bg-slate-900 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
            {(['Normal', 'ELI5', 'Exam-Oriented'] as StudyMode[]).map(m => (
              <button
