             <div className="bg-[#4CC9F0]/10 border border-[#4CC9F0]/20 rounded-full px-8 py-4 flex items-center gap-3">
               <div className="w-2 h-2 bg-[#4CC9F0] rounded-full animate-bounce"></div>
