        )}
      </div>

      {/* Chat Input */}
      <div className={`p-8 border-t ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-50'}`}>
        <div className="max-w-4xl mx-auto relative flex items-center group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={isListening ? "Listening closely..." : "Ask anything in English or Hinglish..."}
            className={`w-full rounded-[2.5rem] py-6 pl-10 pr-20 outline-none focus:ring-4 ring-[#4CC9F0]/10 transition-all font-bold text-lg ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-slate-50 border-slate-100 text-slate-900 placeholder-slate-400'}`}
          />
          <div className="absolute right-4 flex items-center gap-2">
            <button 
              onClick={toggleListening}
              className={`p-4 rounded-3xl transition-all ${isListening ? 'text-red-500 animate-pulse bg-red-500/10' : isDark ? 'text-slate-600 hover:text-[#4CC9F0]' : 'text-slate-300 hover:text-[#4CC9F0]'}`}
              title={isListening ? "Stop Listening" : "Start Voice Input"}
            >
               <i className={`fa-solid ${isListening ? 'fa-microphone' : 'fa-microphone-lines'} text-xl`}></i>
            </button>
            <button
              onClick={handleSend}
              disabled={isLoading || (!input.trim() && !selectedNoteId)}
              className="p-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl hover:scale-110 active:scale-90 transition-all disabled:opacity-30 shadow-2xl shadow-[#4CC9F0]/30"
            >
              <i className="fa-solid fa-paper-plane text-xl"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

