                cx="160" cy="160" r={radius} 
                stroke={mode === 'Work' ? '#4CC9F0' : '#4CAF50'} 
                strokeWidth="6" fill="none"
                strokeDasharray={circumference}
                strokeDashoffset={circumference - progress}
                className="transition-all duration-1000 ease-linear"
                strokeLinecap="round"
              />
            </svg>

            {/* Central Glass Orb */}
            <div className={`relative w-64 h-64 rounded-full flex flex-col items-center justify-center transition-all duration-700 backdrop-blur-3xl shadow-2xl ${
              isDark 
                ? 'bg-gradient-to-br from-slate-800/80 to-slate-900/90 border border-white/5' 
                : 'bg-gradient-to-br from-white/90 to-slate-50/90 border border-slate-200/50'
            }`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.5em] mb-2 opacity-40 ${isDark ? 'text-white' : 'text-slate-900'}`}>
                {isActive ? 'Flowing' : 'Paused'}
              </span>
              <p className={`text-7xl font-light tracking-tighter tabular-nums ${isDark ? 'text-white' : 'text-slate-900'}`}>
                {formatTime(timeLeft)}
              </p>

              {/* Progress Percentage Tiny Tag */}
              <div className="absolute bottom-16">
                 <span className={`text-[9px] font-black ${mode === 'Work' ? 'text-[#4CC9F0]' : 'text-[#4CAF50]'}`}>
                   {Math.round((timeLeft / totalSeconds) * 100)}% REMAINING
                 </span>
              </div>
            </div>
          </div>

          {/* Control Cluster */}
          <div className="mt-12 flex items-center gap-6 z-10">
            <button 
              onClick={() => { setIsActive(false); setTimeLeft(mode === 'Work' ? 25 * 60 : 5 * 60); }}
              className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
                isDark ? 'bg-slate-800 text-slate-500 hover:text-white border border-white/5' : 'bg-white text-slate-400 hover:text-slate-600 border border-slate-100 shadow-sm'
              }`}
            >
              <i className="fa-solid fa-arrow-rotate-left"></i>
            </button>

            <button 
              onClick={() => setIsActive(!isActive)}
              className={`w-24 h-24 rounded-full flex items-center justify-center text-2xl transition-all shadow-2xl group ${
                mode === 'Work' 
                  ? 'bg-[#4CC9F0] text-[#0D1B2A] shadow-[#4CC9F0]/30 hover:scale-105 active:scale-95' 
                  : 'bg-[#4CAF50] text-[#0D1B2A] shadow-[#4CAF50]/30 hover:scale-105 active:scale-95'
              }`}
            >
              <i className={`fa-solid ${isActive ? 'fa-pause' : 'fa-play'}`}></i>
            </button>

            <button 
              onClick={() => {
                const newMode = mode === 'Work' ? 'Break' : 'Work';
                setMode(newMode);
                setTimeLeft(newMode === 'Work' ? 25 * 60 : 5 * 60);
                setIsActive(false);
              }}
              className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
                isDark ? 'bg-slate-800 text-slate-500 hover:text-white border border-white/5' : 'bg-white text-slate-400 hover:text-slate-600 border border-slate-100 shadow-sm'
              }`}
              title="Skip Session"
            >
              <i className="fa-solid fa-forward-step"></i>
            </button>
          </div>
        </div>

        {/* Mission Objectives Board */}
        <div className="lg:col-span-7 card-premium p-12 rounded-[3.5rem] relative overflow-hidden">
          <div className="flex justify-between items-center mb-10 relative z-10">
            <div className="flex items-center gap-4">
               <div className="w-12 h-12 bg-[#4CC9F0]/10 rounded-2xl flex items-center justify-center text-[#4CC9F0] text-xl">
                 <i className="fa-solid fa-list-check"></i>
               </div>
               <h3 className={`text-xl font-black ${isDark ? 'text-white' : 'text-slate-800'}`}>Session Tasks</h3>
            </div>
            <button 
              onClick={() => setShowAddForm(!showAddForm)}
              className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${showAddForm ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-[#4CC9F0]/10 text-[#4CC9F0] border-[#4CC9F0]/20 hover:bg-[#4CC9F0] hover:text-[#0D1B2A]'}`}
            >
              {showAddForm ? 'Cancel' : <><i className="fa-solid fa-plus mr-2"></i> Add Task</>}
            </button>
          </div>

          {showAddForm && (
            <form onSubmit={handleCreateTarget} className={`p-8 rounded-[2.5rem] border mb-10 animate-slideDown relative z-10 ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <input 
                  autoFocus
                  className={`px-6 py-4 rounded-2xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-white border-slate-100 text-slate-900 placeholder-slate-400'}`}
                  placeholder="What are we doing?"
                  value={newTaskName}
                  onChange={(e) => setNewTaskName(e.target.value)}
                />
                <input 
                  className={`px-6 py-4 rounded-2xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-white border-slate-100 text-slate-900 placeholder-slate-400'}`}
                  placeholder="Due Time (e.g., 4:30 PM)"
                  value={newTaskTime}
                  onChange={(e) => setNewTaskTime(e.target.value)}
                />
              </div>
              <button type="submit" className="w-full py-4 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl shadow-[#4CC9F0]/10">
                Confirm Deployment
              </button>
            </form>
          )}

          <div className="space-y-4 relative z-10 max-h-[500px] overflow-y-auto custom-scrollbar pr-2">
            {reminders.map(rem => (
              <div key={rem.id} className={`p-6 rounded-[2.5rem] border flex items-center gap-8 transition-all group ${isDark ? 'bg-slate-900/40 border-slate-800' : 'bg-white border-slate-100 hover:shadow-xl hover:shadow-slate-200/30'}`}>
                <button 
                  onClick={() => onToggleReminder(rem.id)}
                  className={`w-12 h-12 rounded-2xl flex items-center justify-center border-2 transition-all ${rem.completed ? 'bg-[#4CAF50] border-[#4CAF50] text-[#0D1B2A]' : 'border-slate-700 hover:border-[#4CC9F0] text-transparent'}`}
                >
                  <i className="fa-solid fa-check text-sm"></i>
                </button>
                <div className="flex-1">
                  <p className={`text-lg font-bold tracking-tight ${rem.completed ? 'line-through opacity-30' : isDark ? 'text-white' : 'text-slate-900'}`}>{rem.task}</p>
                  <div className="flex items-center gap-4 mt-2">
                    <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest flex items-center gap-2">
                      <i className="fa-solid fa-clock text-[#4CC9F0]"></i> {rem.time}
                    </span>
                  </div>
                </div>
                <button onClick={() => onDeleteReminder(rem.id)} className="w-10 h-10 rounded-xl bg-red-500/5 text-red-500 opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center hover:bg-red-500 hover:text-white">
                  <i className="fa-solid fa-xmark text-sm"></i>
                </button>
              </div>
            ))}
            {reminders.length === 0 && !showAddForm && (
              <div className="py-24 text-center border-2 border-dashed border-slate-800/10 rounded-[3rem]">
                <div className="w-20 h-20 bg-slate-800/5 text-slate-400 rounded-full flex items-center justify-center mx-auto mb-6 text-2xl">
                  <i className="fa-solid fa-cloud-sun"></i>
                </div>
                <h4 className={`text-xl font-bold ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>Ready for takeoff.</h4>
                <p className="text-slate-600 font-bold text-xs mt-2 uppercase tracking-widest">Add a task to populate your mission board.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StudyPlanner;

import React, { useState, useEffect, useRef } from 'react';
import { Reminder, ThemeMode } from '../types';

interface StudyPlannerProps {
  reminders: Reminder[];
  onAddReminder: (task: string, time: string, type: Reminder['type']) => void;
  onToggleReminder: (id: string) => void;
  onDeleteReminder: (id: string) => void;
  theme: ThemeMode;
}

const StudyPlanner: React.FC<StudyPlannerProps> = ({ reminders, onAddReminder, onToggleReminder, onDeleteReminder, theme }) => {
  const isDark = theme === 'dark';

  // Custom Session Timings
  const [workDuration, setWorkDuration] = useState(25); // minutes
  const [breakDuration, setBreakDuration] = useState(5); // minutes

  const [timeLeft, setTimeLeft] = useState(25 * 60);
  const [isActive, setIsActive] = useState(false);
  const [mode, setMode] = useState<'Work' | 'Break'>('Work');
  const [showAddForm, setShowAddForm] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [newTaskName, setNewTaskName] = useState('');
  const [newTaskTime, setNewTaskTime] = useState('');

  // Notification State
  const [notifying, setNotifying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Initialize Audio
  useEffect(() => {
    audioRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3');
  }, []);

  useEffect(() => {
    let interval: any = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && isActive) {
      handleSessionComplete();
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  const handleSessionComplete = () => {
    setIsActive(false);
    setNotifying(true);

    // Play Notification Bell
    if (audioRef.current) {
      audioRef.current.currentTime = 0;
      audioRef.current.play().catch(e => console.warn("Audio blocked by browser", e));
    }

    // Auto switch modes after 3 seconds of notification
    setTimeout(() => {
      setNotifying(false);
      if (mode === 'Work') {
        setMode('Break');
        setTimeLeft(breakDuration * 60);
      } else {
        setMode('Work');
        setTimeLeft(workDuration * 60);
      }
    }, 3000);
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const handleCreateTarget = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTaskName && newTaskTime) {
      onAddReminder(newTaskName, newTaskTime, 'Study');
      setNewTaskName('');
      setNewTaskTime('');
      setShowAddForm(false);
    }
  };

  const updateWorkDuration = (val: number) => {
    const clamped = Math.max(1, Math.min(120, val));
    setWorkDuration(clamped);
    if (!isActive && mode === 'Work') setTimeLeft(clamped * 60);
  };

  const updateBreakDuration = (val: number) => {
    const clamped = Math.max(1, Math.min(60, val));
    setBreakDuration(clamped);
    if (!isActive && mode === 'Break') setTimeLeft(clamped * 60);
  };

  // SVG Constants
  const radius = 110;
  const circumference = 2 * Math.PI * radius;
  const totalSeconds = mode === 'Work' ? workDuration * 60 : breakDuration * 60;
  const progress = (timeLeft / totalSeconds) * circumference;

  return (
    <div className="space-y-12 animate-fadeIn pb-20">
      <header className="flex justify-between items-start">
        <div>
          <h2 className={`text-3xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Spatial <span className="text-[#4CC9F0]">Planner</span></h2>
          <p className="text-slate-500 font-bold text-sm mt-1">Design your focus blocks with precision.</p>
        </div>

        {/* Settings Toggle */}
        <button 
          onClick={() => setShowSettings(!showSettings)}
          className={`p-4 rounded-2xl border transition-all ${showSettings ? 'bg-[#4CC9F0] text-[#0D1B2A] border-[#4CC9F0]' : 'bg-slate-800/10 text-slate-500 border-slate-700/20 hover:border-[#4CC9F0]/50'}`}
        >
          <i className={`fa-solid ${showSettings ? 'fa-xmark' : 'fa-gear'} text-lg`}></i>
        </button>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        {/* The Chronos Orb (Holographic Glass Timer) */}
        <div className={`lg:col-span-5 p-1 rounded-[4rem] relative overflow-hidden flex flex-col items-center justify-center min-h-[550px] transition-all duration-700 ${isDark ? 'bg-slate-900/40' : 'bg-white shadow-2xl shadow-slate-200/50'}`}>

          {/* Background Aura Glow */}
          <div className={`absolute w-[150%] h-[150%] rounded-full blur-[120px] opacity-20 transition-all duration-1000 ${
            notifying ? 'bg-red-500' : mode === 'Work' ? 'bg-[#4CC9F0]' : 'bg-[#4CAF50]'
          } ${isActive || notifying ? 'scale-110 animate-pulse-slow' : 'scale-100'}`}></div>

          {/* Settings Overlay */}
          {showSettings && (
            <div className="absolute inset-0 z-20 backdrop-blur-2xl bg-slate-900/80 p-12 flex flex-col items-center justify-center animate-fadeIn">
              <h3 className="text-white font-black uppercase tracking-[0.4em] text-xs mb-10 text-[#4CC9F0]">Orbit Configurations</h3>
              <div className="w-full space-y-8">
                <div className="space-y-3">
                  <div className="flex justify-between text-[10px] font-black uppercase text-slate-500 tracking-widest px-2">
                    <span>Work Duration</span>
                    <span className="text-white">{workDuration}m</span>
                  </div>
                  <input 
                    type="range" min="1" max="120" value={workDuration} 
                    onChange={(e) => updateWorkDuration(parseInt(e.target.value))}
                    className="w-full accent-[#4CC9F0] h-1 bg-slate-800 rounded-full appearance-none cursor-pointer"
                  />
                </div>
                <div className="space-y-3">
                  <div className="flex justify-between text-[10px] font-black uppercase text-slate-500 tracking-widest px-2">
                    <span>Break Duration</span>
                    <span className="text-white">{breakDuration}m</span>
                  </div>
                  <input 
                    type="range" min="1" max="60" value={breakDuration} 
                    onChange={(e) => updateBreakDuration(parseInt(e.target.value))}
                    className="w-full accent-[#4CAF50] h-1 bg-slate-800 rounded-full appearance-none cursor-pointer"
                  />
                </div>
              </div>
              <button 
                onClick={() => setShowSettings(false)}
                className="mt-12 px-10 py-4 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl font-black uppercase text-[10px] tracking-widest"
              >
                Apply Changes
              </button>
            </div>
          )}

          {/* Mode Indicator Floating Pill */}
          <div className={`z-10 mb-8 px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.3em] transition-all duration-500 ${
            notifying ? 'bg-red-500/20 text-red-500 border border-red-500/30' :
            mode === 'Work' 
              ? 'bg-[#4CC9F0]/10 text-[#4CC9F0] border border-[#4CC9F0]/20' 
              : 'bg-[#4CAF50]/10 text-[#4CAF50] border border-[#4CAF50]/20'
          }`}>
            {notifying ? 'Mission Accomplished' : `${mode} Session`}
          </div>

          <div className="relative w-80 h-80 flex items-center justify-center">
            {/* Notification Bell Flash */}
            {notifying && (
              <div className="absolute z-30 animate-ping">
                 <i className="fa-solid fa-bell text-8xl text-[#4CC9F0]/50"></i>
              </div>
            )}

            {/* Outer Breathing Ring */}
            <div className={`absolute inset-0 rounded-full border border-dashed opacity-20 ${isActive ? 'animate-spin' : ''} ${isDark ? 'border-slate-500' : 'border-slate-300'}`} style={{ animationDuration: '20s' }}></div>

            {/* SVG Liquid Progress Ring */}
            <svg className="absolute w-full h-full -rotate-90 drop-shadow-[0_0_15px_rgba(76,201,240,0.2)]">
              {/* Background Track */}
              <circle 
                cx="160" cy="160" r={radius} 
                stroke={isDark ? 'rgba(255,255,255,0.03)' : 'rgba(0,0,0,0.03)'} 
                strokeWidth="4" fill="none" 
              />
              {/* Active Progress */}
              <circle 
                cx="160" cy="160" r={radius} 
                stroke={notifying ? '#EF4444' : mode === 'Work' ? '#4CC9F0' : '#4CAF50'} 
                strokeWidth="6" fill="none"
                strokeDasharray={circumference}
                strokeDashoffset={circumference - progress}
                className="transition-all duration-1000 ease-linear"
                strokeLinecap="round"
              />
            </svg>

            {/* Central Glass Orb */}
            <div className={`relative w-64 h-64 rounded-full flex flex-col items-center justify-center transition-all duration-700 backdrop-blur-3xl shadow-2xl ${
              isDark 
                ? 'bg-gradient-to-br from-slate-800/80 to-slate-900/90 border border-white/5' 
                : 'bg-gradient-to-br from-white/90 to-slate-50/90 border border-slate-200/50'
            }`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.5em] mb-2 opacity-40 ${isDark ? 'text-white' : 'text-slate-900'}`}>
                {notifying ? 'Success' : isActive ? 'Flowing' : 'Ready'}
              </span>
              <p className={`text-7xl font-light tracking-tighter tabular-nums ${isDark ? 'text-white' : 'text-slate-900'} ${notifying ? 'animate-bounce' : ''}`}>
                {formatTime(timeLeft)}
              </p>

              {/* Progress Percentage Tiny Tag */}
              <div className="absolute bottom-16">
                 <span className={`text-[9px] font-black ${notifying ? 'text-red-500' : mode === 'Work' ? 'text-[#4CC9F0]' : 'text-[#4CAF50]'}`}>
                   {notifying ? 'WELL DONE' : `${Math.round((timeLeft / totalSeconds) * 100)}% REMAINING`}
                 </span>
              </div>
            </div>
          </div>

          {/* Control Cluster */}
          <div className="mt-12 flex items-center gap-6 z-10">
            <button 
              onClick={() => { setIsActive(false); setTimeLeft(mode === 'Work' ? workDuration * 60 : breakDuration * 60); setNotifying(false); }}
              className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
                isDark ? 'bg-slate-800 text-slate-500 hover:text-white border border-white/5' : 'bg-white text-slate-400 hover:text-slate-600 border border-slate-100 shadow-sm'
              }`}
            >
              <i className="fa-solid fa-arrow-rotate-left"></i>
            </button>

            <button 
              onClick={() => setIsActive(!isActive)}
              disabled={notifying}
              className={`w-24 h-24 rounded-full flex items-center justify-center text-2xl transition-all shadow-2xl group disabled:opacity-50 ${
                mode === 'Work' 
                  ? 'bg-[#4CC9F0] text-[#0D1B2A] shadow-[#4CC9F0]/30 hover:scale-105 active:scale-95' 
                  : 'bg-[#4CAF50] text-[#0D1B2A] shadow-[#4CAF50]/30 hover:scale-105 active:scale-95'
              }`}
            >
              <i className={`fa-solid ${isActive ? 'fa-pause' : 'fa-play'}`}></i>
            </button>

            <button 
              onClick={() => {
                const newMode = mode === 'Work' ? 'Break' : 'Work';
                setMode(newMode);
                setTimeLeft(newMode === 'Work' ? workDuration * 60 : breakDuration * 60);
                setIsActive(false);
                setNotifying(false);
              }}
              className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
                isDark ? 'bg-slate-800 text-slate-500 hover:text-white border border-white/5' : 'bg-white text-slate-400 hover:text-slate-600 border border-slate-100 shadow-sm'
              }`}
              title="Skip Session"
            >
              <i className="fa-solid fa-forward-step"></i>
            </button>
          </div>
        </div>

        {/* Mission Objectives Board */}
        <div className="lg:col-span-7 card-premium p-12 rounded-[3.5rem] relative overflow-hidden">
          <div className="flex justify-between items-center mb-10 relative z-10">
            <div className="flex items-center gap-4">
               <div className="w-12 h-12 bg-[#4CC9F0]/10 rounded-2xl flex items-center justify-center text-[#4CC9F0] text-xl">
                 <i className="fa-solid fa-list-check"></i>
               </div>
               <h3 className={`text-xl font-black ${isDark ? 'text-white' : 'text-slate-800'}`}>Session Tasks</h3>
            </div>
            <button 
              onClick={() => setShowAddForm(!showAddForm)}
              className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${showAddForm ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-[#4CC9F0]/10 text-[#4CC9F0] border-[#4CC9F0]/20 hover:bg-[#4CC9F0] hover:text-[#0D1B2A]'}`}
            >
              {showAddForm ? 'Cancel' : <><i className="fa-solid fa-plus mr-2"></i> Add Task</>}
            </button>
          </div>

          {showAddForm && (
            <form onSubmit={handleCreateTarget} className={`p-8 rounded-[2.5rem] border mb-10 animate-slideDown relative z-10 ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <input 
                  autoFocus
                  className={`px-6 py-4 rounded-2xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-white border-slate-100 text-slate-900 placeholder-slate-400'}`}
                  placeholder="What are we doing?"
                  value={newTaskName}
                  onChange={(e) => setNewTaskName(e.target.value)}
                />
                <input 
                  className={`px-6 py-4 rounded-2xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-white border-slate-100 text-slate-900 placeholder-slate-400'}`}
                  placeholder="Due Time (e.g., 4:30 PM)"
                  value={newTaskTime}
                  onChange={(e) => setNewTaskTime(e.target.value)}
                />
              </div>
              <button type="submit" className="w-full py-4 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl shadow-[#4CC9F0]/10">
                Confirm Deployment
              </button>
            </form>
          )}

          <div className="space-y-4 relative z-10 max-h-[500px] overflow-y-auto custom-scrollbar pr-2">
            {reminders.map(rem => (
              <div key={rem.id} className={`p-6 rounded-[2.5rem] border flex items-center gap-8 transition-all group ${isDark ? 'bg-slate-900/40 border-slate-800' : 'bg-white border-slate-100 hover:shadow-xl hover:shadow-slate-200/30'}`}>
                <button 
                  onClick={() => onToggleReminder(rem.id)}
                  className={`w-12 h-12 rounded-2xl flex items-center justify-center border-2 transition-all ${rem.completed ? 'bg-[#4CAF50] border-[#4CAF50] text-[#0D1B2A]' : 'border-slate-700 hover:border-[#4CC9F0] text-transparent'}`}
                >
                  <i className="fa-solid fa-check text-sm"></i>
                </button>
                <div className="flex-1">
                  <p className={`text-lg font-bold tracking-tight ${rem.completed ? 'line-through opacity-30' : isDark ? 'text-white' : 'text-slate-900'}`}>{rem.task}</p>
                  <div className="flex items-center gap-4 mt-2">
                    <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest flex items-center gap-2">
                      <i className="fa-solid fa-clock text-[#4CC9F0]"></i> {rem.time}
                    </span>
                  </div>
                </div>
                <button onClick={() => onDeleteReminder(rem.id)} className="w-10 h-10 rounded-xl bg-red-500/5 text-red-500 opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center hover:bg-red-500 hover:text-white">
                  <i className="fa-solid fa-xmark text-sm"></i>
                </button>
              </div>
            ))}
            {reminders.length === 0 && !showAddForm && (
              <div className="py-24 text-center border-2 border-dashed border-slate-800/10 rounded-[3rem]">
                <div className="w-20 h-20 bg-slate-800/5 text-slate-400 rounded-full flex items-center justify-center mx-auto mb-6 text-2xl">
                  <i className="fa-solid fa-cloud-sun"></i>
                </div>
                <h4 className={`text-xl font-bold ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>Ready for takeoff.</h4>
                <p className="text-slate-600 font-bold text-xs mt-2 uppercase tracking-widest">Add a task to populate your mission board.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StudyPlanner;

import React, { useState, useEffect, useRef } from 'react';
import { Reminder, ThemeMode } from '../types';

interface StudyPlannerProps {
  reminders: Reminder[];
  onAddReminder: (task: string, time: string, type: Reminder['type']) => void;
  onToggleReminder: (id: string) => void;
  onDeleteReminder: (id: string) => void;
  theme: ThemeMode;
}

const StudyPlanner: React.FC<StudyPlannerProps> = ({ reminders, onAddReminder, onToggleReminder, onDeleteReminder, theme }) => {
  const isDark = theme === 'dark';

  // Custom Session Timings (Pomodoro)
  const [workDuration, setWorkDuration] = useState(25);
  const [breakDuration, setBreakDuration] = useState(5);
  const [timeLeft, setTimeLeft] = useState(25 * 60);
  const [isActive, setIsActive] = useState(false);
  const [mode, setMode] = useState<'Work' | 'Break'>('Work');

  // Form/UI States
  const [showAddForm, setShowAddForm] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [newTaskName, setNewTaskName] = useState('');
  const [newTaskTime, setNewTaskTime] = useState('');

  // Notification State for POMODORO
  const [notifying, setNotifying] = useState(false);

  // NEW: Task Alarm State (For individual list tasks)
  const [taskAlarm, setTaskAlarm] = useState<Reminder | null>(null);
  const [alarmPlayedIds, setAlarmPlayedIds] = useState<Set<string>>(new Set());

  const sessionAudioRef = useRef<HTMLAudioElement | null>(null);
  const taskBellRef = useRef<HTMLAudioElement | null>(null);

  // Initialize Audio
  useEffect(() => {
    sessionAudioRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3'); // Smooth chime
    taskBellRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/1070/1070-preview.mp3'); // Sharp bell
    taskBellRef.current.loop = true;
  }, []);

  // 1. Logic for Pomodoro Timer
  useEffect(() => {
    let interval: any = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && isActive) {
      handleSessionComplete();
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  // 2. NEW: Logic for Task Alarms (Monitoring due times)
  useEffect(() => {
    const checkTaskAlarms = () => {
      const now = new Date();
      const currentHours = now.getHours();
      const currentMinutes = now.getMinutes();

      reminders.forEach(rem => {
        if (rem.completed || alarmPlayedIds.has(rem.id)) return;

        // Simple parsing for "HH:MM" or "HH:MM AM/PM"
        const timeStr = rem.time.toLowerCase();
        let taskH = 0, taskM = 0;

        try {
          const [timePart, ampm] = timeStr.split(' ');
          const [h, m] = timePart.split(':').map(n => parseInt(n));
          taskH = h;
          taskM = m;

          if (ampm === 'pm' && taskH < 12) taskH += 12;
          if (ampm === 'am' && taskH === 12) taskH = 0;

          if (currentHours === taskH && currentMinutes === taskM) {
            triggerTaskAlarm(rem);
          }
        } catch (e) {
          // If parsing fails, skip
        }
      });
    };

    const alarmInterval = setInterval(checkTaskAlarms, 10000); // Check every 10 seconds
    return () => clearInterval(alarmInterval);
  }, [reminders, alarmPlayedIds]);

  const triggerTaskAlarm = (rem: Reminder) => {
    setTaskAlarm(rem);
    setAlarmPlayedIds(prev => new Set(prev).add(rem.id));
    if (taskBellRef.current) {
      taskBellRef.current.play().catch(e => console.warn("Sound blocked", e));
    }
  };

  const dismissTaskAlarm = (completeTask: boolean = false) => {
    if (taskAlarm && completeTask) {
      onToggleReminder(taskAlarm.id);
    }
    if (taskBellRef.current) {
      taskBellRef.current.pause();
      taskBellRef.current.currentTime = 0;
    }
    setTaskAlarm(null);
  };

  const handleSessionComplete = () => {
    setIsActive(false);
    setNotifying(true);
    if (sessionAudioRef.current) {
      sessionAudioRef.current.currentTime = 0;
      sessionAudioRef.current.play().catch(e => console.warn("Audio blocked", e));
    }
    setTimeout(() => {
      setNotifying(false);
      if (mode === 'Work') {
        setMode('Break');
        setTimeLeft(breakDuration * 60);
      } else {
        setMode('Work');
        setTimeLeft(workDuration * 60);
      }
    }, 3000);
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const handleCreateTarget = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTaskName && newTaskTime) {
      onAddReminder(newTaskName, newTaskTime, 'Study');
      setNewTaskName('');
      setNewTaskTime('');
      setShowAddForm(false);
    }
  };

  const updateWorkDuration = (val: number) => {
    const clamped = Math.max(1, Math.min(120, val));
    setWorkDuration(clamped);
    if (!isActive && mode === 'Work') setTimeLeft(clamped * 60);
  };

  const updateBreakDuration = (val: number) => {
    const clamped = Math.max(1, Math.min(60, val));
    setBreakDuration(clamped);
    if (!isActive && mode === 'Break') setTimeLeft(clamped * 60);
  };

  // SVG Rings
  const radius = 110;
  const circumference = 2 * Math.PI * radius;
  const totalSeconds = mode === 'Work' ? workDuration * 60 : breakDuration * 60;
  const progress = (timeLeft / totalSeconds) * circumference;

  return (
    <div className="space-y-12 animate-fadeIn pb-20 relative">

      {/* TASK ALARM MODAL */}
      {taskAlarm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 backdrop-blur-3xl bg-[#0D1B2A]/80 animate-fadeIn">
          <div className="card-premium max-w-md w-full p-12 rounded-[4rem] text-center shadow-[0_0_100px_rgba(76,201,240,0.3)] border border-[#4CC9F0]/30">
            <div className="w-24 h-24 bg-[#4CC9F0] text-[#0D1B2A] rounded-full flex items-center justify-center text-4xl mx-auto mb-8 animate-bounce shadow-2xl shadow-[#4CC9F0]/50">
              <i className="fa-solid fa-bell"></i>
            </div>
            <p className="text-[#4CC9F0] font-black uppercase tracking-[0.4em] text-xs mb-4">Mission Deadline Reached</p>
            <h3 className={`text-3xl font-black mb-10 ${isDark ? 'text-white' : 'text-slate-900'}`}>{taskAlarm.task}</h3>

            <div className="space-y-4">
              <button 
                onClick={() => dismissTaskAlarm(true)}
                className="w-full py-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-[2rem] font-black uppercase text-[10px] tracking-widest shadow-xl shadow-[#4CC9F0]/20 hover:scale-[1.02] transition-all"
              >
                Objective Accomplished
              </button>
              <button 
                onClick={() => dismissTaskAlarm(false)}
                className="w-full py-5 bg-slate-800 text-white rounded-[2rem] font-black uppercase text-[10px] tracking-widest hover:bg-slate-700 transition-all"
              >
                Acknowledge & Close
              </button>
            </div>
          </div>
        </div>
      )}

      <header className="flex justify-between items-start">
        <div>
          <h2 className={`text-3xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Spatial <span className="text-[#4CC9F0]">Planner</span></h2>
          <p className="text-slate-500 font-bold text-sm mt-1">Design your focus blocks with precision.</p>
        </div>

        <button 
          onClick={() => setShowSettings(!showSettings)}
          className={`p-4 rounded-2xl border transition-all ${showSettings ? 'bg-[#4CC9F0] text-[#0D1B2A] border-[#4CC9F0]' : 'bg-slate-800/10 text-slate-500 border-slate-700/20 hover:border-[#4CC9F0]/50'}`}
        >
          <i className={`fa-solid ${showSettings ? 'fa-xmark' : 'fa-gear'} text-lg`}></i>
        </button>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        {/* The Chronos Orb */}
        <div className={`lg:col-span-5 p-1 rounded-[4rem] relative overflow-hidden flex flex-col items-center justify-center min-h-[550px] transition-all duration-700 ${isDark ? 'bg-slate-900/40' : 'bg-white shadow-2xl shadow-slate-200/50'}`}>

          <div className={`absolute w-[150%] h-[150%] rounded-full blur-[120px] opacity-20 transition-all duration-1000 ${
            notifying ? 'bg-red-500' : mode === 'Work' ? 'bg-[#4CC9F0]' : 'bg-[#4CAF50]'
          } ${isActive || notifying ? 'scale-110 animate-pulse-slow' : 'scale-100'}`}></div>

          {showSettings && (
            <div className="absolute inset-0 z-20 backdrop-blur-2xl bg-slate-900/80 p-12 flex flex-col items-center justify-center animate-fadeIn">
              <h3 className="text-white font-black uppercase tracking-[0.4em] text-xs mb-10 text-[#4CC9F0]">Orbit Configurations</h3>
              <div className="w-full space-y-8">
                <div className="space-y-3">
                  <div className="flex justify-between text-[10px] font-black uppercase text-slate-500 tracking-widest px-2">
                    <span>Work Session</span>
                    <span className="text-white">{workDuration}m</span>
                  </div>
                  <input 
                    type="range" min="1" max="120" value={workDuration} 
                    onChange={(e) => updateWorkDuration(parseInt(e.target.value))}
                    className="w-full accent-[#4CC9F0] h-1 bg-slate-800 rounded-full appearance-none cursor-pointer"
                  />
                </div>
                <div className="space-y-3">
                  <div className="flex justify-between text-[10px] font-black uppercase text-slate-500 tracking-widest px-2">
                    <span>Break Interval</span>
                    <span className="text-white">{breakDuration}m</span>
                  </div>
                  <input 
                    type="range" min="1" max="60" value={breakDuration} 
                    onChange={(e) => updateBreakDuration(parseInt(e.target.value))}
                    className="w-full accent-[#4CAF50] h-1 bg-slate-800 rounded-full appearance-none cursor-pointer"
                  />
                </div>
              </div>
              <button 
                onClick={() => setShowSettings(false)}
                className="mt-12 px-10 py-4 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl font-black uppercase text-[10px] tracking-widest shadow-lg shadow-[#4CC9F0]/20"
              >
                Deploy Settings
              </button>
            </div>
          )}

          <div className={`z-10 mb-8 px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.3em] transition-all duration-500 ${
            notifying ? 'bg-red-500/20 text-red-500 border border-red-500/30' :
            mode === 'Work' 
              ? 'bg-[#4CC9F0]/10 text-[#4CC9F0] border border-[#4CC9F0]/20' 
              : 'bg-[#4CAF50]/10 text-[#4CAF50] border border-[#4CAF50]/20'
          }`}>
            {notifying ? 'Mission Accomplished' : `${mode} Session`}
          </div>

          <div className="relative w-80 h-80 flex items-center justify-center">
            {notifying && (
              <div className="absolute z-30 animate-ping">
                 <i className="fa-solid fa-bell text-8xl text-[#4CC9F0]/50"></i>
              </div>
            )}

            <div className={`absolute inset-0 rounded-full border border-dashed opacity-20 ${isActive ? 'animate-spin' : ''} ${isDark ? 'border-slate-500' : 'border-slate-300'}`} style={{ animationDuration: '20s' }}></div>

            <svg className="absolute w-full h-full -rotate-90">
              <circle cx="160" cy="160" r={radius} stroke={isDark ? 'rgba(255,255,255,0.03)' : 'rgba(0,0,0,0.03)'} strokeWidth="4" fill="none" />
              <circle 
                cx="160" cy="160" r={radius} 
                stroke={notifying ? '#EF4444' : mode === 'Work' ? '#4CC9F0' : '#4CAF50'} 
                strokeWidth="6" fill="none"
                strokeDasharray={circumference}
                strokeDashoffset={circumference - progress}
                className="transition-all duration-1000 ease-linear"
                strokeLinecap="round"
              />
            </svg>

            <div className={`relative w-64 h-64 rounded-full flex flex-col items-center justify-center transition-all duration-700 backdrop-blur-3xl shadow-2xl ${
              isDark 
                ? 'bg-gradient-to-br from-slate-800/80 to-slate-900/90 border border-white/5' 
                : 'bg-gradient-to-br from-white/90 to-slate-50/90 border border-slate-200/50'
            }`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.5em] mb-2 opacity-40 ${isDark ? 'text-white' : 'text-slate-900'}`}>
                {notifying ? 'Success' : isActive ? 'Active' : 'Standby'}
              </span>
              <p className={`text-7xl font-light tracking-tighter tabular-nums ${isDark ? 'text-white' : 'text-slate-900'} ${notifying ? 'animate-bounce' : ''}`}>
                {formatTime(timeLeft)}
              </p>

              <div className="absolute bottom-16">
                 <span className={`text-[9px] font-black ${notifying ? 'text-red-500' : mode === 'Work' ? 'text-[#4CC9F0]' : 'text-[#4CAF50]'}`}>
                   {notifying ? 'WELL DONE' : `${Math.round((timeLeft / totalSeconds) * 100)}% REMAINING`}
                 </span>
              </div>
            </div>
          </div>

          <div className="mt-12 flex items-center gap-6 z-10">
            <button 
              onClick={() => { setIsActive(false); setTimeLeft(mode === 'Work' ? workDuration * 60 : breakDuration * 60); setNotifying(false); }}
              className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
                isDark ? 'bg-slate-800 text-slate-500 hover:text-white border border-white/5' : 'bg-white text-slate-400 hover:text-slate-600 border border-slate-100 shadow-sm'
              }`}
            >
              <i className="fa-solid fa-arrow-rotate-left"></i>
            </button>

            <button 
              onClick={() => setIsActive(!isActive)}
              disabled={notifying}
              className={`w-24 h-24 rounded-full flex items-center justify-center text-2xl transition-all shadow-2xl group disabled:opacity-50 ${
                mode === 'Work' 
                  ? 'bg-[#4CC9F0] text-[#0D1B2A] shadow-[#4CC9F0]/30 hover:scale-105 active:scale-95' 
                  : 'bg-[#4CAF50] text-[#0D1B2A] shadow-[#4CAF50]/30 hover:scale-105 active:scale-95'
              }`}
            >
              <i className={`fa-solid ${isActive ? 'fa-pause' : 'fa-play'}`}></i>
            </button>

            <button 
              onClick={() => {
                const newMode = mode === 'Work' ? 'Break' : 'Work';
                setMode(newMode);
                setTimeLeft(newMode === 'Work' ? workDuration * 60 : breakDuration * 60);
                setIsActive(false);
                setNotifying(false);
              }}
              className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
                isDark ? 'bg-slate-800 text-slate-500 hover:text-white border border-white/5' : 'bg-white text-slate-400 hover:text-slate-600 border border-slate-100 shadow-sm'
              }`}
            >
              <i className="fa-solid fa-forward-step"></i>
            </button>
          </div>
        </div>

        {/* Mission Objectives Board (Session Tasks) */}
        <div className="lg:col-span-7 card-premium p-12 rounded-[3.5rem] relative overflow-hidden">
          <div className="flex justify-between items-center mb-10 relative z-10">
            <div className="flex items-center gap-4">
               <div className="w-12 h-12 bg-[#4CC9F0]/10 rounded-2xl flex items-center justify-center text-[#4CC9F0] text-xl">
                 <i className="fa-solid fa-list-check"></i>
               </div>
               <h3 className={`text-xl font-black ${isDark ? 'text-white' : 'text-slate-800'}`}>Session Tasks</h3>
            </div>
            <button 
              onClick={() => setShowAddForm(!showAddForm)}
              className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${showAddForm ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-[#4CC9F0]/10 text-[#4CC9F0] border-[#4CC9F0]/20 hover:bg-[#4CC9F0] hover:text-[#0D1B2A]'}`}
            >
              {showAddForm ? 'Cancel' : <><i className="fa-solid fa-plus mr-2"></i> Add Task</>}
            </button>
          </div>

          {showAddForm && (
            <form onSubmit={handleCreateTarget} className={`p-8 rounded-[2.5rem] border mb-10 animate-slideDown relative z-10 ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <input 
                  autoFocus
                  className={`px-6 py-4 rounded-2xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-white border-slate-100 text-slate-900 placeholder-slate-400'}`}
                  placeholder="Task Name"
                  value={newTaskName}
                  onChange={(e) => setNewTaskName(e.target.value)}
