                <input 
                  className={`px-6 py-4 rounded-2xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-white border-slate-100 text-slate-900 placeholder-slate-400'}`}
                  placeholder="Set Time (e.g., 5:03 PM)"
                  value={newTaskTime}
                  onChange={(e) => setNewTaskTime(e.target.value)}
                />
              </div>
              <button type="submit" className="w-full py-4 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl font-black uppercase tracking-widest text-[10px]">
                Confirm Task
              </button>
            </form>
          )}

          <div className="space-y-4 relative z-10 max-h-[500px] overflow-y-auto custom-scrollbar pr-2">
            {reminders.map(rem => (
              <div key={rem.id} className={`p-6 rounded-[2.5rem] border flex items-center gap-8 transition-all group ${isDark ? 'bg-slate-900/40 border-slate-800' : 'bg-white border-slate-100 hover:shadow-xl'}`}>
                <button 
                  onClick={() => onToggleReminder(rem.id)}
                  className={`w-12 h-12 rounded-2xl flex items-center justify-center border-2 transition-all ${rem.completed ? 'bg-[#4CAF50] border-[#4CAF50] text-[#0D1B2A]' : 'border-slate-700 hover:border-[#4CC9F0] text-transparent'}`}
                >
                  <i className="fa-solid fa-check text-sm"></i>
                </button>
                <div className="flex-1">
                  <p className={`text-lg font-bold tracking-tight ${rem.completed ? 'line-through opacity-30' : isDark ? 'text-white' : 'text-slate-900'}`}>{rem.task}</p>
                  <div className="flex items-center gap-4 mt-2">
                    <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest flex items-center gap-2">
                      <i className={`fa-solid fa-clock ${alarmPlayedIds.has(rem.id) ? 'text-red-500' : 'text-[#4CC9F0]'}`}></i> {rem.time}
                    </span>
                  </div>
                </div>
                <button onClick={() => onDeleteReminder(rem.id)} className="w-10 h-10 rounded-xl bg-red-500/5 text-red-500 opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center hover:bg-red-500 hover:text-white">
                  <i className="fa-solid fa-xmark text-sm"></i>
                </button>
              </div>
            ))}
            {reminders.length === 0 && !showAddForm && (
              <div className="py-24 text-center border-2 border-dashed border-slate-800/10 rounded-[3rem]">
                <div className="w-20 h-20 bg-slate-800/5 text-slate-400 rounded-full flex items-center justify-center mx-auto mb-6 text-2xl">
                  <i className="fa-solid fa-cloud-sun"></i>
                </div>
                <h4 className={`text-xl font-bold ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>Orbit is clear.</h4>
                <p className="text-slate-600 font-bold text-xs mt-2 uppercase tracking-widest">Add a session task to start the monitor.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

