  // Alarm States
  const [taskAlarm, setTaskAlarm] = useState<Reminder | null>(null);
  const [triggeredIds, setTriggeredIds] = useState<Set<string>>(new Set());
  const [notifying, setNotifying] = useState(false);

  // Initialize Audio Sources
  useEffect(() => {
    // Pomodoro session end (Smooth)
    sessionAudioRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3');
    // Task Due Time Alarm (Sharp/Urgent)
    taskBellRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/1070/1070-preview.mp3');
    taskBellRef.current.loop = true;
    // Manual Task Completion (Satisfying)
    completionChimeRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/1110/1110-preview.mp3');
  }, []);

  // 1. Pomodoro Logic
  useEffect(() => {
    let interval: any = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && isActive) {
      handleSessionComplete();
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  // 2. Task Deadline Monitor Logic
  useEffect(() => {
    const monitor = setInterval(() => {
      const now = new Date();
      const nowH = now.getHours();
      const nowM = now.getMinutes();

      reminders.forEach(rem => {
        if (rem.completed || triggeredIds.has(rem.id)) return;

        // Enhanced Parsing
        const raw = rem.time.toUpperCase().trim();
        let targetH = -1, targetM = -1;

        try {
          const isPM = raw.includes('PM');
          const isAM = raw.includes('AM');
          const timeParts = raw.replace('AM', '').replace('PM', '').trim().split(':');

          let h = parseInt(timeParts[0]);
          let m = parseInt(timeParts[1] || '0');

          if (isPM && h < 12) h += 12;
          if (isAM && h === 12) h = 0;

          targetH = h;
          targetM = m;

          if (nowH === targetH && nowM === targetM) {
            triggerTaskAlarm(rem);
          }
        } catch (e) { /* silent parse error */ }
      });
    }, 5000); // Check every 5 seconds

    return () => clearInterval(monitor);
  }, [reminders, triggeredIds]);

  const triggerTaskAlarm = (rem: Reminder) => {
    setTaskAlarm(rem);
    setTriggeredIds(prev => new Set(prev).add(rem.id));
    if (taskBellRef.current) {
      taskBellRef.current.play().catch(console.error);
    }
  };

  const handleToggleTask = (id: string) => {
    const task = reminders.find(r => r.id === id);
    if (task && !task.completed) {
      // If we are marking it as completed, play the satisfying chime
      if (completionChimeRef.current) {
        completionChimeRef.current.currentTime = 0;
        completionChimeRef.current.play().catch(console.error);
      }
    }
    onToggleReminder(id);
  };

  const dismissAlarm = (markComplete: boolean) => {
    if (taskAlarm && markComplete) {
      handleToggleTask(taskAlarm.id);
    }
    if (taskBellRef.current) {
      taskBellRef.current.pause();
      taskBellRef.current.currentTime = 0;
    }
    setTaskAlarm(null);
  };

  const handleSessionComplete = () => {
    setIsActive(false);
    setNotifying(true);
    if (sessionAudioRef.current) {
      sessionAudioRef.current.currentTime = 0;
      sessionAudioRef.current.play().catch(console.error);
    }
    setTimeout(() => {
      setNotifying(false);
      const nextMode = mode === 'Work' ? 'Break' : 'Work';
      const nextTime = nextMode === 'Work' ? workDuration : breakDuration;
      setMode(nextMode);
      setTimeLeft(nextTime * 60);
    }, 3000);
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const updateWorkDuration = (val: number) => {
    setWorkDuration(val);
    if (!isActive && mode === 'Work') setTimeLeft(val * 60);
  };

  const updateBreakDuration = (val: number) => {
    setBreakDuration(val);
    if (!isActive && mode === 'Break') setTimeLeft(val * 60);
  };

  // UI Constants
  const radius = 110;
  const circ = 2 * Math.PI * radius;
  const totalSec = mode === 'Work' ? workDuration * 60 : breakDuration * 60;
  const progress = (timeLeft / totalSec) * circ;

  return (
    <div className="space-y-12 animate-fadeIn pb-20 relative">

      {/* TASK ALARM OVERLAY */}
      {taskAlarm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 backdrop-blur-3xl bg-[#0D1B2A]/90 animate-fadeIn">
          <div className="card-premium max-w-lg w-full p-12 rounded-[4rem] text-center shadow-[0_0_120px_rgba(76,201,240,0.4)] border-2 border-[#4CC9F0]/40">
            <div className="w-32 h-32 bg-[#4CC9F0] text-[#0D1B2A] rounded-full flex items-center justify-center text-5xl mx-auto mb-10 animate-bounce shadow-2xl shadow-[#4CC9F0]/60">
              <i className="fa-solid fa-bell"></i>
            </div>
            <p className="text-[#4CC9F0] font-black uppercase tracking-[0.5em] text-[10px] mb-4">Urgent Task Alert</p>
            <h3 className={`text-4xl font-black mb-4 ${isDark ? 'text-white' : 'text-slate-900'}`}>{taskAlarm.task}</h3>
            <p className="text-slate-500 font-bold mb-12">Scheduled for {taskAlarm.time}</p>

            <div className="grid grid-cols-1 gap-4">
              <button 
                onClick={() => dismissAlarm(true)}
                className="py-6 bg-[#4CC9F0] text-[#0D1B2A] rounded-[2.5rem] font-black uppercase text-xs tracking-[0.2em] shadow-xl hover:scale-[1.03] transition-all"
              >
                Mark as Done & Stop Ringing
              </button>
              <button 
                onClick={() => dismissAlarm(false)}
                className="py-6 bg-slate-800 text-white rounded-[2.5rem] font-black uppercase text-xs tracking-[0.2em] hover:bg-slate-700 transition-all"
              >
                Acknowledge Alert
              </button>
            </div>
          </div>
        </div>
      )}

      <header className="flex justify-between items-start">
        <div>
          <h2 className={`text-3xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Spatial <span className="text-[#4CC9F0]">Planner</span></h2>
          <p className="text-slate-500 font-bold text-sm mt-1">Strategic focus for elite performance.</p>
        </div>
        <button 
          onClick={() => setShowSettings(!showSettings)}
          className={`p-4 rounded-2xl border transition-all ${showSettings ? 'bg-[#4CC9F0] text-[#0D1B2A] border-[#4CC9F0]' : 'bg-slate-800/10 text-slate-500 border-slate-700/20'}`}
        >
          <i className={`fa-solid ${showSettings ? 'fa-xmark' : 'fa-gear'} text-lg`}></i>
        </button>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        {/* The Chronos Orb (Pomodoro) */}
        <div className={`lg:col-span-5 p-1 rounded-[4rem] relative overflow-hidden flex flex-col items-center justify-center min-h-[550px] transition-all duration-700 ${isDark ? 'bg-slate-900/40' : 'bg-white shadow-2xl'}`}>
          <div className={`absolute w-full h-full blur-[120px] opacity-20 transition-all duration-1000 ${notifying ? 'bg-red-500' : mode === 'Work' ? 'bg-[#4CC9F0]' : 'bg-[#4CAF50]'} ${isActive ? 'animate-pulse' : ''}`}></div>

          {showSettings && (
            <div className="absolute inset-0 z-20 backdrop-blur-2xl bg-slate-900/90 p-12 flex flex-col items-center justify-center animate-fadeIn">
              <h3 className="text-white font-black uppercase tracking-[0.5em] text-[10px] mb-12 text-[#4CC9F0]">Timing Parameters</h3>
              <div className="w-full space-y-10">
                <div className="space-y-4">
                  <div className="flex justify-between text-[10px] font-black uppercase text-slate-400 tracking-widest px-2">
                    <span>Work Block</span>
                    <span className="text-white">{workDuration} Minutes</span>
                  </div>
                  <input type="range" min="1" max="120" value={workDuration} onChange={e => updateWorkDuration(parseInt(e.target.value))} className="w-full accent-[#4CC9F0]" />
                </div>
                <div className="space-y-4">
                  <div className="flex justify-between text-[10px] font-black uppercase text-slate-400 tracking-widest px-2">
                    <span>Break Interval</span>
                    <span className="text-white">{breakDuration} Minutes</span>
                  </div>
                  <input type="range" min="1" max="60" value={breakDuration} onChange={e => updateBreakDuration(parseInt(e.target.value))} className="w-full accent-[#4CAF50]" />
                </div>
              </div>
              <button onClick={() => setShowSettings(false)} className="mt-12 px-12 py-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-[2rem] font-black uppercase text-[10px] tracking-widest">Apply To Orb</button>
            </div>
          )}

          <div className="z-10 mb-8 px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.3em] bg-white/5 border border-white/10 text-[#4CC9F0]">
            {mode} Mode
          </div>

          <div className="relative w-80 h-80 flex items-center justify-center">
            <svg className="absolute w-full h-full -rotate-90">
              <circle cx="160" cy="160" r={radius} stroke="rgba(255,255,255,0.05)" strokeWidth="4" fill="none" />
              <circle cx="160" cy="160" r={radius} stroke={mode === 'Work' ? '#4CC9F0' : '#4CAF50'} strokeWidth="6" fill="none" strokeDasharray={circ} strokeDashoffset={circ - progress} className="transition-all duration-1000 ease-linear" strokeLinecap="round" />
            </svg>
            <div className={`relative w-64 h-64 rounded-full flex flex-col items-center justify-center backdrop-blur-3xl shadow-2xl ${isDark ? 'bg-slate-800/80 border border-white/5' : 'bg-white border border-slate-100'}`}>
              <span className="text-[10px] font-black uppercase tracking-[0.5em] mb-2 opacity-40">{isActive ? 'Flowing' : 'Standby'}</span>
              <p className={`text-7xl font-light tracking-tighter ${isDark ? 'text-white' : 'text-slate-900'}`}>{formatTime(timeLeft)}</p>
            </div>
          </div>

          <div className="mt-12 flex items-center gap-6 z-10">
            <button onClick={() => {setIsActive(false); setTimeLeft(mode === 'Work' ? workDuration * 60 : breakDuration * 60);}} className="w-14 h-14 rounded-full bg-slate-800/50 text-slate-400 hover:text-white transition-all"><i className="fa-solid fa-rotate-right"></i></button>
            <button onClick={() => setIsActive(!isActive)} className={`w-24 h-24 rounded-full flex items-center justify-center text-3xl shadow-2xl transition-all ${mode === 'Work' ? 'bg-[#4CC9F0] text-[#0D1B2A]' : 'bg-[#4CAF50] text-[#0D1B2A]'}`}>
              <i className={`fa-solid ${isActive ? 'fa-pause' : 'fa-play'}`}></i>
            </button>
            <button onClick={() => {const nm = mode === 'Work' ? 'Break' : 'Work'; setMode(nm); setTimeLeft(nm === 'Work' ? workDuration : breakDuration); setIsActive(false);}} className="w-14 h-14 rounded-full bg-slate-800/50 text-slate-400 hover:text-white transition-all"><i className="fa-solid fa-forward-step"></i></button>
          </div>
        </div>

        {/* Task List Board */}
        <div className="lg:col-span-7 card-premium p-12 rounded-[4rem] relative overflow-hidden">
          <div className="flex justify-between items-center mb-12">
            <h3 className={`text-xl font-black ${isDark ? 'text-white' : 'text-slate-800'}`}>Session Tasks</h3>
            <button onClick={() => setShowAddForm(!showAddForm)} className="px-6 py-3 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-2xl text-[10px] font-black uppercase tracking-widest border border-[#4CC9F0]/20">{showAddForm ? 'Cancel' : '+ New Task'}</button>
          </div>

          {showAddForm && (
            <form onSubmit={e => {e.preventDefault(); if(newTaskName && newTaskTime) {onAddReminder(newTaskName, newTaskTime, 'Study'); setNewTaskName(''); setNewTaskTime(''); setShowAddForm(false);}}} className="p-8 rounded-[3rem] bg-slate-800/20 border border-slate-700/50 mb-10 animate-slideDown">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                <input className="bg-slate-900/50 border border-slate-700 p-5 rounded-2xl text-sm font-bold text-white outline-none" placeholder="Task Name" value={newTaskName} onChange={e => setNewTaskName(e.target.value)} />
