              </div>
              <button type="submit" className="w-full py-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl font-black uppercase text-[10px] tracking-widest">Deploy Objective</button>
            </form>
          )}

          <div className="space-y-4 max-h-[500px] overflow-y-auto pr-4 custom-scrollbar">
            {reminders.map(rem => (
              <div key={rem.id} className={`p-8 rounded-[3rem] border flex items-center gap-8 transition-all group ${isDark ? 'bg-slate-900/40 border-slate-800' : 'bg-white border-slate-100 shadow-sm'}`}>
                <button onClick={() => handleToggleTask(rem.id)} className={`w-14 h-14 rounded-[2rem] flex items-center justify-center border-2 transition-all ${rem.completed ? 'bg-[#4CAF50] border-[#4CAF50] text-[#0D1B2A]' : 'border-slate-700 text-transparent'}`}><i className="fa-solid fa-check"></i></button>
                <div className="flex-1">
                  <p className={`text-xl font-bold ${rem.completed ? 'line-through opacity-30' : isDark ? 'text-white' : 'text-slate-900'}`}>{rem.task}</p>
                  <div className="flex items-center gap-4 mt-2">
                    <span className={`text-[10px] font-black uppercase tracking-widest flex items-center gap-2 ${triggeredIds.has(rem.id) && !rem.completed ? 'text-red-500' : 'text-slate-500'}`}>
                      <i className={`fa-solid ${triggeredIds.has(rem.id) && !rem.completed ? 'fa-bell animate-swing' : 'fa-clock text-[#4CC9F0]'}`}></i> {rem.time}
                    </span>
                    {triggeredIds.has(rem.id) && !rem.completed && <span className="text-[8px] bg-red-500/20 text-red-500 px-2 py-0.5 rounded-md font-black uppercase tracking-tighter">TIME UP</span>}
                  </div>
                </div>
                <button onClick={() => onDeleteReminder(rem.id)} className="w-10 h-10 bg-red-500/10 text-red-500 rounded-xl opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center hover:bg-red-50 hover:text-white"><i className="fa-solid fa-trash-can text-sm"></i></button>
              </div>
            ))}
            {reminders.length === 0 && <div className="py-24 text-center opacity-30 text-2xl font-black tracking-tighter">ORBIT_CLEAR.SYS</div>}
          </div>
        </div>
      </div>
    </div>
  );
};

