            isDark ? 'border-slate-800 bg-slate-900/50 text-slate-500' : 'border-slate-100 bg-slate-50 text-slate-400'
          }`}
        >
          <span className="hidden lg:block">{isDark ? 'Dark' : 'Light'}</span>
          <i className={`fa-solid ${isDark ? 'fa-moon text-[#4CC9F0]' : 'fa-sun text-amber-500'}`}></i>
        </button>

        <button 
          onClick={onLogout}
          className={`w-full flex items-center justify-center lg:justify-start gap-4 p-4 rounded-3xl text-red-400 hover:bg-red-500/10 font-bold text-xs uppercase tracking-widest transition-colors`}
        >
          <i className="fa-solid fa-right-from-bracket lg:w-6"></i>
          <span className="hidden lg:block">Exit Orbit</span>
        </button>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { Subject, ThemeMode, TestQuestion, MockTestResult } from '../types';
import { generateMockTest } from '../services/geminiService';

interface MockTestProps {
  subjects: Subject[];
  theme: ThemeMode;
}

const MockTest: React.FC<MockTestProps> = ({ subjects, theme }) => {
  const isDark = theme === 'dark';
  const [phase, setPhase] = useState<'setup' | 'loading' | 'taking' | 'result'>('setup');

  // Setup state
  const [selectedSubjectId, setSelectedSubjectId] = useState<string>('');
  const [selectedTopics, setSelectedTopics] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState<number>(10);

  // Taking state
  const [questions, setQuestions] = useState<TestQuestion[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [userAnswers, setUserAnswers] = useState<number[]>([]);

  // Result state
  const [testResult, setTestResult] = useState<MockTestResult | null>(null);

  const startTest = async () => {
    const subject = subjects.find(s => s.id === selectedSubjectId);
    if (!subject) return;

    setPhase('loading');
    try {
      const topics = selectedTopics.length > 0 
        ? selectedTopics 
        : subject.topics.map(t => t.name);

      const generatedQuestions = await generateMockTest(subject.name, topics, questionCount);
      setQuestions(generatedQuestions);
      setUserAnswers(new Array(generatedQuestions.length).fill(-1));
      setCurrentQuestionIndex(0);
      setPhase('taking');
    } catch (err) {
      alert(err instanceof Error ? err.message : "Satellite connection failed.");
      setPhase('setup');
    }
  };

  const handleAnswer = (optionIndex: number) => {
    const updated = [...userAnswers];
    updated[currentQuestionIndex] = optionIndex;
    setUserAnswers(updated);
  };

  const nextQuestion = () => {
    if (currentQuestionIndex < questions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      finishTest();
    }
  };

  const finishTest = () => {
    let score = 0;
    questions.forEach((q, i) => {
      if (q.correctAnswerIndex === userAnswers[i]) score++;
    });

    setTestResult({
      score,
      total: questions.length,
      questions,
      userAnswers,
      timestamp: Date.now()
    });
    setPhase('result');
  };

  const resetTest = () => {
    setPhase('setup');
    setQuestions([]);
    setUserAnswers([]);
    setTestResult(null);
  };

  if (phase === 'loading') {
    return (
      <div className="h-full flex flex-col items-center justify-center p-20 animate-fadeIn">
        <div className="w-24 h-24 bg-[#4CC9F0]/10 rounded-full flex items-center justify-center mb-10 relative">
          <div className="absolute inset-0 border-4 border-[#4CC9F0] border-t-transparent rounded-full animate-spin"></div>
          <i className="fa-solid fa-satellite text-[#4CC9F0] text-3xl"></i>
        </div>
        <h3 className={`text-2xl font-black mb-4 ${isDark ? 'text-white' : 'text-slate-900'}`}>Generating Intelligence Probe</h3>
        <p className="text-slate-500 font-bold text-center max-w-sm">Orbit AI is constructing a custom testing environment for your selected parameters.</p>
      </div>
    );
  }

  if (phase === 'taking') {
    const q = questions[currentQuestionIndex];
    const progress = ((currentQuestionIndex + 1) / questions.length) * 100;

    return (
      <div className="max-w-4xl mx-auto space-y-10 animate-fadeIn pb-20">
        <div className="flex justify-between items-center">
          <div className="space-y-1">
            <h3 className={`text-sm font-black uppercase tracking-widest text-[#4CC9F0]`}>Question {currentQuestionIndex + 1} / {questions.length}</h3>
            <p className="text-slate-500 text-xs font-bold">In-Orbit Evaluation</p>
          </div>
          <button onClick={finishTest} className="text-red-400 font-black text-[10px] uppercase tracking-widest hover:text-red-500 transition-colors">Abort Mission</button>
        </div>

        <div className={`w-full h-1.5 rounded-full overflow-hidden ${isDark ? 'bg-slate-800' : 'bg-slate-100'}`}>
          <div className="h-full bg-[#4CC9F0] transition-all duration-500" style={{ width: `${progress}%` }}></div>
        </div>

        <div className={`p-12 rounded-[3.5rem] card-premium border ${isDark ? 'border-slate-800 shadow-2xl' : 'border-slate-100 shadow-xl'}`}>
          <p className={`text-2xl font-black mb-12 leading-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>{q.question}</p>

          <div className="grid grid-cols-1 gap-4">
            {q.options.map((opt, idx) => (
              <button
                key={idx}
                onClick={() => handleAnswer(idx)}
                className={`w-full text-left p-6 rounded-3xl border-2 transition-all font-bold group flex items-center gap-6 ${
                  userAnswers[currentQuestionIndex] === idx
                    ? 'bg-[#4CC9F0]/10 border-[#4CC9F0] text-[#4CC9F0]'
                    : isDark 
                      ? 'border-slate-800 hover:border-slate-600 text-slate-300' 
                      : 'border-slate-100 hover:border-blue-200 text-slate-700'
                }`}
              >
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-all ${
                  userAnswers[currentQuestionIndex] === idx ? 'bg-[#4CC9F0] text-[#0D1B2A]' : 'bg-slate-800/20 text-slate-500 group-hover:bg-slate-800/40'
                }`}>
                  {String.fromCharCode(65 + idx)}
                </div>
                {opt}
              </button>
            ))}
          </div>
        </div>

        <div className="flex justify-end gap-6 pt-6">
           <button 
             onClick={nextQuestion}
             disabled={userAnswers[currentQuestionIndex] === -1}
             className="px-12 py-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl font-black uppercase text-xs tracking-widest shadow-2xl shadow-[#4CC9F0]/20 disabled:opacity-30 disabled:scale-100 hover:scale-105 active:scale-95 transition-all"
           >
             {currentQuestionIndex === questions.length - 1 ? 'Finish Test' : 'Next Objective'}
           </button>
        </div>
      </div>
    );
  }

  if (phase === 'result' && testResult) {
    const percentage = Math.round((testResult.score / testResult.total) * 100);
    return (
      <div className="max-w-5xl mx-auto space-y-12 animate-fadeIn pb-24">
        <header className="text-center space-y-4">
           <h3 className="text-[#4CC9F0] font-black uppercase tracking-[0.4em] text-xs">Mission Report</h3>
           <h2 className={`text-5xl font-black tracking-tighter ${isDark ? 'text-white' : 'text-slate-900'}`}>Mission {percentage >= 50 ? 'Successful' : 'Incomplete'}</h2>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
           <div className="card-premium p-10 rounded-[3rem] text-center">
              <p className="text-slate-500 font-black uppercase text-[10px] tracking-widest mb-4">Accuracy</p>
              <p className={`text-6xl font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>{percentage}%</p>
           </div>
           <div className="card-premium p-10 rounded-[3rem] text-center">
              <p className="text-slate-500 font-black uppercase text-[10px] tracking-widest mb-4">Score</p>
              <p className={`text-6xl font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>{testResult.score}/{testResult.total}</p>
           </div>
           <div className="card-premium p-10 rounded-[3rem] flex flex-col justify-center items-center">
              <button 
                onClick={resetTest}
                className="w-full py-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl font-black uppercase text-[10px] tracking-widest"
              >
                Launch New Mission
              </button>
           </div>
        </div>

        <div className="space-y-8">
           <h3 className={`text-xl font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>Detailed Debriefing</h3>
           {testResult.questions.map((q, idx) => {
             const isCorrect = testResult.userAnswers[idx] === q.correctAnswerIndex;
             return (
               <div key={idx} className={`p-10 rounded-[3rem] border-2 transition-all ${isDark ? 'bg-slate-900/40 border-slate-800' : 'bg-white border-slate-100 shadow-sm'}`}>
                 <div className="flex justify-between items-start mb-6">
                    <p className={`text-lg font-bold flex-1 ${isDark ? 'text-white' : 'text-slate-900'}`}>{idx + 1}. {q.question}</p>
                    <div className={`px-4 py-1.5 rounded-full font-black text-[9px] uppercase tracking-widest ${isCorrect ? 'bg-[#4CAF50]/10 text-[#4CAF50]' : 'bg-red-500/10 text-red-500'}`}>
                      {isCorrect ? 'Correct' : 'Critical Failure'}
                    </div>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
                    {q.options.map((opt, oIdx) => (
                      <div 
                        key={oIdx}
                        className={`p-4 rounded-2xl text-sm font-bold border-2 ${
                          oIdx === q.correctAnswerIndex 
                            ? 'bg-[#4CAF50]/10 border-[#4CAF50] text-[#4CAF50]' 
                            : oIdx === testResult.userAnswers[idx] && !isCorrect 
                              ? 'bg-red-500/10 border-red-500 text-red-500'
                              : isDark ? 'bg-slate-800/50 border-transparent text-slate-500' : 'bg-slate-50 border-transparent text-slate-400'
                        }`}
                      >
                        {String.fromCharCode(65 + oIdx)}. {opt}
                      </div>
                    ))}
                 </div>

                 <div className={`p-8 rounded-[2rem] border ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
                    <p className="text-[#4CC9F0] font-black uppercase text-[10px] tracking-[0.2em] mb-4">AI Explanatory Core</p>
                    <p className={`text-sm leading-relaxed ${isDark ? 'text-slate-400' : 'text-slate-600'}`}>{q.explanation}</p>
                 </div>
               </div>
             );
           })}
        </div>
      </div>
    );
  }

  // Setup Phase
  return (
    <div className="space-y-12 animate-fadeIn pb-24 max-w-5xl mx-auto">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Mock <span className="text-[#4CC9F0]">Test</span></h2>
          <p className="text-slate-500 font-bold text-sm mt-1">Simulated orbital stress-tests for academic readiness.</p>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 space-y-10">
          <div className="card-premium p-10 rounded-[3.5rem] space-y-10">
            <div>
              <h3 className={`text-lg font-black mb-6 ${isDark ? 'text-white' : 'text-slate-900'}`}>1. Target Subject</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {subjects.map(s => (
                  <button
                    key={s.id}
                    onClick={() => { setSelectedSubjectId(s.id); setSelectedTopics([]); }}
                    className={`p-6 rounded-3xl border-2 text-left font-bold transition-all ${
                      selectedSubjectId === s.id 
                        ? 'bg-[#4CC9F0]/10 border-[#4CC9F0] text-[#4CC9F0]' 
                        : isDark ? 'border-slate-800 text-slate-500 hover:border-slate-700' : 'border-slate-100 text-slate-400 hover:border-slate-200 shadow-sm'
                    }`}
                  >
                    {s.name}
                  </button>
                ))}
              </div>
            </div>

            {selectedSubjectId && (
              <div className="animate-slideUp">
                <div className="flex justify-between items-center mb-6">
                  <h3 className={`text-lg font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>2. Module Focus</h3>
                  <button 
                    onClick={() => setSelectedTopics([])}
                    className="text-[10px] font-black uppercase tracking-widest text-[#4CC9F0]"
                  >
                    Full Syllabus
                  </button>
                </div>
                <div className="flex flex-wrap gap-3">
                  {subjects.find(s => s.id === selectedSubjectId)?.topics.map(t => (
                    <button
                      key={t.id}
                      onClick={() => {
                        if (selectedTopics.includes(t.name)) {
                          setSelectedTopics(prev => prev.filter(x => x !== t.name));
                        } else {
                          setSelectedTopics(prev => [...prev, t.name]);
                        }
                      }}
                      className={`px-6 py-3 rounded-2xl border-2 text-[10px] font-black uppercase tracking-widest transition-all ${
                        selectedTopics.includes(t.name)
                          ? 'bg-[#4CC9F0] text-[#0D1B2A] border-[#4CC9F0]'
                          : isDark ? 'border-slate-800 text-slate-500' : 'border-slate-100 text-slate-400'
                      }`}
                    >
                      {t.name}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="space-y-10">
          <div className="card-premium p-10 rounded-[3.5rem] space-y-8">
            <h3 className={`text-lg font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>Mission Setup</h3>

            <div className="space-y-4">
              <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-slate-500">
                <span>Intensity</span>
                <span className="text-[#4CC9F0]">{questionCount} Qs</span>
              </div>
              <input 
                type="range" min="5" max="25" step="5" value={questionCount} 
                onChange={e => setQuestionCount(parseInt(e.target.value))}
                className="w-full accent-[#4CC9F0] h-1.5 bg-slate-800 rounded-full appearance-none cursor-pointer"
              />
            </div>

            <div className="pt-8">
              <button
                disabled={!selectedSubjectId}
                onClick={startTest}
                className="w-full py-6 bg-[#4CC9F0] text-[#0D1B2A] rounded-[2.5rem] font-black uppercase text-xs tracking-[0.2em] shadow-2xl shadow-[#4CC9F0]/20 disabled:opacity-30 disabled:scale-100 hover:scale-[1.03] active:scale-95 transition-all"
              >
                Initiate Test
              </button>
            </div>
          </div>

          <div className={`p-8 rounded-[3rem] border flex items-center gap-6 ${isDark ? 'bg-slate-900/40 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
             <div className="w-12 h-12 rounded-2xl bg-[#4CC9F0]/10 flex items-center justify-center text-[#4CC9F0]">
               <i className="fa-solid fa-wand-magic-sparkles"></i>
             </div>
             <p className="text-[10px] font-bold text-slate-500 uppercase leading-relaxed tracking-wider">Orbit AI will generate unique questions with detailed feedback for every incorrect answer.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MockTest;

import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import AITutor from './components/AITutor';
import SyllabusTracker from './components/SyllabusTracker';
import NotesManager from './components/NotesManager';
import LandingPage from './components/LandingPage';
import StudyPlanner from './components/StudyPlanner';
import DeepDive from './components/DeepDive';
import MockTest from './components/MockTest';
import { Subject, Note, Doubt, Reminder, ThemeMode, Badge, Message } from './types';
import { INITIAL_SYLLABUS, INITIAL_BADGES, INITIAL_CHAT_MESSAGES, APP_MODES } from './constants';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<string>(APP_MODES.LANDING);
  const [theme, setTheme] = useState<ThemeMode>(() => (localStorage.getItem('mindorbit_theme') as ThemeMode) || 'dark');

  const [subjects, setSubjects] = useState<Subject[]>(() => {
    const saved = localStorage.getItem('mindorbit_syllabus_v3');
    return saved ? JSON.parse(saved) : INITIAL_SYLLABUS;
  });
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('mindorbit_notes');
    return saved ? JSON.parse(saved) : [];
  });
  const [doubts, setDoubts] = useState<Doubt[]>(() => {
    const saved = localStorage.getItem('mindorbit_doubts');
    return saved ? JSON.parse(saved) : [];
  });
  const [reminders, setReminders] = useState<Reminder[]>(() => {
    const saved = localStorage.getItem('mindorbit_reminders');
    return saved ? JSON.parse(saved) : [];
  });
  const [badges, setBadges] = useState<Badge[]>(() => {
    const saved = localStorage.getItem('mindorbit_badges');
    return saved ? JSON.parse(saved) : INITIAL_BADGES;
  });
  const [chatHistory, setChatHistory] = useState<Message[]>(() => {
    const saved = localStorage.getItem('mindorbit_chat_v1');
    return saved ? JSON.parse(saved) : INITIAL_CHAT_MESSAGES;
  });

  useEffect(() => {
    if (activeMode !== APP_MODES.LANDING) {
      localStorage.setItem('mindorbit_syllabus_v3', JSON.stringify(subjects));
      localStorage.setItem('mindorbit_notes', JSON.stringify(notes));
      localStorage.setItem('mindorbit_doubts', JSON.stringify(doubts));
      localStorage.setItem('mindorbit_reminders', JSON.stringify(reminders));
      localStorage.setItem('mindorbit_badges', JSON.stringify(badges));
      localStorage.setItem('mindorbit_chat_v1', JSON.stringify(chatHistory));
      localStorage.setItem('mindorbit_theme', theme);
    }
    document.body.className = theme;
  }, [subjects, notes, doubts, reminders, badges, chatHistory, theme, activeMode]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const handleAuthSuccess = useCallback(() => {
    console.log("Resetting application state to defaults...");
    localStorage.removeItem('mindorbit_syllabus_v3');
    localStorage.removeItem('mindorbit_notes');
    localStorage.removeItem('mindorbit_doubts');
    localStorage.removeItem('mindorbit_reminders');
    localStorage.removeItem('mindorbit_badges');
    localStorage.removeItem('mindorbit_chat_v1');

    setSubjects(JSON.parse(JSON.stringify(INITIAL_SYLLABUS)));
    setNotes([]);
    setDoubts([]);
    setReminders([]);
    setBadges(JSON.parse(JSON.stringify(INITIAL_BADGES)));
    setChatHistory(JSON.parse(JSON.stringify(INITIAL_CHAT_MESSAGES)));

    setActiveMode(APP_MODES.DASHBOARD);
  }, []);

  const handleToggleTopic = (subjectId: string, topicId: string) => {
    setSubjects(prev => prev.map(s => s.id === subjectId ? { ...s, topics: s.topics.map(t => t.id === topicId ? { ...t, completed: !t.completed } : t) } : s));
  };

  const handleAddSubject = (name: string, classLevel: string) => {
    const newSubject: Subject = {
      id: `subj-${Math.random().toString(36).substr(2, 5)}`,
      name,
      classLevel,
      topics: [
        { id: `topic-${Math.random()}`, name: 'Introductory Chapter', completed: false, revisionStatus: 'Not Started' }
      ]
    };
    setSubjects(prev => [...prev, newSubject]);
  };

  const handleAddNote = (newNoteData: Omit<Note, 'id' | 'timestamp'>) => {
    setNotes(prev => [{ ...newNoteData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now() }, ...prev]);
  };

  const handleDeleteNote = (id: string) => setNotes(prev => prev.filter(n => n.id !== id));

  const handleSaveDoubt = (doubtData: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => {
    setDoubts(prev => [{ ...doubtData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now(), resolved: false }, ...prev]);
  };

  const handleAddReminder = (task: string, time: string, type: Reminder['type'] = 'Study') => {
    setReminders(prev => [...prev, { id: Math.random().toString(36).substr(2, 9), task, time, completed: false, type }]);
  };

  const toggleReminder = (id: string) => setReminders(prev => prev.map(r => r.id === id ? { ...r, completed: !r.completed } : r));
  const deleteReminder = (id: string) => setReminders(prev => prev.filter(r => r.id !== id));

  const renderContent = () => {
    const isDark = theme === 'dark';
    switch (activeMode) {
      case APP_MODES.DASHBOARD:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} badges={badges} />;
      case APP_MODES.CHAT:
        return <AITutor messages={chatHistory} setMessages={setChatHistory} notes={notes} onSaveDoubt={handleSaveDoubt} theme={theme} />;
      case APP_MODES.PLANNER:
        return <StudyPlanner reminders={reminders} onAddReminder={handleAddReminder} onToggleReminder={toggleReminder} onDeleteReminder={deleteReminder} theme={theme} />;
      case APP_MODES.SYLLABUS:
        return <SyllabusTracker subjects={subjects} onToggleTopic={handleToggleTopic} onAddSubject={handleAddSubject} theme={theme} />;
      case APP_MODES.NOTES:
        return <NotesManager notes={notes} onAddNote={handleAddNote} onDeleteNote={handleDeleteNote} />;
      case APP_MODES.DEEP_DIVE:
        return <DeepDive theme={theme} />;
      case APP_MODES.MOCK_TEST:
        return <MockTest subjects={subjects} theme={theme} />;
      case APP_MODES.DOUBTS:
        return (
          <div className="space-y-10 animate-fadeIn">
            <header>
              <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>The <span className="text-[#4CC9F0]">Vault</span></h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Permanently archived intelligence blocks.</p>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {doubts.map(doubt => (
                <div key={doubt.id} className={`p-10 rounded-[3rem] border transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
                  <div className="flex justify-between items-center mb-8">
                    <span className="text-[10px] px-4 py-1.5 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-full font-black uppercase tracking-widest border border-[#4CC9F0]/20">Doubt #{doubt.id.substring(0,3)}</span>
                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{doubt.subject}</span>
                  </div>
                  <p className={`text-xl font-bold mb-8 leading-tight ${isDark ? 'text-white' : 'text-slate-950'}`}>{doubt.question}</p>
                  <div className={`p-8 rounded-[2rem] italic text-sm leading-relaxed border ${isDark ? 'bg-[#0D1B2A] border-slate-800 text-slate-400' : 'bg-slate-50 border-slate-100 text-slate-600'}`}>
                    {doubt.answer}
                  </div>
                </div>
              ))}
              {doubts.length === 0 && <div className="col-span-full py-32 text-center opacity-30 italic font-black text-2xl tracking-tighter">VAULT_EMPTY.SYS</div>}
            </div>
          </div>
        );
      default:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} badges={badges} />;
    }
  };

  if (activeMode === APP_MODES.LANDING) {
    return <LandingPage onStart={handleAuthSuccess} theme={theme} />;
  }

  return (
    <div className={`flex min-h-screen transition-colors duration-500 ${theme === 'dark' ? 'bg-[#0D1B2A]' : 'bg-slate-50'}`}>
      <Sidebar 
        activeMode={activeMode} 
        setActiveMode={setActiveMode} 
        theme={theme} 
        toggleTheme={toggleTheme} 
        onLogout={() => setActiveMode(APP_MODES.LANDING)}
      />
      <main className="flex-1 ml-24 lg:ml-72 p-8 lg:p-16 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

