import React, { useState } from 'react';
import { Subject, ThemeMode, StreamType } from '../types';

interface SyllabusTrackerProps {
  subjects: Subject[];
  onToggleTopic: (subjectId: string, topicId: string) => void;
  onAddSubject: (name: string, classLevel: string) => void;
  theme: ThemeMode;
}

const SyllabusTracker: React.FC<SyllabusTrackerProps> = ({ subjects, onToggleTopic, onAddSubject, theme }) => {
  const isDark = theme === 'dark';
  const [selectedClass, setSelectedClass] = useState<string>('All');
  const [selectedStream, setSelectedStream] = useState<StreamType | 'All'>('All');
  const [isAdding, setIsAdding] = useState(false);
  const [newSubName, setNewSubName] = useState('');
  const [newSubClass, setNewSubClass] = useState('');

  const classes = ['All', ...Array.from(new Set(subjects.map(s => s.classLevel)))].sort();
  const streams: (StreamType | 'All')[] = ['All', 'Science', 'Commerce', 'Humanities', 'General'];

  const filteredSubjects = subjects.filter(s => {
    const classMatch = selectedClass === 'All' || s.classLevel === selectedClass;
    const streamMatch = selectedStream === 'All' || s.stream === selectedStream;
    return classMatch && streamMatch;
  });

  const handleSubmitSubject = (e: React.FormEvent) => {
    e.preventDefault();
    if (newSubName && newSubClass) {
      onAddSubject(newSubName, newSubClass);
      setNewSubName('');
      setNewSubClass('');
      setIsAdding(false);
    }
  };

  const getSubjectIcon = (name: string) => {
    const n = name.toLowerCase();
    if (n.includes('math')) return 'fa-function';
    if (n.includes('phys')) return 'fa-atom';
    if (n.includes('comp') || n.includes('cs')) return 'fa-code';
    if (n.includes('bio')) return 'fa-dna';
    if (n.includes('hist') || n.includes('landmark')) return 'fa-landmark';
    if (n.includes('geo')) return 'fa-earth-americas';
    if (n.includes('chem')) return 'fa-flask';
    if (n.includes('acc') || n.includes('account')) return 'fa-scale-balanced';
    if (n.includes('bst') || n.includes('business')) return 'fa-briefcase';
    if (n.includes('eco')) return 'fa-chart-line';
    if (n.includes('pol') || n.includes('ps')) return 'fa-building-columns';
    return 'fa-book-sparkles';
  };

  return (
    <div className="space-y-12 animate-fadeIn pb-24">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className={`text-3xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Syllabus <span className="text-[#4CC9F0]">Orbit</span></h2>
          <p className="text-slate-500 font-bold text-sm mt-1">Strategic roadmap for your chosen academic stream.</p>
        </div>
        <div className="flex flex-wrap gap-4">
          {/* Stream Filter */}
          <div className={`flex p-1 rounded-2xl border ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-sm'}`}>
            {streams.map(stream => (
              <button
                key={stream}
                onClick={() => setSelectedStream(stream)}
                className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${
                  selectedStream === stream 
                    ? 'bg-[#4CC9F0] text-[#0D1B2A]' 
                    : 'text-slate-500 hover:text-[#4CC9F0]'
                }`}
              >
                {stream}
              </button>
            ))}
          </div>

          <select 
            className={`px-6 py-3.5 rounded-3xl border font-bold text-[10px] uppercase tracking-widest outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-900 border-slate-800 text-slate-400' : 'bg-white border-slate-100 text-slate-600 shadow-sm'}`}
            value={selectedClass}
            onChange={(e) => setSelectedClass(e.target.value)}
          >
            {classes.map(c => <option key={c} value={c}>{c}</option>)}
          </select>

          <button 
            onClick={() => setIsAdding(true)}
            className="px-8 py-3.5 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl font-black text-[10px] uppercase tracking-widest shadow-2xl shadow-[#4CC9F0]/30 hover:scale-105 transition-all"
          >
            <i className="fa-solid fa-plus mr-2"></i> Custom Subject
          </button>
        </div>
      </header>

      {isAdding && (
        <div className={`p-10 rounded-[3rem] border animate-slideDown mb-10 ${isDark ? 'bg-slate-900 border-[#4CC9F0]/20' : 'bg-white border-slate-100 shadow-xl'}`}>
           <h3 className={`text-xl font-black mb-8 ${isDark ? 'text-white' : 'text-slate-900'}`}>Subject Configuration</h3>
           <form onSubmit={handleSubmitSubject} className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <input 
                autoFocus
                className={`px-6 py-4 rounded-2xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-slate-50 border-slate-100 text-slate-900 placeholder-slate-400'}`}
                placeholder="Subject Name (e.g. Psychology)"
                value={newSubName}
                onChange={(e) => setNewSubName(e.target.value)}
              />
              <input 
                className={`px-6 py-4 rounded-2xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white placeholder-slate-600' : 'bg-slate-50 border-slate-100 text-slate-900 placeholder-slate-400'}`}
                placeholder="Class Level (e.g. Class 12)"
                value={newSubClass}
                onChange={(e) => setNewSubClass(e.target.value)}
              />
              <div className="md:col-span-2 flex justify-end gap-4 mt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="text-slate-500 font-bold text-xs uppercase">Cancel</button>
                <button type="submit" className="px-10 py-4 bg-[#4CC9F0] text-[#0D1B2A] rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl shadow-[#4CC9F0]/10">
                  Initialize Subject
                </button>
              </div>
           </form>
        </div>
      )}

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-10">
        {filteredSubjects.map((subject) => {
          const completedCount = subject.topics.filter(t => t.completed).length;
          const progress = Math.round((completedCount / subject.topics.length) * 100);

          return (
            <div key={subject.id} className="card-premium rounded-[3.5rem] p-10 group">
              <div className="flex justify-between items-start mb-8">
                <div className="flex items-center gap-6">
                  <div className="w-16 h-16 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-3xl flex items-center justify-center text-3xl shadow-inner border border-[#4CC9F0]/10 transition-transform group-hover:rotate-6">
                    <i className={`fa-solid ${getSubjectIcon(subject.name)}`}></i>
                  </div>
                  <div>
                    <h3 className={`text-2xl font-black tracking-tighter ${isDark ? 'text-white' : 'text-slate-900'}`}>{subject.name}</h3>
                    <div className="flex items-center gap-3 mt-1">
                      <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{subject.classLevel}</p>
                      <div className="w-1 h-1 bg-slate-700 rounded-full"></div>
                      <p className="text-[10px] font-black text-[#4CAF50] uppercase tracking-widest">{subject.stream}</p>
                    </div>
                  </div>
                </div>
                <div className="text-right">
                  <span className="text-4xl font-black text-[#4CC9F0]">{progress}%</span>
                </div>
              </div>

              <div className={`w-full h-2.5 rounded-full mb-10 overflow-hidden ${isDark ? 'bg-slate-800' : 'bg-slate-50'}`}>
                <div 
                  className="bg-[#4CC9F0] h-full rounded-full transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(76,201,240,0.4)]" 
                  style={{ width: `${progress}%` }}
                ></div>
              </div>

              <div className="space-y-4">
                {subject.topics.map((topic) => (
                  <label 
                    key={topic.id} 
                    className={`flex items-center p-5 rounded-[2rem] border transition-all cursor-pointer group/item select-none ${
                      topic.completed 
                        ? (isDark ? 'bg-slate-900/50 border-[#4CC9F0]/20' : 'bg-blue-50/30 border-blue-100/30') 
                        : (isDark ? 'bg-slate-900/10 border-slate-800 hover:border-[#4CC9F0]/40' : 'bg-white border-slate-50 hover:border-blue-200/50')
                    }`}
                  >
                    <div className="relative flex items-center justify-center mr-5">
                       <input
                        type="checkbox"
                        checked={topic.completed}
                        onChange={() => onToggleTopic(subject.id, topic.id)}
                        className="peer w-6 h-6 rounded-xl text-[#4CC9F0] focus:ring-[#4CC9F0] border-slate-300 cursor-pointer transition-all"
                      />
                    </div>
                    <div className="flex-1">
                      <span className={`text-lg font-bold tracking-tight ${topic.completed ? (isDark ? 'text-slate-600 line-through' : 'text-slate-400 line-through') : (isDark ? 'text-slate-300' : 'text-slate-700')}`}>
                        {topic.name}
                      </span>
                      <div className="flex gap-2 mt-2">
                        <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-lg ${topic.revisionStatus === 'Mastered' ? 'bg-[#4CAF50]/10 text-[#4CAF50]' : topic.revisionStatus === 'Partial' ? 'bg-amber-500/10 text-amber-500' : 'bg-slate-500/10 text-slate-500'}`}>
                          {topic.revisionStatus}
                        </span>
                      </div>
                    </div>
                  </label>
                ))}
              </div>
            </div>
          );
        })}
        {filteredSubjects.length === 0 && (
          <div className="col-span-full py-32 text-center opacity-40">
            <i className="fa-solid fa-satellite-dish text-6xl mb-6 text-[#4CC9F0]"></i>
            <h3 className="text-2xl font-black">No Data in this Quadrant</h3>
            <p className="font-bold text-slate-500 mt-2">Try adjusting your filters or adding a custom subject.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default SyllabusTracker;

import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import AITutor from './components/AITutor';
import SyllabusTracker from './components/SyllabusTracker';
import NotesManager from './components/NotesManager';
import LandingPage from './components/LandingPage';
import StudyPlanner from './components/StudyPlanner';
import DeepDive from './components/DeepDive';
import MockTest from './components/MockTest';
import { Subject, Note, Doubt, Reminder, ThemeMode, Badge, Message } from './types';
import { INITIAL_SYLLABUS, INITIAL_BADGES, INITIAL_CHAT_MESSAGES, APP_MODES } from './constants';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<string>(APP_MODES.LANDING);
  const [theme, setTheme] = useState<ThemeMode>(() => (localStorage.getItem('mindorbit_theme') as ThemeMode) || 'dark');

  const [subjects, setSubjects] = useState<Subject[]>(() => {
    const saved = localStorage.getItem('mindorbit_syllabus_v3');
    return saved ? JSON.parse(saved) : INITIAL_SYLLABUS;
  });
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('mindorbit_notes');
    return saved ? JSON.parse(saved) : [];
  });
  const [doubts, setDoubts] = useState<Doubt[]>(() => {
    const saved = localStorage.getItem('mindorbit_doubts');
    return saved ? JSON.parse(saved) : [];
  });
  const [reminders, setReminders] = useState<Reminder[]>(() => {
    const saved = localStorage.getItem('mindorbit_reminders');
    return saved ? JSON.parse(saved) : [];
  });
  const [badges, setBadges] = useState<Badge[]>(() => {
    const saved = localStorage.getItem('mindorbit_badges');
    return saved ? JSON.parse(saved) : INITIAL_BADGES;
  });
  const [chatHistory, setChatHistory] = useState<Message[]>(() => {
    const saved = localStorage.getItem('mindorbit_chat_v1');
    return saved ? JSON.parse(saved) : INITIAL_CHAT_MESSAGES;
  });

  useEffect(() => {
    if (activeMode !== APP_MODES.LANDING) {
      localStorage.setItem('mindorbit_syllabus_v3', JSON.stringify(subjects));
      localStorage.setItem('mindorbit_notes', JSON.stringify(notes));
      localStorage.setItem('mindorbit_doubts', JSON.stringify(doubts));
      localStorage.setItem('mindorbit_reminders', JSON.stringify(reminders));
      localStorage.setItem('mindorbit_badges', JSON.stringify(badges));
      localStorage.setItem('mindorbit_chat_v1', JSON.stringify(chatHistory));
      localStorage.setItem('mindorbit_theme', theme);
    }
    document.body.className = theme;
  }, [subjects, notes, doubts, reminders, badges, chatHistory, theme, activeMode]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const handleAuthSuccess = useCallback(() => {
    console.log("Resetting application state to defaults...");
    localStorage.removeItem('mindorbit_syllabus_v3');
    localStorage.removeItem('mindorbit_notes');
    localStorage.removeItem('mindorbit_doubts');
    localStorage.removeItem('mindorbit_reminders');
    localStorage.removeItem('mindorbit_badges');
    localStorage.removeItem('mindorbit_chat_v1');

    setSubjects(JSON.parse(JSON.stringify(INITIAL_SYLLABUS)));
    setNotes([]);
    setDoubts([]);
    setReminders([]);
    setBadges(JSON.parse(JSON.stringify(INITIAL_BADGES)));
    setChatHistory(JSON.parse(JSON.stringify(INITIAL_CHAT_MESSAGES)));

    setActiveMode(APP_MODES.DASHBOARD);
  }, []);

  const handleToggleTopic = (subjectId: string, topicId: string) => {
    setSubjects(prev => prev.map(s => s.id === subjectId ? { ...s, topics: s.topics.map(t => t.id === topicId ? { ...t, completed: !t.completed } : t) } : s));
  };

  const handleAddSubject = (name: string, classLevel: string) => {
    const newSubject: Subject = {
      id: `subj-${Math.random().toString(36).substr(2, 5)}`,
      name,
      classLevel,
      // Fix: Added missing required 'stream' property. Defaulting to 'General' for custom subjects.
      stream: 'General',
      topics: [
        { id: `topic-${Math.random()}`, name: 'Introductory Chapter', completed: false, revisionStatus: 'Not Started' }
      ]
    };
    setSubjects(prev => [...prev, newSubject]);
  };

  const handleAddNote = (newNoteData: Omit<Note, 'id' | 'timestamp'>) => {
    setNotes(prev => [{ ...newNoteData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now() }, ...prev]);
  };

  const handleDeleteNote = (id: string) => setNotes(prev => prev.filter(n => n.id !== id));

  const handleSaveDoubt = (doubtData: Omit<Doubt, 'id' | 'timestamp' | 'resolved'>) => {
    setDoubts(prev => [{ ...doubtData, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now(), resolved: false }, ...prev]);
  };

  const handleAddReminder = (task: string, time: string, type: Reminder['type'] = 'Study') => {
    setReminders(prev => [...prev, { id: Math.random().toString(36).substr(2, 9), task, time, completed: false, type }]);
  };

  const toggleReminder = (id: string) => setReminders(prev => prev.map(r => r.id === id ? { ...r, completed: !r.completed } : r));
  const deleteReminder = (id: string) => setReminders(prev => prev.filter(r => r.id !== id));

  const renderContent = () => {
    const isDark = theme === 'dark';
    switch (activeMode) {
      case APP_MODES.DASHBOARD:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} badges={badges} />;
      case APP_MODES.CHAT:
        return <AITutor messages={chatHistory} setMessages={setChatHistory} notes={notes} onSaveDoubt={handleSaveDoubt} theme={theme} />;
      case APP_MODES.PLANNER:
        return <StudyPlanner reminders={reminders} onAddReminder={handleAddReminder} onToggleReminder={toggleReminder} onDeleteReminder={deleteReminder} theme={theme} />;
      case APP_MODES.SYLLABUS:
        return <SyllabusTracker subjects={subjects} onToggleTopic={handleToggleTopic} onAddSubject={handleAddSubject} theme={theme} />;
      case APP_MODES.NOTES:
        return <NotesManager notes={notes} onAddNote={handleAddNote} onDeleteNote={handleDeleteNote} />;
      case APP_MODES.DEEP_DIVE:
        return <DeepDive theme={theme} />;
      case APP_MODES.MOCK_TEST:
        return <MockTest subjects={subjects} theme={theme} />;
      case APP_MODES.DOUBTS:
        return (
          <div className="space-y-10 animate-fadeIn">
            <header>
              <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>The <span className="text-[#4CC9F0]">Vault</span></h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-1">Permanently archived intelligence blocks.</p>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {doubts.map(doubt => (
                <div key={doubt.id} className={`p-10 rounded-[3rem] border transition-all ${isDark ? 'bg-[#1B263B] border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
                  <div className="flex justify-between items-center mb-8">
                    <span className="text-[10px] px-4 py-1.5 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-full font-black uppercase tracking-widest border border-[#4CC9F0]/20">Doubt #{doubt.id.substring(0,3)}</span>
                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{doubt.subject}</span>
                  </div>
                  <p className={`text-xl font-bold mb-8 leading-tight ${isDark ? 'text-white' : 'text-slate-950'}`}>{doubt.question}</p>
                  <div className={`p-8 rounded-[2rem] italic text-sm leading-relaxed border ${isDark ? 'bg-[#0D1B2A] border-slate-800 text-slate-400' : 'bg-slate-50 border-slate-100 text-slate-600'}`}>
                    {doubt.answer}
                  </div>
                </div>
              ))}
              {doubts.length === 0 && <div className="col-span-full py-32 text-center opacity-30 italic font-black text-2xl tracking-tighter">VAULT_EMPTY.SYS</div>}
            </div>
          </div>
        );
      default:
        return <Dashboard subjects={subjects} notes={notes} doubts={doubts} theme={theme} badges={badges} />;
    }
  };

  if (activeMode === APP_MODES.LANDING) {
    return <LandingPage onStart={handleAuthSuccess} theme={theme} />;
  }

  return (
    <div className={`flex min-h-screen transition-colors duration-500 ${theme === 'dark' ? 'bg-[#0D1B2A]' : 'bg-slate-50'}`}>
      <Sidebar 
        activeMode={activeMode} 
        setActiveMode={setActiveMode} 
        theme={theme} 
        toggleTheme={toggleTheme} 
        onLogout={() => setActiveMode(APP_MODES.LANDING)}
      />
      <main className="flex-1 ml-24 lg:ml-72 p-8 lg:p-16 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

