  MOCK_TEST: 'mock-test'
} as const;

import React, { useState } from 'react';
import { Subject, ThemeMode, TestQuestion, MockTestResult } from '../types';
import { generateMockTest } from '../services/geminiService';

interface MockTestProps {
  subjects: Subject[];
  theme: ThemeMode;
}

const MockTest: React.FC<MockTestProps> = ({ subjects, theme }) => {
  const isDark = theme === 'dark';
  const [phase, setPhase] = useState<'setup' | 'loading' | 'taking' | 'result'>('setup');
  const [testMode, setTestMode] = useState<'exam' | 'practice'>('exam');

  // Setup state
  const [selectedSubjectId, setSelectedSubjectId] = useState<string>('');
  const [selectedTopics, setSelectedTopics] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState<number>(10);

  // Taking state
  const [questions, setQuestions] = useState<TestQuestion[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [userAnswers, setUserAnswers] = useState<number[]>([]);
  const [showFeedback, setShowFeedback] = useState(false);

  // Result state
  const [testResult, setTestResult] = useState<MockTestResult | null>(null);

  const startTest = async () => {
    const subject = subjects.find(s => s.id === selectedSubjectId);
    if (!subject) return;

    setPhase('loading');
    try {
      const topics = selectedTopics.length > 0 
        ? selectedTopics 
        : subject.topics.map(t => t.name);

      const generatedQuestions = await generateMockTest(subject.name, topics, questionCount);
      setQuestions(generatedQuestions);
      setUserAnswers(new Array(generatedQuestions.length).fill(-1));
      setCurrentQuestionIndex(0);
      setShowFeedback(false);
      setPhase('taking');
    } catch (err) {
      alert(err instanceof Error ? err.message : "Satellite connection failed.");
      setPhase('setup');
    }
  };

  const handleAnswer = (optionIndex: number) => {
    if (showFeedback && testMode === 'practice') return;

    const updated = [...userAnswers];
    updated[currentQuestionIndex] = optionIndex;
    setUserAnswers(updated);

    if (testMode === 'practice') {
      setShowFeedback(true);
    }
  };

  const nextQuestion = () => {
    if (currentQuestionIndex < questions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
      setShowFeedback(false);
    } else {
      finishTest();
    }
  };

  const finishTest = () => {
    let score = 0;
    questions.forEach((q, i) => {
      if (q.correctAnswerIndex === userAnswers[i]) score++;
    });

    setTestResult({
      score,
      total: questions.length,
      questions,
      userAnswers,
      timestamp: Date.now()
    });
    setPhase('result');
  };

  const resetTest = () => {
    setPhase('setup');
    setQuestions([]);
    setUserAnswers([]);
    setTestResult(null);
    setShowFeedback(false);
  };

  if (phase === 'loading') {
    return (
      <div className="h-full flex flex-col items-center justify-center p-20 animate-fadeIn">
        <div className="w-24 h-24 bg-[#4CC9F0]/10 rounded-full flex items-center justify-center mb-10 relative">
          <div className="absolute inset-0 border-4 border-[#4CC9F0] border-t-transparent rounded-full animate-spin"></div>
          <i className="fa-solid fa-satellite text-[#4CC9F0] text-3xl"></i>
        </div>
        <h3 className={`text-2xl font-black mb-4 ${isDark ? 'text-white' : 'text-slate-900'}`}>Generating Intelligence Probe</h3>
        <p className="text-slate-500 font-bold text-center max-w-sm">Orbit AI is constructing a {testMode} environment for your selected parameters.</p>
      </div>
    );
  }

  if (phase === 'taking') {
    const q = questions[currentQuestionIndex];
    const progress = ((currentQuestionIndex + 1) / questions.length) * 100;
    const hasAnswered = userAnswers[currentQuestionIndex] !== -1;

    return (
      <div className="max-w-4xl mx-auto space-y-10 animate-fadeIn pb-20">
        <div className="flex justify-between items-center">
          <div className="space-y-1">
            <h3 className={`text-sm font-black uppercase tracking-widest text-[#4CC9F0]`}>{testMode === 'practice' ? 'Practice Mode' : 'Question'} {currentQuestionIndex + 1} / {questions.length}</h3>
            <p className="text-slate-500 text-xs font-bold">{testMode === 'practice' ? 'Instant Feedback Active' : 'In-Orbit Evaluation'}</p>
          </div>
          <button onClick={finishTest} className="text-red-400 font-black text-[10px] uppercase tracking-widest hover:text-red-500 transition-colors">Abort Mission</button>
        </div>

        <div className={`w-full h-1.5 rounded-full overflow-hidden ${isDark ? 'bg-slate-800' : 'bg-slate-100'}`}>
          <div className="h-full bg-[#4CC9F0] transition-all duration-500" style={{ width: `${progress}%` }}></div>
        </div>

        <div className={`p-10 lg:p-12 rounded-[3.5rem] card-premium border ${isDark ? 'border-slate-800 shadow-2xl' : 'border-slate-100 shadow-xl'}`}>
          <p className={`text-2xl font-black mb-12 leading-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>{q.question}</p>

          <div className="grid grid-cols-1 gap-4">
            {q.options.map((opt, idx) => {
              const isSelected = userAnswers[currentQuestionIndex] === idx;
              const isCorrect = idx === q.correctAnswerIndex;
              const shouldShowCorrect = showFeedback && isCorrect;
              const shouldShowIncorrect = showFeedback && isSelected && !isCorrect;

              return (
                <button
                  key={idx}
                  onClick={() => handleAnswer(idx)}
                  disabled={showFeedback && testMode === 'practice'}
                  className={`w-full text-left p-6 rounded-3xl border-2 transition-all font-bold group flex items-center gap-6 ${
                    shouldShowCorrect 
                      ? 'bg-[#4CAF50]/10 border-[#4CAF50] text-[#4CAF50]'
                      : shouldShowIncorrect
                        ? 'bg-red-500/10 border-red-500 text-red-500'
                        : isSelected
                          ? 'bg-[#4CC9F0]/10 border-[#4CC9F0] text-[#4CC9F0]'
                          : isDark 
                            ? 'border-slate-800 hover:border-slate-600 text-slate-300' 
                            : 'border-slate-100 hover:border-blue-200 text-slate-700'
                  }`}
                >
                  <div className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-all ${
                    shouldShowCorrect ? 'bg-[#4CAF50] text-[#0D1B2A]' : 
                    shouldShowIncorrect ? 'bg-red-500 text-white' :
                    isSelected ? 'bg-[#4CC9F0] text-[#0D1B2A]' : 
                    'bg-slate-800/20 text-slate-500 group-hover:bg-slate-800/40'
                  }`}>
                    {shouldShowCorrect ? <i className="fa-solid fa-check"></i> : 
                     shouldShowIncorrect ? <i className="fa-solid fa-xmark"></i> : 
                     String.fromCharCode(65 + idx)}
                  </div>
                  {opt}
                </button>
              );
            })}
          </div>

          {showFeedback && (
            <div className={`mt-10 p-8 rounded-[2.5rem] border animate-slideUp ${isDark ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-200'}`}>
              <div className="flex items-center gap-3 mb-4">
                 <div className="w-8 h-8 rounded-full bg-[#4CC9F0]/10 text-[#4CC9F0] flex items-center justify-center">
                   <i className="fa-solid fa-lightbulb"></i>
                 </div>
                 <h4 className={`text-xs font-black uppercase tracking-widest ${isDark ? 'text-white' : 'text-slate-800'}`}>Explanation</h4>
              </div>
              <p className={`text-sm leading-relaxed ${isDark ? 'text-slate-400' : 'text-slate-600'}`}>{q.explanation}</p>
            </div>
          )}
        </div>

        <div className="flex justify-end gap-6 pt-6">
           <button 
             onClick={nextQuestion}
             disabled={!hasAnswered}
             className="px-12 py-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl font-black uppercase text-xs tracking-widest shadow-2xl shadow-[#4CC9F0]/20 disabled:opacity-30 disabled:scale-100 hover:scale-105 active:scale-95 transition-all"
           >
             {currentQuestionIndex === questions.length - 1 ? 'Complete Review' : (testMode === 'practice' ? 'Next Question' : 'Next Objective')}
           </button>
        </div>
      </div>
    );
  }

  if (phase === 'result' && testResult) {
    const percentage = Math.round((testResult.score / testResult.total) * 100);
    return (
      <div className="max-w-5xl mx-auto space-y-12 animate-fadeIn pb-24">
        <header className="text-center space-y-4">
           <h3 className="text-[#4CC9F0] font-black uppercase tracking-[0.4em] text-xs">Mission Report</h3>
           <h2 className={`text-5xl font-black tracking-tighter ${isDark ? 'text-white' : 'text-slate-900'}`}>
             {testMode === 'practice' ? 'Review Complete' : percentage >= 50 ? 'Mission Successful' : 'Mission Incomplete'}
           </h2>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
           <div className="card-premium p-10 rounded-[3rem] text-center">
              <p className="text-slate-500 font-black uppercase text-[10px] tracking-widest mb-4">Accuracy</p>
              <p className={`text-6xl font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>{percentage}%</p>
           </div>
           <div className="card-premium p-10 rounded-[3rem] text-center">
              <p className="text-slate-500 font-black uppercase text-[10px] tracking-widest mb-4">Score</p>
              <p className={`text-6xl font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>{testResult.score}/{testResult.total}</p>
           </div>
           <div className="card-premium p-10 rounded-[3rem] flex flex-col justify-center items-center">
              <button 
                onClick={resetTest}
                className="w-full py-5 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl font-black uppercase text-[10px] tracking-widest"
              >
                Launch New Mission
              </button>
           </div>
        </div>

        <div className="space-y-8">
           <h3 className={`text-xl font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>Detailed Debriefing</h3>
           {testResult.questions.map((q, idx) => {
             const isCorrect = testResult.userAnswers[idx] === q.correctAnswerIndex;
             return (
               <div key={idx} className={`p-10 rounded-[3rem] border-2 transition-all ${isDark ? 'bg-slate-900/40 border-slate-800' : 'bg-white border-slate-100 shadow-sm'}`}>
                 <div className="flex justify-between items-start mb-6">
                    <p className={`text-lg font-bold flex-1 ${isDark ? 'text-white' : 'text-slate-900'}`}>{idx + 1}. {q.question}</p>
                    <div className={`px-4 py-1.5 rounded-full font-black text-[9px] uppercase tracking-widest ${isCorrect ? 'bg-[#4CAF50]/10 text-[#4CAF50]' : 'bg-red-500/10 text-red-500'}`}>
                      {isCorrect ? 'Correct' : 'Critical Failure'}
                    </div>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
                    {q.options.map((opt, oIdx) => (
                      <div 
                        key={oIdx}
                        className={`p-4 rounded-2xl text-sm font-bold border-2 ${
                          oIdx === q.correctAnswerIndex 
                            ? 'bg-[#4CAF50]/10 border-[#4CAF50] text-[#4CAF50]' 
                            : oIdx === testResult.userAnswers[idx] && !isCorrect 
                              ? 'bg-red-500/10 border-red-500 text-red-500'
                              : isDark ? 'bg-slate-800/50 border-transparent text-slate-500' : 'bg-slate-50 border-transparent text-slate-400'
                        }`}
                      >
                        {String.fromCharCode(65 + oIdx)}. {opt}
                      </div>
                    ))}
                 </div>

                 <div className={`p-8 rounded-[2rem] border ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
                    <p className="text-[#4CC9F0] font-black uppercase text-[10px] tracking-[0.2em] mb-4">AI Explanatory Core</p>
                    <p className={`text-sm leading-relaxed ${isDark ? 'text-slate-400' : 'text-slate-600'}`}>{q.explanation}</p>
                 </div>
               </div>
             );
           })}
        </div>
      </div>
    );
  }

  // Setup Phase
  return (
    <div className="space-y-12 animate-fadeIn pb-24 max-w-5xl mx-auto">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className={`text-4xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>Mock <span className="text-[#4CC9F0]">Test</span></h2>
          <p className="text-slate-500 font-bold text-sm mt-1">Simulated orbital stress-tests for academic readiness.</p>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 space-y-10">
          <div className="card-premium p-10 rounded-[3.5rem] space-y-10">
            <div>
              <h3 className={`text-lg font-black mb-6 ${isDark ? 'text-white' : 'text-slate-900'}`}>1. Target Subject</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {subjects.map(s => (
                  <button
                    key={s.id}
                    onClick={() => { setSelectedSubjectId(s.id); setSelectedTopics([]); }}
                    className={`p-6 rounded-3xl border-2 text-left font-bold transition-all ${
                      selectedSubjectId === s.id 
                        ? 'bg-[#4CC9F0]/10 border-[#4CC9F0] text-[#4CC9F0]' 
                        : isDark ? 'border-slate-800 text-slate-500 hover:border-slate-700' : 'border-slate-100 text-slate-400 hover:border-slate-200 shadow-sm'
                    }`}
                  >
                    {s.name}
                  </button>
                ))}
              </div>
            </div>

            {selectedSubjectId && (
              <div className="animate-slideUp">
                <div className="flex justify-between items-center mb-6">
                  <h3 className={`text-lg font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>2. Module Focus</h3>
                  <button 
                    onClick={() => setSelectedTopics([])}
                    className="text-[10px] font-black uppercase tracking-widest text-[#4CC9F0]"
                  >
                    Full Syllabus
                  </button>
                </div>
                <div className="flex flex-wrap gap-3">
                  {subjects.find(s => s.id === selectedSubjectId)?.topics.map(t => (
                    <button
                      key={t.id}
                      onClick={() => {
                        if (selectedTopics.includes(t.name)) {
                          setSelectedTopics(prev => prev.filter(x => x !== t.name));
                        } else {
                          setSelectedTopics(prev => [...prev, t.name]);
                        }
                      }}
                      className={`px-6 py-3 rounded-2xl border-2 text-[10px] font-black uppercase tracking-widest transition-all ${
                        selectedTopics.includes(t.name)
                          ? 'bg-[#4CC9F0] text-[#0D1B2A] border-[#4CC9F0]'
                          : isDark ? 'border-slate-800 text-slate-500' : 'border-slate-100 text-slate-400'
                      }`}
                    >
                      {t.name}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="space-y-10">
          <div className="card-premium p-10 rounded-[3.5rem] space-y-8">
            <h3 className={`text-lg font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>Mission Setup</h3>

            <div className="space-y-6">
              <div className="space-y-3">
                <p className="text-[10px] font-black uppercase tracking-widest text-slate-500">Evaluation Mode</p>
                <div className={`grid grid-cols-2 p-1 rounded-2xl border ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
                  <button 
                    onClick={() => setTestMode('exam')}
                    className={`py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${testMode === 'exam' ? 'bg-[#4CC9F0] text-[#0D1B2A]' : 'text-slate-500'}`}
                  >
                    Exam
                  </button>
                  <button 
                    onClick={() => setTestMode('practice')}
                    className={`py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${testMode === 'practice' ? 'bg-[#4CAF50] text-[#0D1B2A]' : 'text-slate-500'}`}
                  >
                    Practice
                  </button>
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-slate-500">
                  <span>Intensity</span>
                  <span className="text-[#4CC9F0]">{questionCount} Qs</span>
                </div>
                <input 
                  type="range" min="5" max="25" step="5" value={questionCount} 
                  onChange={e => setQuestionCount(parseInt(e.target.value))}
                  className="w-full accent-[#4CC9F0] h-1.5 bg-slate-800 rounded-full appearance-none cursor-pointer"
                />
              </div>
            </div>

            <div className="pt-8">
              <button
                disabled={!selectedSubjectId}
                onClick={startTest}
                className={`w-full py-6 text-[#0D1B2A] rounded-[2.5rem] font-black uppercase text-xs tracking-[0.2em] shadow-2xl disabled:opacity-30 disabled:scale-100 hover:scale-[1.03] active:scale-95 transition-all ${testMode === 'practice' ? 'bg-[#4CAF50] shadow-[#4CAF50]/20' : 'bg-[#4CC9F0] shadow-[#4CC9F0]/20'}`}
              >
                Initiate {testMode === 'practice' ? 'Practice' : 'Test'}
              </button>
            </div>
          </div>

          <div className={`p-8 rounded-[3rem] border flex items-center gap-6 ${isDark ? 'bg-slate-900/40 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
             <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${testMode === 'practice' ? 'bg-[#4CAF50]/10 text-[#4CAF50]' : 'bg-[#4CC9F0]/10 text-[#4CC9F0]'}`}>
               <i className={`fa-solid ${testMode === 'practice' ? 'fa-graduation-cap' : 'fa-wand-magic-sparkles'}`}></i>
             </div>
             <p className="text-[10px] font-bold text-slate-500 uppercase leading-relaxed tracking-wider">
               {testMode === 'practice' 
                 ? "Study without scoring. Get immediate feedback and deep-dive explanations after every choice." 
                 : "Standard evaluation. Answer all questions under pressure and receive a mission report at the end."}
             </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MockTest;

import React, { useState, useEffect } from 'react';
import { APP_MODES } from '../constants';
import { ThemeMode } from '../types';

interface SidebarProps {
  activeMode: string;
  setActiveMode: (mode: string) => void;
  theme: ThemeMode;
  toggleTheme: () => void;
  onLogout: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeMode, setActiveMode, theme, toggleTheme, onLogout }) => {
  const [isFullscreen, setIsFullscreen] = useState(false);

  useEffect(() => {
    const handleFsChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  const menuItems = [
    { id: APP_MODES.DASHBOARD, label: 'Home', icon: 'fa-house-user' },
    { id: APP_MODES.CHAT, label: 'AI Tutor', icon: 'fa-brain' },
    { id: APP_MODES.DEEP_DIVE, label: 'Deep Dive', icon: 'fa-search-plus' },
    { id: APP_MODES.MOCK_TEST, label: 'Mock Test', icon: 'fa-file-signature' },
    { id: APP_MODES.PLANNER, label: 'Planner', icon: 'fa-calendar-check' },
    { id: APP_MODES.NOTES, label: 'Library', icon: 'fa-folder-open' },
    { id: APP_MODES.SYLLABUS, label: 'Orbit', icon: 'fa-compass' },
    { id: APP_MODES.DOUBTS, label: 'Doubts', icon: 'fa-question-circle' },
  ];

  const isDark = theme === 'dark';
  const sidebarBg = isDark ? 'bg-[#0D1B2A] border-slate-800' : 'bg-white border-slate-100 shadow-xl';
  const textPrimary = isDark ? 'text-white' : 'text-slate-900';

  return (
    <div className={`w-24 lg:w-72 h-full flex flex-col fixed left-0 top-0 z-40 transition-all border-r ${sidebarBg}`}>
      <div className="p-8 flex items-center justify-center lg:justify-start gap-4">
        <div className="w-12 h-12 bg-[#4CC9F0] rounded-2xl flex items-center justify-center shadow-lg shadow-[#4CC9F0]/20 cursor-pointer hover:rotate-12 transition-all">
          <i className="fa-solid fa-rocket text-[#0D1B2A] text-xl"></i>
        </div>
        <div className="hidden lg:block">
          <h1 className={`text-xl font-extrabold tracking-tighter ${textPrimary}`}>MindOrbit</h1>
          <p className="text-[8px] font-black uppercase tracking-[0.2em] text-[#4CC9F0]">Mission Active</p>
        </div>
      </div>

      <nav className="flex-1 mt-6 px-4 space-y-2 overflow-y-auto">
        {menuItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setActiveMode(item.id)}
            className={`w-full flex items-center justify-center lg:justify-start gap-4 px-4 py-4 rounded-3xl transition-all duration-300 group ${
              activeMode === item.id
                ? 'bg-[#4CC9F0] text-[#0D1B2A] shadow-xl shadow-[#4CC9F0]/10'
                : isDark 
                  ? 'text-slate-500 hover:bg-slate-800/50 hover:text-[#4CC9F0]' 
                  : 'text-slate-400 hover:bg-slate-50 hover:text-[#4CC9F0]'
            }`}
          >
            <i className={`fa-solid ${item.icon} text-xl lg:w-6`}></i>
            <span className="hidden lg:block font-bold text-sm tracking-tight">{item.label}</span>
          </button>
        ))}
      </nav>

      <div className="p-6 space-y-3">
        {/* Fullscreen Toggle Button */}
        <button 
          onClick={toggleFullscreen}
          className={`w-full flex items-center justify-center lg:justify-between p-4 rounded-3xl border font-bold text-[10px] uppercase tracking-widest transition-all ${
            isDark ? 'border-[#4CC9F0]/20 bg-slate-900/50 text-[#4CC9F0]' : 'border-slate-100 bg-slate-50 text-[#4CC9F0]'
          } hover:scale-[1.02] active:scale-95`}
        >
          <span className="hidden lg:block">{isFullscreen ? 'Exit Focus' : 'Focus Mode'}</span>
          <i className={`fa-solid ${isFullscreen ? 'fa-compress' : 'fa-expand'} ${isFullscreen ? 'animate-pulse' : ''}`}></i>
        </button>

        <button 
          onClick={toggleTheme}
          className={`w-full flex items-center justify-center lg:justify-between p-4 rounded-3xl border font-bold text-[10px] uppercase tracking-widest ${
            isDark ? 'border-slate-800 bg-slate-900/50 text-slate-500' : 'border-slate-100 bg-slate-50 text-slate-400'
          }`}
        >
          <span className="hidden lg:block">{isDark ? 'Dark' : 'Light'}</span>
          <i className={`fa-solid ${isDark ? 'fa-moon text-[#4CC9F0]' : 'fa-sun text-amber-500'}`}></i>
        </button>

        <button 
          onClick={onLogout}
          className={`w-full flex items-center justify-center lg:justify-start gap-4 p-4 rounded-3xl text-red-400 hover:bg-red-500/10 font-bold text-[10px] uppercase tracking-widest transition-colors`}
        >
          <i className="fa-solid fa-right-from-bracket lg:w-6 text-sm"></i>
          <span className="hidden lg:block">Exit Orbit</span>
        </button>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useMemo } from 'react';
import { Note, ThemeMode } from '../types';

interface NotesManagerProps {
  notes: Note[];
  onAddNote: (note: Omit<Note, 'id' | 'timestamp'>) => void;
  onDeleteNote: (id: string) => void;
  theme: ThemeMode;
}

const NotesManager: React.FC<NotesManagerProps> = ({ notes, onAddNote, onDeleteNote, theme }) => {
  const isDark = theme === 'dark';
  const [isUploading, setIsUploading] = useState(false);
  const [newNoteTitle, setNewNoteTitle] = useState('');
  const [newNoteContent, setNewNoteContent] = useState('');
  const [newNoteTags, setNewNoteTags] = useState('');
  const [selectedTag, setSelectedTag] = useState<string | null>(null);

  // Extract unique tags for the tag cloud
  const allTags = useMemo(() => {
    const tags = new Set<string>();
    notes.forEach(note => {
      note.tags?.forEach(tag => tags.add(tag.toLowerCase().trim()));
    });
    return Array.from(tags).sort();
  }, [notes]);

  const filteredNotes = useMemo(() => {
    if (!selectedTag) return notes;
    return notes.filter(note => 
      note.tags?.some(tag => tag.toLowerCase() === selectedTag.toLowerCase())
    );
  }, [notes, selectedTag]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const content = event.target?.result as string;
        onAddNote({
          title: file.name,
          content: content,
          type: 'text',
          tags: ['imported']
        });
      };
      reader.readAsText(file);
    }
  };

  const handleManualAdd = () => {
    if (newNoteTitle && newNoteContent) {
      const parsedTags = newNoteTags
        .split(',')
        .map(t => t.trim())
        .filter(t => t !== '');

      onAddNote({
        title: newNoteTitle,
        content: newNoteContent,
        type: 'text',
        tags: parsedTags
      });
      setNewNoteTitle('');
      setNewNoteContent('');
      setNewNoteTags('');
      setIsUploading(false);
    }
  };

  const toggleTag = (tag: string) => {
    setSelectedTag(prev => prev === tag ? null : tag);
  };

  return (
    <div className="space-y-12 animate-fadeIn pb-24 max-w-6xl mx-auto">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className={`text-3xl font-black tracking-tight ${isDark ? 'text-white' : 'text-slate-900'}`}>
            Knowledge <span className="text-[#4CC9F0]">Library</span>
          </h2>
          <p className="text-slate-500 font-bold text-sm mt-1">Archived intelligence and cross-referenced study logs.</p>
        </div>
        <div className="flex flex-wrap gap-4">
           <label className={`px-6 py-3.5 rounded-3xl border font-bold text-[10px] uppercase tracking-widest cursor-pointer transition-all ${isDark ? 'bg-slate-900 border-slate-800 text-slate-400 hover:border-[#4CC9F0]/40' : 'bg-white border-slate-100 text-slate-600 shadow-sm hover:border-blue-200'}`}>
             <i className="fa-solid fa-cloud-arrow-up mr-2 text-[#4CC9F0]"></i> Import Data
             <input type="file" className="hidden" onChange={handleFileUpload} accept=".txt,.md,.json" />
           </label>
           <button 
             onClick={() => setIsUploading(true)}
             className="px-8 py-3.5 bg-[#4CC9F0] text-[#0D1B2A] rounded-3xl font-black text-[10px] uppercase tracking-widest shadow-2xl shadow-[#4CC9F0]/30 hover:scale-105 active:scale-95 transition-all"
           >
             <i className="fa-solid fa-plus-circle mr-2"></i> New Protocol
           </button>
        </div>
      </header>

      {/* Tag Cloud Filter */}
      {allTags.length > 0 && (
        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h3 className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-500">Cross-Reference Matrix</h3>
            {selectedTag && (
              <button 
                onClick={() => setSelectedTag(null)}
                className="text-[9px] font-black text-[#4CC9F0] uppercase tracking-widest hover:underline"
              >
                Clear Filter
              </button>
            )}
          </div>
          <div className="flex flex-wrap gap-3">
            {allTags.map(tag => (
              <button
                key={tag}
                onClick={() => toggleTag(tag)}
                className={`px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest border-2 transition-all ${
                  selectedTag === tag
                    ? 'bg-[#4CC9F0] text-[#0D1B2A] border-[#4CC9F0] shadow-lg shadow-[#4CC9F0]/20'
                    : isDark 
                      ? 'border-slate-800 text-slate-500 hover:border-slate-700 hover:text-slate-300' 
                      : 'border-slate-100 text-slate-400 hover:border-slate-200 hover:text-slate-600 shadow-sm'
                }`}
              >
                # {tag}
              </button>
            ))}
          </div>
        </div>
      )}

      {isUploading && (
        <div className={`p-10 rounded-[3.5rem] border animate-slideDown mb-10 ${isDark ? 'bg-slate-900/80 border-[#4CC9F0]/20 backdrop-blur-xl' : 'bg-white border-slate-100 shadow-2xl shadow-slate-200/50'}`}>
          <div className="flex items-center gap-4 mb-8">
             <div className="w-10 h-10 bg-[#4CC9F0]/10 text-[#4CC9F0] rounded-2xl flex items-center justify-center">
                <i className="fa-solid fa-pen-nib"></i>
             </div>
             <h3 className={`text-xl font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>Initialize New Record</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-6">
              <div className="space-y-2">
                <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-2">Title</p>
                <input 
                  className={`w-full p-5 rounded-3xl border text-sm font-bold outline-none focus:ring-4 ring-[#4CC9F0]/10 ${isDark ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-50 border-slate-100'}`}
                  placeholder="Record Designation"
